-- Features table: stores all portfolio mini-cases from all projects
-- Replaces static data/portfolioFeatures.ts + data/jobbotFeatures.ts

-- Projects registry for multi-project support
CREATE TABLE IF NOT EXISTS feature_projects (
  id TEXT PRIMARY KEY,
  name_en TEXT NOT NULL,
  name_no TEXT NOT NULL,
  name_ua TEXT NOT NULL,
  description_en TEXT,
  description_no TEXT,
  description_ua TEXT,
  repo_url TEXT,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW()
);


-- Features table
CREATE TABLE IF NOT EXISTS features (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  feature_id TEXT NOT NULL UNIQUE,
  project_id TEXT NOT NULL REFERENCES feature_projects(id),
  category TEXT NOT NULL CHECK (category IN ('ai_automation', 'media_production', 'bot_scraping', 'frontend_ux', 'devops_infra', 'other')),
  title_en TEXT NOT NULL,
  title_no TEXT NOT NULL,
  title_ua TEXT NOT NULL,
  short_description_en TEXT NOT NULL,
  short_description_no TEXT NOT NULL,
  short_description_ua TEXT NOT NULL,
  problem_en TEXT NOT NULL,
  problem_no TEXT NOT NULL,
  problem_ua TEXT NOT NULL,
  solution_en TEXT NOT NULL,
  solution_no TEXT NOT NULL,
  solution_ua TEXT NOT NULL,
  result_en TEXT NOT NULL,
  result_no TEXT NOT NULL,
  result_ua TEXT NOT NULL,
  tech_stack TEXT[] DEFAULT '{}',
  hashtags TEXT[] DEFAULT '{}',
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'published', 'rejected')),
  source_commits TEXT[],
  discovered_at TIMESTAMPTZ,
  published_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX idx_features_project ON features (project_id);
CREATE INDEX idx_features_status ON features (status);
CREATE INDEX idx_features_category ON features (category);

-- RLS
ALTER TABLE features ENABLE ROW LEVEL SECURITY;
ALTER TABLE feature_projects ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Service role full access features" ON features FOR ALL USING (auth.role() = 'service_role');
CREATE POLICY "Public read published features" ON features FOR SELECT USING (status = 'published');
CREATE POLICY "Service role full access projects" ON feature_projects FOR ALL USING (auth.role() = 'service_role');
CREATE POLICY "Public read active projects" ON feature_projects FOR SELECT USING (is_active = true);

