INSERT INTO feature_projects (id, name_en, name_no, name_ua, description_en, description_no, description_ua, repo_url) VALUES
('portfolio', 'Portfolio & News Platform', 'Portefølje & Nyhetsplattform', 'Портфоліо & Новинна платформа', 'AI-powered multilingual content platform', 'AI-drevet flerspråklig innholdsplattform', 'AI-платформа багатомовного контенту', 'https://github.com/SmmShaman/vitalii_claude-code-in-browser'),
('jobbot', 'JobBot Norway', 'JobBot Norge', 'JobBot Norway', 'Intelligent job hunting automation platform', 'Intelligent automatiseringsplattform for jobbsøk', 'AI-платформа автоматизації пошуку роботи', NULL);
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p01', 'portfolio', 'ai_automation', 'AI Pre-Moderation — killing spam before it reaches my eyes', 'AI-forhåndsmoderering — dreper spam før det når øynene mine', 'AI-премодерація — вбиває спам ще до того, як я його побачу', '6 Telegram channels + RSS feeds pump 50-80 articles per day. 70% is spam. AI filters the noise so I only review what matters.', '6 Telegram-kanaler + RSS-feeder pumper 50-80 artikler daglig. 70% er spam. AI filtrerer støyen slik at jeg bare ser det som betyr noe.', '6 Telegram-каналів + RSS-стрічки качають 50-80 статей на день. 70% — спам. AI фільтрує шум, і я бачу лише те, що варте уваги.', '6 Telegram channels + RSS feeds pump 50-80 articles per day. 70% is spam, ads, or irrelevant noise. Manual review was eating 2+ hours daily.', '6 Telegram-kanaler + RSS-feeder pumper 50-80 artikler per dag. 70% er spam, annonser eller irrelevant støy. Manuell gjennomgang tok over 2 timer daglig.', '6 Telegram-каналів + RSS-стрічки качають 50-80 статей на день. 70% — спам, реклама або нерелевантний шум. Ручний перегляд забирав 2+ години щодня.', 'Every scraped article hits an Azure OpenAI function (Jobbot-gpt-4.1-mini) with a custom prompt from the database. The prompt is editable through the admin panel — no redeploy needed. AI returns: approve, reject, or flag for review. Rejected articles never reach the Telegram bot.', 'Hver skrapet artikkel treffer en Azure OpenAI-funksjon (Jobbot-gpt-4.1-mini) med en tilpasset prompt fra databasen. Prompten kan redigeres via adminpanelet — ingen ny deploy nødvendig. AI returnerer: godkjenn, avvis eller flagg for gjennomgang. Avviste artikler når aldri Telegram-boten.', 'Кожна зіскрейпена стаття потрапляє в Azure OpenAI функцію (Jobbot-gpt-4.1-mini) з кастомним промптом із бази даних. Промпт редагується через адмінку — без редеплою. AI повертає: схвалити, відхилити або позначити для перегляду. Відхилені статті ніколи не потрапляють до Telegram-бота.', 'Review time dropped from 2 hours to 15 minutes. 1,234 commits later, the pre-moderation prompt has been refined 12+ times through the admin panel — each iteration learned from false positives.', 'Gjennomgangstid falt fra 2 timer til 15 minutter. 1234 commits senere er forhåndsmodereringsprompten finjustert 12+ ganger via adminpanelet — hver iterasjon lærte av falske positiver.', 'Час перегляду впав із 2 годин до 15 хвилин. Через 1234 комміти промпт премодерації був вдосконалений 12+ разів через адмінку — кожна ітерація вчилася на хибних спрацюваннях.', '{"Azure OpenAI","Supabase","Deno","Telegram Bot API"}', '{"#AI","#ContentModeration","#Automation","#AzureOpenAI","#Supabase"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p02', 'portfolio', 'ai_automation', 'AI Content Rewriting — one article, three languages, zero translators', 'AI-innholdsomskriving — én artikkel, tre språk, null oversettere', 'AI-рерайт контенту — одна стаття, три мови, нуль перекладачів', 'Norway-based portfolio targeting three audiences. Every article needs EN, NO, and UA versions. AI rewrites — not just translates — adapting tone for each audience.', 'Norgesbasert portefølje rettet mot tre målgrupper. Hver artikkel trenger EN-, NO- og UA-versjoner. AI omskriver — ikke bare oversetter — og tilpasser tonen for hvert publikum.', 'Портфоліо з Норвегії для трьох аудиторій. Кожна стаття потребує версії EN, NO та UA. AI переписує — а не просто перекладає — адаптуючи тон для кожної аудиторії.', 'Norway-based portfolio targeting three audiences: Norwegian locals, Ukrainian diaspora, international tech community. Every article needs to exist in EN, NO, and UA. Hiring translators for 5-10 articles per day? Unrealistic.', 'Norgesbasert portefølje rettet mot tre målgrupper: norske lokale, ukrainsk diaspora, internasjonalt teknologisamfunn. Hver artikkel må eksistere på EN, NO og UA. Å ansette oversettere for 5-10 artikler daglig? Urealistisk.', 'Портфоліо з Норвегії для трьох аудиторій: норвежці, українська діаспора, міжнародна техспільнота. Кожна стаття має існувати EN, NO та UA. Наймати перекладачів для 5-10 статей на день? Нереально.', 'The process-news Edge Function takes the original article and rewrites it three times using Azure OpenAI. Each language has its own prompt template (editable via admin panel). The AI preserves facts but adjusts style: formal for NO, conversational for UA, SEO-friendly for EN. All three versions share the same slug structure for cross-language linking.', 'Edge Function process-news tar den originale artikkelen og omskriver den tre ganger med Azure OpenAI. Hvert språk har sin egen promptmal (redigerbar via adminpanelet). AI bevarer fakta men tilpasser stil: formell for NO, uformell for UA, SEO-vennlig for EN. Alle tre versjoner deler samme slug-struktur for kryssspråklig lenking.', 'Edge Function process-news бере оригінальну статтю і переписує її тричі через Azure OpenAI. Кожна мова має власний шаблон промпту (редагується через адмінку). AI зберігає факти, але адаптує стиль: формальний для NO, розмовний для UA, SEO-оптимізований для EN. Усі три версії мають спільну slug-структуру для міжмовної навігації.', '3x content output with zero translation cost. The Ukrainian audience gets articles that feel native, not machine-translated. SEO benefits from unique content per language (not just translated meta tags).', '3x innholdsproduksjon uten oversettelseskostnader. Det ukrainske publikummet får artikler som føles naturlige, ikke maskinoversatte. SEO drar nytte av unikt innhold per språk (ikke bare oversatte meta-tagger).', '3x контенту без витрат на переклад. Українська аудиторія отримує статті, що звучать природно, а не машинно. SEO виграє від унікального контенту на кожній мові (а не просто перекладених мета-тегів).', '{"Azure OpenAI","Supabase Edge Functions","Deno","Next.js"}', '{"#AI","#Translation","#Multilingual","#ContentPipeline","#NLP"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p03', 'portfolio', 'ai_automation', 'Two-Stage AI Image Prompt System — because "generate an image for this article" never works', 'To-trinns AI-bildepromptsystem — fordi "generer et bilde for denne artikkelen" aldri fungerer', 'Двоетапна AI-система промптів для зображень — бо "згенеруй картинку для цієї статті" ніколи не працює', 'Generic AI image prompts produce unusable results. A two-stage classifier + template system extracts structured data first, then fills proven visual templates.', 'Generiske AI-bildeprompter gir ubrukelige resultater. Et to-trinns klassifiserings- og malsystem trekker ut strukturerte data først, og fyller deretter utprøvde visuelle maler.', 'Загальні AI-промпти для зображень дають непридатні результати. Двоетапна система класифікатор + шаблон спочатку витягує структуровані дані, а потім заповнює перевірені візуальні шаблони.', 'Giving an AI a full article and saying "make an image" produces generic, unusable results. Every image looked like a stock photo from 2015.', 'Å gi en AI en hel artikkel og si "lag et bilde" gir generiske, ubrukelige resultater. Hvert bilde så ut som et arkivfoto fra 2015.', 'Давати AI повну статтю і казати "зроби картинку" дає загальні, непридатні результати. Кожне зображення виглядало як стокове фото з 2015 року.', 'Stage 1 (Classifier) uses Azure OpenAI to extract JSON: {company, category, visual_concept, color_scheme}. Seven categories: tech_product, marketing_campaign, ai_research, business_news, science, lifestyle, general. Stage 2 selects a template by category and fills {placeholder} values. Both prompts live in the ai_prompts table — editable without code changes.', 'Trinn 1 (Klassifiserer) bruker Azure OpenAI for å trekke ut JSON: {company, category, visual_concept, color_scheme}. Syv kategorier: tech_product, marketing_campaign, ai_research, business_news, science, lifestyle, general. Trinn 2 velger en mal etter kategori og fyller {placeholder}-verdier. Begge promptene ligger i ai_prompts-tabellen — redigerbare uten kodeendringer.', 'Етап 1 (Класифікатор) використовує Azure OpenAI для витягування JSON: {company, category, visual_concept, color_scheme}. Сім категорій: tech_product, marketing_campaign, ai_research, business_news, science, lifestyle, general. Етап 2 обирає шаблон за категорією і заповнює значення {placeholder}. Обидва промпти живуть у таблиці ai_prompts — редагуються без змін коду.', 'Image relevance jumped from ~30% to ~85%. The two-stage approach means I can improve classification and aesthetics independently. When a new visual trend emerges, I update one template — all future images follow.', 'Bilderelevans økte fra ~30% til ~85%. To-trinns-tilnærmingen gjør at jeg kan forbedre klassifisering og estetikk uavhengig. Når en ny visuell trend dukker opp, oppdaterer jeg én mal — alle fremtidige bilder følger etter.', 'Релевантність зображень зросла з ~30% до ~85%. Двоетапний підхід дозволяє покращувати класифікацію та естетику незалежно. Коли з''являється новий візуальний тренд, я оновлюю один шаблон — усі майбутні зображення слідують за ним.', '{"Azure OpenAI","Supabase","Deno"}', '{"#AI","#ImageGeneration","#PromptEngineering","#TwoStage","#Classification"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p04', 'portfolio', 'ai_automation', 'AI Social Teasers — every platform speaks its own language', 'AI-sosiale teasere — hver plattform snakker sitt eget språk', 'AI-тизери для соцмереж — кожна платформа говорить своєю мовою', 'Posting the same text on LinkedIn, Instagram, and Facebook kills engagement. AI generates 9 platform-specific teasers (3 platforms x 3 languages) per article.', 'Å poste samme tekst på LinkedIn, Instagram og Facebook dreper engasjement. AI genererer 9 plattformspesifikke teasere (3 plattformer x 3 språk) per artikkel.', 'Постити однаковий текст у LinkedIn, Instagram і Facebook вбиває залученість. AI генерує 9 платформо-специфічних тизерів (3 платформи x 3 мови) на статтю.', 'Posting the same text on LinkedIn, Instagram, and Facebook is a recipe for low engagement. LinkedIn wants professional insights. Instagram wants short hooks. Facebook wants conversation starters. Writing 3 versions manually for each article in 3 languages = 9 texts per article.', 'Å poste samme tekst på LinkedIn, Instagram og Facebook gir lavt engasjement. LinkedIn ønsker profesjonelle innsikter. Instagram ønsker korte kroker. Facebook ønsker samtalestartere. Å skrive 3 versjoner manuelt for hver artikkel på 3 språk = 9 tekster per artikkel.', 'Постити однаковий текст у LinkedIn, Instagram і Facebook — рецепт низької залученості. LinkedIn хоче професійні інсайти. Instagram хоче короткі хуки. Facebook хоче стартери для дискусій. Писати 3 версії вручну для кожної статті на 3 мовах = 9 текстів на статтю.', 'Edge Function generate-social-teasers creates 9 variants (3 platforms x 3 languages) per article. Results are cached in the database (social_teaser_{platform}_{lang}). First click generates, subsequent clicks use cache. Each platform''s prompt is independently editable.', 'Edge Function generate-social-teasers lager 9 varianter (3 plattformer x 3 språk) per artikkel. Resultatene caches i databasen (social_teaser_{platform}_{lang}). Første klikk genererer, påfølgende klikk bruker cache. Hver plattforms prompt kan redigeres uavhengig.', 'Edge Function generate-social-teasers створює 9 варіантів (3 платформи x 3 мови) на статтю. Результати кешуються в базі даних (social_teaser_{platform}_{lang}). Перший клік генерує, наступні використовують кеш. Промпт кожної платформи редагується незалежно.', 'Engagement increased noticeably after switching from copy-paste to tailored teasers. The cache means generation happens once — no API costs on repeated views.', 'Engasjement økte merkbart etter overgang fra kopier-lim til skreddersydde teasere. Caching betyr at generering skjer én gang — ingen API-kostnader ved gjentatte visninger.', 'Залученість помітно зросла після переходу від копіпасти до адаптованих тизерів. Кешування означає, що генерація відбувається один раз — жодних витрат на API при повторних переглядах.', '{"Azure OpenAI","Supabase Edge Functions","Deno"}', '{"#AI","#SocialMedia","#ContentGeneration","#Engagement","#Multilingual"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p05', 'portfolio', 'ai_automation', 'AI Comment Replies — sentiment-aware, never robotic', 'AI-kommentarsvar — stemningsbevisste, aldri robotaktige', 'AI-відповіді на коментарі — з розумінням тональності, ніколи не роботизовані', 'Social media comments need timely responses. AI generates suggested replies based on article context and comment sentiment, but human always reviews before sending.', 'Kommentarer på sosiale medier trenger raske svar. AI genererer foreslåtte svar basert på artikkelkontekst og kommentarstemning, men mennesket gjennomgår alltid før sending.', 'Коментарі в соцмережах потребують швидких відповідей. AI генерує пропоновані відповіді на основі контексту статті та тональності коментаря, але людина завжди перевіряє перед відправкою.', 'Social media comments need timely responses. But writing thoughtful replies to 20+ comments across 3 platforms daily is a time sink. Ignoring comments kills algorithm reach.', 'Kommentarer på sosiale medier trenger rettidige svar. Men å skrive gjennomtenkte svar på 20+ kommentarer på tvers av 3 plattformer daglig er tidkrevende. Å ignorere kommentarer dreper algoritmerekkevidden.', 'Коментарі в соцмережах потребують своєчасних відповідей. Але писати вдумливі відповіді на 20+ коментарів на 3 платформах щодня — це поглинач часу. Ігнорування коментарів вбиває охоплення алгоритмів.', 'sync-comments fetches new comments from Facebook and Instagram every 30 minutes. Each comment gets sentiment analysis (-1 to +1 score). generate-comment-reply creates a contextual reply suggestion. The comments bot sends it to Telegram with buttons: Reply, Edit, Ignore. One tap to send, or edit first.', 'sync-comments henter nye kommentarer fra Facebook og Instagram hvert 30. minutt. Hver kommentar får sentimentanalyse (-1 til +1). generate-comment-reply lager et kontekstuelt svarforslag. Kommentarboten sender det til Telegram med knapper: Svar, Rediger, Ignorer. Ett trykk for å sende, eller rediger først.', 'sync-comments забирає нові коментарі з Facebook та Instagram кожні 30 хвилин. Кожен коментар отримує аналіз тональності (-1 до +1). generate-comment-reply створює контекстну пропозицію відповіді. Бот коментарів надсилає її в Telegram з кнопками: Відповісти, Редагувати, Ігнорувати. Один тап для відправки або спочатку редагування.', 'Response time dropped from hours to minutes. Spam gets auto-flagged. Questions get thoughtful AI drafts. The human stays in the loop, but the heavy lifting is done.', 'Responstid falt fra timer til minutter. Spam flagges automatisk. Spørsmål får gjennomtenkte AI-utkast. Mennesket forblir i loopen, men det tunge arbeidet er gjort.', 'Час відповіді впав з годин до хвилин. Спам автоматично позначається. Запитання отримують продумані AI-чернетки. Людина залишається в процесі, але важка робота вже зроблена.', '{"Azure OpenAI","Facebook Graph API","Instagram API","Supabase","Telegram Bot API"}', '{"#AI","#SentimentAnalysis","#SocialMedia","#Comments","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p06', 'portfolio', 'ai_automation', 'AI Duplicate Detection — when six channels post the same story', 'AI-duplikatdeteksjon — når seks kanaler publiserer samme nyhet', 'AI-виявлення дублікатів — коли шість каналів постять ту саму новину', 'Breaking news hits all 6 Telegram channels within minutes. Two-layer detection (title similarity + AI semantic comparison) catches duplicates before they flood the queue.', 'Siste nytt treffer alle 6 Telegram-kanaler innen minutter. To-lags deteksjon (tittellikhet + AI-semantisk sammenligning) fanger duplikater før de flommer inn i køen.', 'Гарячі новини потрапляють у всі 6 Telegram-каналів за лічені хвилини. Дворівневе виявлення (схожість заголовків + AI-семантичне порівняння) ловить дублікати до того, як вони заповнять чергу.', 'Breaking news hits all 6 Telegram channels within minutes. Without detection, the same story gets scraped 6 times, creating 6 identical articles in the moderation queue. Reviewing duplicates wastes time and creates confusion.', 'Siste nytt treffer alle 6 Telegram-kanaler innen minutter. Uten deteksjon blir samme nyhet skrapet 6 ganger, noe som skaper 6 identiske artikler i modereringskøen. Å gjennomgå duplikater sløser tid og skaper forvirring.', 'Гарячі новини потрапляють у всі 6 Telegram-каналів за хвилини. Без детекції та сама новина скрейпиться 6 разів, створюючи 6 однакових статей у черзі модерації. Перегляд дублікатів — марна трата часу та плутанина.', 'The scraper checks incoming titles against a 48-hour cache of recent titles. Exact or near-exact matches are auto-rejected. For uncertain cases, Azure OpenAI compares the full content semantically. Both layers run inside pre-moderate-news before the article enters the queue.', 'Skraperen sjekker innkommende titler mot en 48-timers cache av nylige titler. Eksakte eller nesten-eksakte treff avvises automatisk. For usikre tilfeller sammenligner Azure OpenAI hele innholdet semantisk. Begge lag kjører i pre-moderate-news før artikkelen går inn i køen.', 'Скрейпер перевіряє вхідні заголовки проти 48-годинного кешу нещодавніх заголовків. Точні або майже точні збіги автоматично відхиляються. Для невизначених випадків Azure OpenAI порівнює повний контент семантично. Обидва шари працюють у pre-moderate-news до потрапляння статті в чергу.', 'Duplicate rate in moderation queue dropped from ~40% to under 3%. The two-layer approach keeps API costs low — most duplicates are caught by the free title comparison.', 'Duplikatraten i modereringskøen falt fra ~40% til under 3%. To-lags-tilnærmingen holder API-kostnadene lave — de fleste duplikater fanges av den gratis tittelsammenligningen.', 'Відсоток дублікатів у черзі модерації впав з ~40% до менш ніж 3%. Дворівневий підхід тримає витрати на API низькими — більшість дублікатів ловиться безкоштовним порівнянням заголовків.', '{"Azure OpenAI","Supabase","Deno"}', '{"#AI","#DuplicateDetection","#NLP","#ContentPipeline","#SemanticSearch"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p07', 'portfolio', 'ai_automation', 'Multi-LLM Provider Support — never depend on one AI vendor', 'Støtte for flere LLM-leverandører — aldri avhengig av én AI-leverandør', 'Підтримка кількох LLM-провайдерів — ніколи не залежати від одного AI-вендора', 'Azure OpenAI had a 4-hour outage. The entire content pipeline was dead. Now the system supports Azure, Gemini, Grok, and Groq with automatic fallback.', 'Azure OpenAI hadde et 4-timers strømbrudd. Hele innholdspipelinen var nede. Nå støtter systemet Azure, Gemini, Grok og Groq med automatisk fallback.', 'Azure OpenAI мав 4-годинний збій. Весь контент-пайплайн був мертвий. Тепер система підтримує Azure, Gemini, Grok і Groq з автоматичним фолбеком.', 'Azure OpenAI had a 4-hour outage in January. During that time, the entire content pipeline was dead. No pre-moderation, no rewrites, no image prompts. A single point of failure.', 'Azure OpenAI hadde et 4-timers strømbrudd i januar. I denne perioden var hele innholdspipelinen nede. Ingen forhåndsmoderering, ingen omskrivinger, ingen bildeprompter. Et enkelt feilpunkt.', 'Azure OpenAI мав 4-годинний збій у січні. Весь цей час контент-пайплайн був мертвий. Жодної премодерації, жодних рерайтів, жодних промптів для зображень. Єдина точка відмови.', 'The system supports Azure OpenAI, Google Gemini, Grok (XAI), and Groq. Image generation uses cascading fallback: Grok -> Gemini. Translation experimented with multi-LLM quality comparison via regenerate-translations. Each provider''s key is stored in api_settings — switchable from the admin panel.', 'Systemet støtter Azure OpenAI, Google Gemini, Grok (XAI) og Groq. Bildegenerering bruker kaskaderende fallback: Grok -> Gemini. Oversettelse eksperimenterte med multi-LLM kvalitetssammenligning via regenerate-translations. Hver leverandørs nøkkel lagres i api_settings — kan byttes fra adminpanelet.', 'Система підтримує Azure OpenAI, Google Gemini, Grok (XAI) та Groq. Генерація зображень використовує каскадний фолбек: Grok -> Gemini. Переклад експериментував із мульти-LLM порівнянням якості через regenerate-translations. Ключ кожного провайдера зберігається в api_settings — перемикається з адмінки.', 'Zero downtime during subsequent provider outages. The cascading approach also improved image quality — Grok produces better creative images, Gemini handles technical illustrations. Best of both worlds.', 'Null nedetid under påfølgende leverandøravbrudd. Den kaskaderende tilnærmingen forbedret også bildekvaliteten — Grok produserer bedre kreative bilder, Gemini håndterer tekniske illustrasjoner. Det beste fra begge verdener.', 'Нуль простоїв під час наступних збоїв провайдерів. Каскадний підхід також покращив якість зображень — Grok створює кращі креативні зображення, Gemini обробляє технічні ілюстрації. Найкраще з обох світів.', '{"Azure OpenAI","Google Gemini","Grok","Groq","Supabase"}', '{"#AI","#MultiLLM","#Resilience","#Fallback","#CloudArchitecture"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p08', 'portfolio', 'media_production', 'Remotion Video Rendering — turning text articles into broadcast-ready video', 'Remotion-videorendering — gjør tekstartikler om til kringkastingsklare videoer', 'Remotion-рендеринг відео — перетворення текстових статей у відео, готове до ефіру', 'Video content gets 5-10x more reach. Manual production takes 30-60 minutes per video. Remotion makes the entire pipeline — script, voiceover, subtitles, rendering — fully programmatic.', 'Videoinnhold får 5-10x mer rekkevidde. Manuell produksjon tar 30-60 minutter per video. Remotion gjør hele pipelinen — manus, voiceover, undertekster, rendering — fullstendig programmatisk.', 'Відеоконтент отримує в 5-10 разів більше охоплення. Ручне виробництво займає 30-60 хвилин на відео. Remotion робить весь пайплайн — скрипт, озвучка, субтитри, рендеринг — повністю програмним.', 'Video content gets 5-10x more reach on social media than text. But producing even a simple news video manually takes 30-60 minutes: script, voiceover, editing, subtitles, export. With 5-10 articles per day, manual video production is impossible.', 'Videoinnhold får 5-10x mer rekkevidde på sosiale medier enn tekst. Men å produsere selv en enkel nyhetsvideo manuelt tar 30-60 minutter: manus, voiceover, redigering, undertekster, eksport. Med 5-10 artikler daglig er manuell videoproduksjon umulig.', 'Відеоконтент отримує в 5-10 разів більше охоплення в соцмережах, ніж текст. Але ручне виробництво навіть простого новинного відео займає 30-60 хвилин: скрипт, озвучка, монтаж, субтитри, експорт. При 5-10 статтях на день ручне виробництво відео неможливе.', 'Article text -> Azure OpenAI generates a broadcast script -> Zvukogram Neural TTS creates voiceover with word-level timestamps -> Remotion renders the final video with animated subtitles, blurred background, and progress bar. Two templates: Vertical (1080x1920 for Reels) and Horizontal (1920x1080 for YouTube). If any step fails, the system gracefully falls back to raw video upload.', 'Artikkeltekst -> Azure OpenAI genererer et kringkastingsmanus -> Zvukogram Neural TTS lager voiceover med tidsstempler på ordnivå -> Remotion rendrer den ferdige videoen med animerte undertekster, uskarp bakgrunn og fremdriftslinje. To maler: Vertikal (1080x1920 for Reels) og Horisontal (1920x1080 for YouTube). Hvis noe trinn feiler, faller systemet tilbake til rå videoopplasting.', 'Текст статті -> Azure OpenAI генерує скрипт для ефіру -> Zvukogram Neural TTS створює озвучку з таймстемпами на рівні слів -> Remotion рендерить фінальне відео з анімованими субтитрами, розмитим фоном та прогрес-баром. Два шаблони: Вертикальний (1080x1920 для Reels) і Горизонтальний (1920x1080 для YouTube). Якщо будь-який крок зазнає невдачі, система gracefully повертається до завантаження сирого відео.', 'Video production time: from 45 minutes to 3 minutes (mostly approval time). Output: broadcast-quality videos with synced subtitles, professional voiceover, and consistent branding. Toggle SKIP_REMOTION=true when raw video is preferred.', 'Videoproduksjonstid: fra 45 minutter til 3 minutter (hovedsakelig godkjenningstid). Resultat: kringkastingskvalitets videoer med synkroniserte undertekster, profesjonell voiceover og konsistent merkevarebygging. Bryter SKIP_REMOTION=true når rå video foretrekkes.', 'Час виробництва відео: з 45 хвилин до 3 хвилин (переважно час на затвердження). Результат: відео ефірної якості з синхронізованими субтитрами, професійною озвучкою та консистентним брендингом. Перемикач SKIP_REMOTION=true, коли бажано сире відео.', '{"Remotion","Azure OpenAI","Zvukogram TTS","React","GitHub Actions"}', '{"#Remotion","#VideoAutomation","#TTS","#AI","#MediaProduction"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p09', 'portfolio', 'media_production', 'Visual Director — AI decides what you see, frame by frame', 'Visuell regissør — AI bestemmer hva du ser, bilde for bilde', 'Візуальний режисер — AI вирішує, що ви бачите, кадр за кадром', 'Auto-generated videos looked monotonous. Visual Director analyzes each phrase and assigns visual effects based on meaning — particles, glitch, globe, data dashboards.', 'Autogenererte videoer så monotone ut. Visuell regissør analyserer hver frase og tildeler visuelle effekter basert på mening — partikler, glitch, jordklode, datadashbord.', 'Автогенеровані відео виглядали монотонно. Візуальний режисер аналізує кожну фразу і призначає візуальні ефекти на основі змісту — частинки, глітч, глобус, дата-дашборди.', 'Auto-generated videos looked monotonous. Same background, same text animation, same feel for every article. A story about a tech product launch shouldn''t look the same as a geopolitical analysis.', 'Autogenererte videoer så monotone ut. Samme bakgrunn, samme tekstanimasjon, samme følelse for hver artikkel. En historie om en teknologiproduktlansering bør ikke se ut som en geopolitisk analyse.', 'Автогенеровані відео виглядали монотонно. Той самий фон, та сама текстова анімація, те саме відчуття для кожної статті. Історія про запуск техпродукту не повинна виглядати так само, як геополітичний аналіз.', 'The script is split into phrases. For each phrase, the Visual Director runs keyword analysis and assigns one of 8 effect types: blur-text, particles, glitch, globe (Three.js), data-dashboard, perlin-waves, photo-native, or infographic. Each effect has its own Remotion component. The system also searches Pexels/Google for contextual images per phrase.', 'Manuset deles inn i fraser. For hver frase kjører Visuell regissør nøkkelordanalyse og tildeler én av 8 effekttyper: blur-text, particles, glitch, globe (Three.js), data-dashboard, perlin-waves, photo-native eller infographic. Hver effekt har sin egen Remotion-komponent. Systemet søker også Pexels/Google etter kontekstuelle bilder per frase.', 'Скрипт розбивається на фрази. Для кожної фрази Візуальний режисер виконує аналіз ключових слів і призначає один із 8 типів ефектів: blur-text, particles, glitch, globe (Three.js), data-dashboard, perlin-waves, photo-native або infographic. Кожен ефект має власний Remotion-компонент. Система також шукає контекстні зображення на Pexels/Google для кожної фрази.', 'Every video feels unique. The Visual Director turns a script about Nordic energy policy into a visually different experience than a script about Silicon Valley AI startups. Same pipeline, different soul.', 'Hver video føles unik. Visuell regissør gjør et manus om nordisk energipolitikk til en visuelt annerledes opplevelse enn et manus om AI-startups i Silicon Valley. Samme pipeline, forskjellig sjel.', 'Кожне відео відчувається унікальним. Візуальний режисер перетворює скрипт про нордичну енергетичну політику у візуально інший досвід, ніж скрипт про AI-стартапи Кремнієвої долини. Той самий пайплайн, інша душа.', '{"Remotion","Three.js","Pexels API","Azure OpenAI","GSAP"}', '{"#VisualDirector","#AI","#VideoEffects","#Remotion","#ThreeJS"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p10', 'portfolio', 'media_production', 'Daily News Video Digest — the morning show that makes itself', 'Daglig nyhetsvideoresymé — morgensendingen som lager seg selv', 'Щоденний відеодайджест новин — ранкове шоу, яке робить себе само', 'A daily video compilation of top stories is the gold standard. AI ranks articles, generates per-segment scripts and voiceovers, Remotion stitches everything into one broadcast.', 'En daglig videokompilasjon av toppnyheter er gullstandarden. AI rangerer artikler, genererer manus og voiceover per segment, Remotion syr alt sammen til én sending.', 'Щоденна відеокомпіляція топових новин — золотий стандарт. AI ранжує статті, генерує скрипти та озвучку по сегментах, Remotion зшиває все в один ефір.', 'A daily video compilation of top stories is the gold standard of news channels. But curating, scripting, and producing a multi-segment video daily is a full-time job for a team of 3-5 people.', 'En daglig videokompilasjon av toppnyheter er gullstandarden for nyhetskanaler. Men å kuratere, skripte og produsere en flersegments video daglig er en fulltidsjobb for et team på 3-5 personer.', 'Щоденна відеокомпіляція топових новин — золотий стандарт новинних каналів. Але курування, написання скриптів і виробництво мультисегментного відео щодня — це повна зайнятість для команди з 3-5 людей.', 'daily-video-bot Edge Function triggers daily. LLM ranks articles by relevance/importance. generate-script.js creates per-segment scripts. generate-voiceover.js records per-segment TTS. daily-compilation.js stitches everything with Remotion: Headlines Roundup cold open, segment transitions, end card. Max 10 segments, respecting YouTube attention spans.', 'daily-video-bot Edge Function utløses daglig. LLM rangerer artikler etter relevans/viktighet. generate-script.js lager manus per segment. generate-voiceover.js tar opp TTS per segment. daily-compilation.js syr alt sammen med Remotion: Headlines Roundup cold open, segmentoverganger, sluttskjerm. Maks 10 segmenter, tilpasset YouTubes oppmerksomhetsspenn.', 'daily-video-bot Edge Function запускається щодня. LLM ранжує статті за релевантністю/важливістю. generate-script.js створює скрипти по сегментах. generate-voiceover.js записує TTS по сегментах. daily-compilation.js зшиває все через Remotion: Headlines Roundup cold open, переходи між сегментами, фінальна карточка. Максимум 10 сегментів, з урахуванням тривалості уваги на YouTube.', 'A daily news show produced in under 10 minutes of compute time. Telegram bot sends it for approval. One click to publish on YouTube. Consistent quality, consistent schedule, zero burnout.', 'En daglig nyhetssending produsert på under 10 minutter beregningstid. Telegram-bot sender den til godkjenning. Ett klikk for å publisere på YouTube. Konsistent kvalitet, konsistent timeplan, null utbrenthet.', 'Щоденне новинне шоу за менш ніж 10 хвилин обчислювального часу. Telegram-бот надсилає на затвердження. Один клік для публікації на YouTube. Стабільна якість, стабільний розклад, нуль вигорання.', '{"Remotion","Azure OpenAI","Zvukogram TTS","GitHub Actions","YouTube API"}', '{"#VideoDigest","#AI","#NewsAutomation","#Remotion","#YouTube"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p11', 'portfolio', 'media_production', 'AI Thumbnail Generation — 4 options, one click', 'AI-miniatyrbildegenerering — 4 alternativer, ett klikk', 'AI-генерація мініатюр — 4 варіанти, один клік', 'YouTube thumbnails make or break CTR. AI generates 4 distinct thumbnail variants and sends them to Telegram for instant selection by the moderator.', 'YouTube-miniatyrbilder avgjør klikkfrekvensen. AI genererer 4 distinkte miniatyrvarianter og sender dem til Telegram for umiddelbar velging av moderatoren.', 'Мініатюри YouTube визначають CTR. AI генерує 4 різні варіанти мініатюр і надсилає їх у Telegram для миттєвого вибору модератором.', 'YouTube thumbnails make or break click-through rates. But designing unique thumbnails per video is a creative bottleneck. Generic auto-thumbnails from video frames perform poorly.', 'YouTube-miniatyrbilder avgjør klikkfrekvensen. Men å designe unike miniatyrbilder per video er en kreativ flaskehals. Generiske automatiske miniatyrbilder fra videorammer presterer dårlig.', 'Мініатюри YouTube визначають клікабельність. Але дизайн унікальних мініатюр для кожного відео — це креативне вузьке місце. Загальні автоматичні мініатюри з кадрів відео працюють погано.', 'generate-ai-thumbnail.js sends article context to Gemini to create 4 stylistically different thumbnail concepts. Each emphasizes different hooks: data point, emotional face, contrast, question. Telegram bot displays all 4 as inline images. Moderator taps one. Background music auto-ducks during voiceover sections.', 'generate-ai-thumbnail.js sender artikkelkontekst til Gemini for å lage 4 stilistisk forskjellige miniatyrbildekonsepter. Hvert fremhever forskjellige kroker: datapunkt, emosjonelt ansikt, kontrast, spørsmål. Telegram-bot viser alle 4 som innebygde bilder. Moderator trykker på ett. Bakgrunnsmusikk dempes automatisk under voiceover-seksjoner.', 'generate-ai-thumbnail.js надсилає контекст статті до Gemini для створення 4 стилістично різних концептів мініатюр. Кожен акцентує різні хуки: дані, емоційне обличчя, контраст, запитання. Telegram-бот показує всі 4 як інлайн-зображення. Модератор тапає на одне. Фонова музика автоматично приглушується під час озвучки.', 'Thumbnail selection takes 5 seconds instead of 15 minutes of design work. A/B testing through variety — the 4-option approach naturally surfaces what works for different content types.', 'Miniatyrvalg tar 5 sekunder i stedet for 15 minutters designarbeid. A/B-testing gjennom variasjon — 4-alternativs-tilnærmingen avdekker naturlig hva som fungerer for forskjellige innholdstyper.', 'Вибір мініатюри займає 5 секунд замість 15 хвилин дизайнерської роботи. A/B-тестування через різноманітність — підхід із 4 варіантами природно виявляє, що працює для різних типів контенту.', '{"Google Gemini","Telegram Bot API","Remotion","Node.js"}', '{"#AI","#Thumbnails","#YouTube","#Gemini","#ContentCreation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p12', 'portfolio', 'media_production', 'Neural TTS — the voice that doesn''t sound like a robot', 'Nevral TTS — stemmen som ikke høres ut som en robot', 'Нейронний TTS — голос, який не звучить як робот', 'Standard TTS sounds robotic. Professional voiceover costs $50-200 per video. Zvukogram Neural TTS delivers human-quality voice with word-level timestamp alignment for perfect subtitle sync.', 'Standard TTS høres robotaktig ut. Profesjonell voiceover koster $50-200 per video. Zvukogram Neural TTS leverer menneskelig kvalitet med tidsstempler på ordnivå for perfekt undertekstsynkronisering.', 'Стандартний TTS звучить роботизовано. Професійна озвучка коштує $50-200 за відео. Zvukogram Neural TTS дає голос людської якості з таймстемпами на рівні слів для ідеальної синхронізації субтитрів.', 'Standard TTS (Google, AWS Polly) sounds robotic. Professional voiceover artists cost $50-200 per video. For 5-10 videos daily, that''s $250-2000/day. Unsustainable.', 'Standard TTS (Google, AWS Polly) høres robotaktig ut. Profesjonelle voiceover-artister koster $50-200 per video. For 5-10 videoer daglig er det $250-2000/dag. Uholdbart.', 'Стандартний TTS (Google, AWS Polly) звучить роботизовано. Професійні диктори коштують $50-200 за відео. При 5-10 відео на день це $250-2000/день. Нестійко.', 'The script goes to Zvukogram API (replaced earlier OpenAI TTS for better quality). Returns audio file + JSON with per-word start/end timestamps. Remotion''s AnimatedSubtitles component uses these timestamps for pixel-perfect subtitle synchronization. Each word highlights exactly when spoken.', 'Manuset sendes til Zvukogram API (erstattet tidligere OpenAI TTS for bedre kvalitet). Returnerer lydfil + JSON med start-/sluttidsstempler per ord. Remotions AnimatedSubtitles-komponent bruker disse tidsstemplene for pikselperfekt undertekstsynkronisering. Hvert ord utheves nøyaktig når det uttales.', 'Скрипт відправляється до Zvukogram API (замінив раніше OpenAI TTS для кращої якості). Повертає аудіофайл + JSON з таймстемпами початку/кінця для кожного слова. Компонент AnimatedSubtitles у Remotion використовує ці таймстемпи для піксельно-точної синхронізації субтитрів. Кожне слово підсвічується саме тоді, коли воно вимовляється.', 'Voiceover quality indistinguishable from human at scale. Word-level sync means subtitles feel like professional captioning, not auto-generated afterthought. Cost: fraction of human voiceover.', 'Voiceover-kvalitet som ikke kan skilles fra menneske i skala. Synkronisering på ordnivå betyr at undertekster føles som profesjonell teksting, ikke autogenerert ettertanke. Kostnad: brøkdel av menneskelig voiceover.', 'Якість озвучки, нерозрізнювана від людської у масштабі. Синхронізація на рівні слів означає, що субтитри відчуваються як професійне титрування, а не автогенерована думка наостанок. Вартість: частка від людської озвучки.', '{"Zvukogram TTS","Remotion","React","Node.js"}', '{"#TTS","#NeuralVoice","#Subtitles","#Remotion","#MediaProduction"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p13', 'portfolio', 'media_production', 'Cross-Platform Video Distribution — one render, four platforms', 'Kryssplattform videodistribusjon — én rendering, fire plattformer', 'Кросплатформна дистрибуція відео — один рендер, чотири платформи', 'YouTube wants 16:9, Instagram Reels wants 9:16, LinkedIn wants MP4 under 200MB. Remotion renders both formats, GitHub Actions uploads natively to each platform.', 'YouTube vil ha 16:9, Instagram Reels vil ha 9:16, LinkedIn vil ha MP4 under 200MB. Remotion rendrer begge formater, GitHub Actions laster opp nativt til hver plattform.', 'YouTube хоче 16:9, Instagram Reels хоче 9:16, LinkedIn хоче MP4 до 200MB. Remotion рендерить обидва формати, GitHub Actions завантажує нативно на кожну платформу.', 'YouTube wants 16:9. Instagram Reels wants 9:16. LinkedIn wants MP4 under 200MB. Facebook wants its own upload. Each platform has different format requirements, aspect ratios, and upload APIs.', 'YouTube vil ha 16:9. Instagram Reels vil ha 9:16. LinkedIn vil ha MP4 under 200MB. Facebook vil ha sin egen opplasting. Hver plattform har forskjellige formatkrav, aspektforhold og opplastings-API-er.', 'YouTube хоче 16:9. Instagram Reels хоче 9:16. LinkedIn хоче MP4 до 200MB. Facebook хоче своє власне завантаження. Кожна платформа має різні вимоги до формату, співвідношення сторін і API завантаження.', 'Remotion renders two versions: NewsVideo (1080x1920) and NewsVideo (1920x1080). GitHub Actions workflows handle the heavy lifting: process-video.yml (YouTube), linkedin-video.yml (LinkedIn native), instagram-video.yml (Reels), facebook-video.yml (Facebook). MTKruto downloads source videos from Telegram (up to 2GB, bypassing Bot API''s 20MB limit). Fallback: if any upload fails, Telegram embed is used.', 'Remotion rendrer to versjoner: NewsVideo (1080x1920) og NewsVideo (1920x1080). GitHub Actions-arbeidsflyter håndterer tungt arbeid: process-video.yml (YouTube), linkedin-video.yml (LinkedIn nativt), instagram-video.yml (Reels), facebook-video.yml (Facebook). MTKruto laster ned kildevideoer fra Telegram (opptil 2GB, omgår Bot APIs 20MB-grense). Fallback: hvis opplasting feiler, brukes Telegram-embed.', 'Remotion рендерить дві версії: NewsVideo (1080x1920) та NewsVideo (1920x1080). Воркфлоу GitHub Actions виконують важку роботу: process-video.yml (YouTube), linkedin-video.yml (LinkedIn native), instagram-video.yml (Reels), facebook-video.yml (Facebook). MTKruto завантажує вихідні відео з Telegram (до 2GB, обходячи ліміт Bot API у 20MB). Фолбек: якщо завантаження зазнає невдачі, використовується Telegram embed.', 'One article -> one video -> four platforms -> maximum reach. Fully automated. The GitHub Actions approach avoids Edge Function /tmp limits (256MB free, 512MB pro) for large video files.', 'Én artikkel -> én video -> fire plattformer -> maksimal rekkevidde. Fullstendig automatisert. GitHub Actions-tilnærmingen unngår Edge Function /tmp-begrensninger (256MB gratis, 512MB pro) for store videofiler.', 'Одна стаття -> одне відео -> чотири платформи -> максимальне охоплення. Повністю автоматизовано. Підхід GitHub Actions обходить обмеження Edge Function /tmp (256MB free, 512MB pro) для великих відеофайлів.', '{"Remotion","GitHub Actions","MTKruto","YouTube API","LinkedIn API","Instagram API","Facebook API"}', '{"#VideoDistribution","#CrossPlatform","#Automation","#Remotion","#GitHubActions"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p14', 'portfolio', 'media_production', 'LinkedIn Native Image Upload — because link previews don''t cut it', 'LinkedIn nativ bildeopplasting — fordi lenkforhåndsvisninger ikke holder mål', 'LinkedIn нативне завантаження зображень — бо прев''ю посилань не вистачає', 'LinkedIn auto-generated link previews are small and blurry. Native image uploads get 2-3x more impressions. Full upload flow with race condition-proof duplicate prevention.', 'LinkedIns autogenererte lenkforhåndsvisninger er små og uskarpe. Native bildeopplastinger får 2-3x flere visninger. Full opplastingsflyt med duplikatforebygging mot race conditions.', 'Автогенеровані прев''ю посилань LinkedIn маленькі та розмиті. Нативне завантаження зображень дає в 2-3 рази більше показів. Повний флоу завантаження з захистом від race condition при запобіганні дублікатів.', 'LinkedIn''s auto-generated link previews are small, blurry, and uncontrollable. Posts with native images get 2-3x more impressions than link posts. But the LinkedIn API''s native upload process is complex: register asset, get upload URL, upload binary, get asset URN, then create post.', 'LinkedIns autogenererte lenkforhåndsvisninger er små, uskarpe og ukontrollerbare. Innlegg med native bilder får 2-3x flere visninger enn lenkeinnlegg. Men LinkedIns APIs native opplastingsprosess er kompleks: registrer eiendel, hent opplastings-URL, last opp binærfil, hent eiendels-URN, deretter opprett innlegg.', 'Автогенеровані прев''ю посилань LinkedIn маленькі, розмиті та неконтрольовані. Пости з нативними зображеннями отримують в 2-3 рази більше показів, ніж пости з посиланнями. Але процес нативного завантаження через LinkedIn API складний: зареєструвати ассет, отримати URL завантаження, завантажити бінарник, отримати URN ассету, потім створити пост.', 'post-to-linkedin Edge Function: 1) Check duplicates via wasAlreadyPosted() (checks both ''posted'' AND ''pending'' — race condition fix). 2) Create ''pending'' record. 3) Register upload with Assets API. 4) Download source image. 5) Upload binary to LinkedIn. 6) Create UGC post with asset URN. 7) Update status to ''posted''. Fallback: if image upload fails, falls back to ARTICLE type (link preview).', 'post-to-linkedin Edge Function: 1) Sjekk duplikater via wasAlreadyPosted() (sjekker både ''posted'' OG ''pending'' — race condition-fiks). 2) Opprett ''pending''-post. 3) Registrer opplasting med Assets API. 4) Last ned kildebilde. 5) Last opp binærfil til LinkedIn. 6) Opprett UGC-innlegg med eiendels-URN. 7) Oppdater status til ''posted''. Fallback: hvis bildeopplasting feiler, faller tilbake til ARTICLE-type (lenkforhåndsvisning).', 'post-to-linkedin Edge Function: 1) Перевірка дублікатів через wasAlreadyPosted() (перевіряє і ''posted'', і ''pending'' — фікс race condition). 2) Створення ''pending'' запису. 3) Реєстрація завантаження через Assets API. 4) Завантаження вихідного зображення. 5) Завантаження бінарника в LinkedIn. 6) Створення UGC поста з URN ассету. 7) Оновлення статусу на ''posted''. Фолбек: якщо завантаження зображення зазнає невдачі, повертається до типу ARTICLE (прев''ю посилання).', 'Average impressions per post increased after switching to native uploads. The duplicate prevention system (checking both statuses) eliminated the double-posting bug that plagued the first version.', 'Gjennomsnittlige visninger per innlegg økte etter overgang til native opplastinger. Duplikatforebyggingssystemet (sjekking av begge statuser) eliminerte dobbeltpostingsfeilen som plaget den første versjonen.', 'Середня кількість показів на пост зросла після переходу на нативне завантаження. Система запобігання дублікатів (перевірка обох статусів) усунула баг подвійного постингу, що мучив першу версію.', '{"LinkedIn UGC API","LinkedIn Assets API","Supabase Edge Functions","Deno"}', '{"#LinkedIn","#NativeUpload","#SocialMedia","#API","#RaceCondition"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p15', 'portfolio', 'media_production', 'Instagram Publishing — the platform that hates developers', 'Instagram-publisering — plattformen som hater utviklere', 'Публікація в Instagram — платформа, яка ненавидить розробників', 'Instagram API is notoriously restrictive. Pre-validation of aspect ratios, comprehensive error handling, and polling-based Reels publishing brought failure rate from 40% to under 5%.', 'Instagram API er notorisk restriktivt. Forhåndsvalidering av aspektforhold, omfattende feilhåndtering og pollingsbasert Reels-publisering reduserte feilraten fra 40% til under 5%.', 'API Instagram сумнозвісно обмежувальний. Попередня валідація співвідношення сторін, комплексна обробка помилок та публікація Reels на основі полінгу знизили відсоток помилок з 40% до менш ніж 5%.', 'Instagram''s API is notoriously restrictive. No clickable links in captions. Business account required. Aspect ratio must be between 4:5 and 1.91:1 (or post gets rejected). Reels require a multi-step container creation -> polling -> publish flow. Error messages are cryptic (#10, #24, #100, #190).', 'Instagrams API er notorisk restriktivt. Ingen klikkbare lenker i bildetekster. Bedriftskonto kreves. Aspektforhold må være mellom 4:5 og 1.91:1 (ellers avvises innlegget). Reels krever en flerstegs opprettelse av container -> polling -> publiseringsflyt. Feilmeldinger er kryptiske (#10, #24, #100, #190).', 'API Instagram сумнозвісно обмежувальний. Жодних клікабельних посилань у підписах. Потрібен бізнес-акаунт. Співвідношення сторін має бути між 4:5 та 1.91:1 (або пост відхиляється). Reels вимагають багатокрокового створення контейнера -> полінг -> публікація. Повідомлення про помилки криптичні (#10, #24, #100, #190).', 'post-to-instagram creates a media container, polls status every 10 seconds (max 30 attempts), then publishes. Aspect ratio pre-validation via binary header parsing catches bad images before they hit the API. Instagram errors get mapped to fix instructions (Error #10 -> "regenerate token with instagram_content_publish scope"). Caption formatter respects the 2,200 char limit.', 'post-to-instagram oppretter en mediecontainer, poller status hvert 10. sekund (maks 30 forsøk), og publiserer deretter. Forhåndsvalidering av aspektforhold via binær header-parsing fanger dårlige bilder før de treffer API-et. Instagram-feil mappes til retteinstruksjoner (Error #10 -> "regenerer token med instagram_content_publish scope"). Bildetekstformaterer respekterer grensen på 2200 tegn.', 'post-to-instagram створює медіа-контейнер, полить статус кожні 10 секунд (максимум 30 спроб), потім публікує. Попередня валідація співвідношення сторін через парсинг бінарного заголовку ловить погані зображення до потрапляння в API. Помилки Instagram мапляться на інструкції виправлення (Error #10 -> "перегенеруйте токен зі скоупом instagram_content_publish"). Форматер підписів дотримується ліміту в 2200 символів.', 'Instagram publishing went from a 40% failure rate (API rejections) to under 5%. The error-to-fix mapping means every failure is self-diagnosable — no more digging through Facebook''s documentation.', 'Instagram-publisering gikk fra 40% feilrate (API-avvisninger) til under 5%. Feil-til-fiks-mappingen betyr at hver feil er selvdiagnostiserbar — ikke mer graving i Facebooks dokumentasjon.', 'Публікація в Instagram перейшла від 40% відмов (відхилення API) до менш ніж 5%. Маппінг помилок до виправлень означає, що кожна помилка самодіагностується — більше не потрібно копатися в документації Facebook.', '{"Facebook Graph API","Instagram API","Supabase Edge Functions","Deno"}', '{"#Instagram","#API","#SocialMedia","#ErrorHandling","#Reels"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p16', 'portfolio', 'media_production', 'Social Analytics Dashboard — building my own Shield App', 'Sosial analyse-dashboard — bygger min egen Shield App', 'Дашборд аналітики соцмереж — будую свій власний Shield App', 'Shield App charges $25/month for LinkedIn analytics. Built a full analytics dashboard inside the admin panel using data already flowing through the system — at zero recurring cost.', 'Shield App tar $25/mnd for LinkedIn-analyse. Bygget et fullverdig analysedashboard i adminpanelet med data som allerede flyter gjennom systemet — til null løpende kostnad.', 'Shield App бере $25/місяць за аналітику LinkedIn. Побудував повний дашборд аналітики в адмінці, використовуючи дані, що вже проходять через систему — з нульовими щомісячними витратами.', 'Shield App charges $25/month/profile for LinkedIn analytics. I already have all the data flowing through my system — posts, engagement, timestamps. I just wasn''t collecting metrics from the platforms.', 'Shield App tar $25/mnd/profil for LinkedIn-analyse. Jeg har allerede alle dataene som flyter gjennom systemet mitt — innlegg, engasjement, tidsstempler. Jeg samlet bare ikke inn metrikker fra plattformene.', 'Shield App бере $25/місяць/профіль за аналітику LinkedIn. Усі дані вже проходять через мою систему — пости, залученість, таймстемпи. Я просто не збирав метрики з платформ.', 'New Edge Function sync-social-metrics runs every 6 hours. Fetches post insights from Facebook Graph API and Instagram Media API. Tracks follower counts in follower_history table. Aggregates daily snapshots. Dashboard shows: summary cards with % changes, engagement-over-time charts, top posts ranking, platform comparison, follower growth, posting frequency. CSV export for reporting.', 'Ny Edge Function sync-social-metrics kjører hver 6. time. Henter innleggsinnsikt fra Facebook Graph API og Instagram Media API. Sporer følgertall i follower_history-tabellen. Aggregerer daglige øyeblikksbilder. Dashboard viser: sammendragskort med %-endringer, engasjement-over-tid-diagrammer, topp innlegg-rangering, plattformsammenligning, følgervekst, publiseringsfrekvens. CSV-eksport for rapportering.', 'Нова Edge Function sync-social-metrics запускається кожні 6 годин. Забирає інсайти постів з Facebook Graph API та Instagram Media API. Відстежує кількість підписників у таблиці follower_history. Агрегує щоденні знімки. Дашборд показує: карточки з % змінами, графіки залученості в часі, рейтинг топ-постів, порівняння платформ, зростання підписників, частоту публікацій. CSV-експорт для звітності.', 'Full analytics dashboard at zero recurring cost. Real-time engagement tracking for Facebook and Instagram. LinkedIn pending API approval — when it arrives, it''s just filling in one function stub.', 'Fullverdig analysedashboard til null løpende kostnad. Sanntids engasjementssporing for Facebook og Instagram. LinkedIn venter på API-godkjenning — når den kommer, er det bare å fylle inn én funksjonsstubb.', 'Повний дашборд аналітики з нульовими щомісячними витратами. Відстеження залученості в реальному часі для Facebook та Instagram. LinkedIn очікує на затвердження API — коли воно прийде, потрібно лише заповнити один стаб функції.', '{"Facebook Graph API","Instagram API","Recharts","Supabase","Deno"}', '{"#Analytics","#Dashboard","#SocialMedia","#Recharts","#ZeroCost"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p17', 'portfolio', 'media_production', 'Race Condition-Proof Duplicate Prevention — the bug that posted everything twice', 'Race condition-sikker duplikatforebygging — feilen som postet alt to ganger', 'Захист від race condition при дублікатах — баг, який постив все двічі', 'Articles were posted twice to LinkedIn due to a classic race condition. Fixed with a UNIQUE constraint + pending status check before the actual API call.', 'Artikler ble postet to ganger til LinkedIn på grunn av en klassisk race condition. Fikset med en UNIQUE-begrensning + pending-statussjekk før selve API-kallet.', 'Статті постилися двічі в LinkedIn через класичний race condition. Виправлено через UNIQUE constraint + перевірку статусу pending перед самим API-викликом.', 'In January 2025, articles were being posted twice to LinkedIn. The duplicate check (wasAlreadyPosted()) only looked for status=''posted''. But between the check and the actual posting, there''s a ~3 second window where another request could also pass the check and start posting.', 'I januar 2025 ble artikler postet to ganger til LinkedIn. Duplikatsjekken (wasAlreadyPosted()) sjekket bare status=''posted''. Men mellom sjekken og selve postingen er det et ~3 sekunders vindu der en annen forespørsel også kunne passere sjekken og begynne å poste.', 'У січні 2025 статті постилися двічі в LinkedIn. Перевірка дублікатів (wasAlreadyPosted()) шукала лише status=''posted''. Але між перевіркою та фактичним постингом є вікно ~3 секунди, де інший запит теж міг пройти перевірку та почати постити.', 'createSocialPost() inserts a pending record with UNIQUE(content_id, platform, language). If the insert fails with error code 23505, it means another process already started posting. The function returns {isNew: false, raceCondition: true} and the caller aborts. After successful posting, status updates to ''posted''.', 'createSocialPost() setter inn en pending-post med UNIQUE(content_id, platform, language). Hvis innsettingen feiler med feilkode 23505, betyr det at en annen prosess allerede har begynt å poste. Funksjonen returnerer {isNew: false, raceCondition: true} og kalleren avbryter. Etter vellykket posting oppdateres status til ''posted''.', 'createSocialPost() вставляє pending запис із UNIQUE(content_id, platform, language). Якщо вставка зазнає невдачі з кодом помилки 23505, це означає, що інший процес вже почав постити. Функція повертає {isNew: false, raceCondition: true} і викликач скасовує. Після успішного постингу статус оновлюється на ''posted''.', 'Zero duplicate posts since the fix. The pattern is now used across all three social platforms. A 3-line database constraint replaced what would have been complex distributed locking.', 'Null duplikatinnlegg siden fiksen. Mønsteret brukes nå på tvers av alle tre sosiale plattformer. En 3-linjers databasebegrensning erstattet det som ville vært kompleks distribuert låsing.', 'Нуль дублікатів постів після фіксу. Патерн тепер використовується на всіх трьох соціальних платформах. 3-рядковий database constraint замінив те, що було б складним розподіленим блокуванням.', '{"PostgreSQL","Supabase","Deno"}', '{"#RaceCondition","#PostgreSQL","#DuplicatePrevention","#BugFix","#Database"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p18', 'portfolio', 'bot_scraping', '9-Step Moderation Workflow — from raw scrape to published article in 4 taps', '9-trinns modereringsarbeidsflyt — fra rå skraping til publisert artikkel på 4 trykk', '9-кроковий воркфлоу модерації — від сирого скрейпу до опублікованої статті за 4 тапи', 'Content moderation via Telegram with complex branching: image selection, language choice, platform selection. Handles 50+ articles/day with average moderation time of 8 seconds per article.', 'Innholdsmoderering via Telegram med kompleks forgrening: bildevalg, språkvalg, plattformvalg. Håndterer 50+ artikler/dag med gjennomsnittlig modereringstid på 8 sekunder per artikkel.', 'Модерація контенту через Telegram зі складним розгалуженням: вибір зображення, мови, платформи. Обробляє 50+ статей/день з середнім часом модерації 8 секунд на статтю.', 'Content moderation needed a workflow that''s fast on mobile (Telegram), supports complex branching (image selection, language choice, platform selection), and handles 50+ articles per day without overwhelming the moderator.', 'Innholdsmoderering trengte en arbeidsflyt som er rask på mobil (Telegram), støtter kompleks forgrening (bildevalg, språkvalg, plattformvalg), og håndterer 50+ artikler daglig uten å overbelaste moderatoren.', 'Модерація контенту потребувала воркфлоу, який швидкий на мобільному (Telegram), підтримує складне розгалуження (вибір зображення, мови, платформи) та обробляє 50+ статей на день без перевантаження модератора.', 'telegram-webhook Edge Function handles all inline button callbacks. Pattern: action_prefix_${newsId}. The bot edits the same message at each step (no message spam). Image priority: processed_image_url > image_url > null. For video posts, the workflow detects videoUrl && videoType and jumps straight to publish buttons.', 'telegram-webhook Edge Function håndterer alle inline-knappkallbacker. Mønster: action_prefix_${newsId}. Boten redigerer samme melding ved hvert trinn (ingen meldingsspam). Bildeprioritet: processed_image_url > image_url > null. For videoinnlegg oppdager arbeidsflyten videoUrl && videoType og hopper rett til publiseringsknapper.', 'telegram-webhook Edge Function обробляє всі колбеки інлайн-кнопок. Патерн: action_prefix_${newsId}. Бот редагує те саме повідомлення на кожному кроці (без спаму повідомленнями). Пріоритет зображень: processed_image_url > image_url > null. Для відеопостів воркфлоу визначає videoUrl && videoType і переходить прямо до кнопок публікації.', 'Average moderation time per article: 8 seconds (4 taps). The 64-byte callback constraint forced elegant prefix design. Message editing (vs sending new messages) keeps the chat clean even with 50+ articles per day.', 'Gjennomsnittlig modereringstid per artikkel: 8 sekunder (4 trykk). 64-byte callback-begrensningen tvang frem elegant prefiksdesign. Meldingsredigering (vs sending av nye meldinger) holder chatten ren selv med 50+ artikler daglig.', 'Середній час модерації на статтю: 8 секунд (4 тапи). Обмеження колбеку в 64 байти змусило створити елегантний дизайн префіксів. Редагування повідомлень (замість відправки нових) тримає чат чистим навіть при 50+ статтях на день.', '{"Telegram Bot API","Supabase Edge Functions","Deno"}', '{"#TelegramBot","#Moderation","#Workflow","#ContentPipeline","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p19', 'portfolio', 'bot_scraping', 'Creative Builder — Telegram as an image prompt IDE', 'Creative Builder — Telegram som et bildepromt-IDE', 'Creative Builder — Telegram як IDE для промптів зображень', 'AI-generated images need creative direction. An interactive prompt constructor inside Telegram with 7 categories x 6 options lets non-technical moderators influence visual output through tapping.', 'AI-genererte bilder trenger kreativ retning. En interaktiv promptkonstruktør inne i Telegram med 7 kategorier x 6 alternativer lar ikke-tekniske moderatorer påvirke visuelt resultat gjennom trykking.', 'AI-генеровані зображення потребують креативного напрямку. Інтерактивний конструктор промптів у Telegram із 7 категоріями x 6 опцій дозволяє нетехнічним модераторам впливати на візуальний результат через тапи.', 'AI-generated images sometimes need creative direction. "Make it more corporate" or "use warmer colors" doesn''t translate well to structured prompts. The moderator needs to influence the visual output without writing complex prompts.', 'AI-genererte bilder trenger noen ganger kreativ retning. "Gjør det mer bedriftsmessig" eller "bruk varmere farger" oversettes ikke godt til strukturerte prompter. Moderatoren trenger å påvirke det visuelle resultatet uten å skrive komplekse prompter.', 'AI-генеровані зображення іноді потребують креативного напрямку. "Зроби більш корпоративним" або "використай теплі кольори" погано перекладається в структуровані промпти. Модератор повинен впливати на візуальний результат без написання складних промптів.', 'cb_hub_${uuid} shows the 7 categories. cb_c_XX_${uuid} selects a category. cb_s_XX_N_${uuid} selects an option within it. cb_gen_${uuid} triggers generation with all selected elements. cb_rst_${uuid} resets all choices. Creative elements stored in creative_elements table (6 categories x 6 options). The final prompt combines selections with the article''s AI-extracted metadata.', 'cb_hub_${uuid} viser de 7 kategoriene. cb_c_XX_${uuid} velger en kategori. cb_s_XX_N_${uuid} velger et alternativ innenfor den. cb_gen_${uuid} utløser generering med alle valgte elementer. cb_rst_${uuid} tilbakestiller alle valg. Kreative elementer lagret i creative_elements-tabellen (6 kategorier x 6 alternativer). Den endelige prompten kombinerer valg med artikkelens AI-uttrukne metadata.', 'cb_hub_${uuid} показує 7 категорій. cb_c_XX_${uuid} обирає категорію. cb_s_XX_N_${uuid} обирає опцію всередині неї. cb_gen_${uuid} запускає генерацію з усіма обраними елементами. cb_rst_${uuid} скидає всі вибори. Креативні елементи зберігаються в таблиці creative_elements (6 категорій x 6 опцій). Фінальний промпт комбінує вибори з AI-витягнутими метаданими статті.', 'Non-technical content moderators can influence image generation through an intuitive tap-based interface. No prompt engineering knowledge needed. The constraint of 6x6 options prevents choice paralysis while covering the most common creative directions.', 'Ikke-tekniske innholdsmoderatorer kan påvirke bildegenerering gjennom et intuitivt trykkbasert grensesnitt. Ingen kunnskap om prompt engineering nødvendig. Begrensningen på 6x6 alternativer forhindrer valgparalyse mens de vanligste kreative retningene dekkes.', 'Нетехнічні модератори контенту можуть впливати на генерацію зображень через інтуїтивний інтерфейс на основі тапів. Не потрібні знання prompt engineering. Обмеження 6x6 опцій запобігає паралічу вибору, покриваючи найпоширеніші креативні напрямки.', '{"Telegram Bot API","Supabase","Azure OpenAI","Deno"}', '{"#CreativeBuilder","#TelegramBot","#ImageGeneration","#UX","#PromptEngineering"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p20', 'portfolio', 'bot_scraping', 'Auto-Publish Pipeline — the system that runs itself', 'Auto-publiseringspipeline — systemet som kjører seg selv', 'Пайплайн автопублікації — система, яка працює сама', 'Even with Telegram moderation, manual steps add up. Fully autonomous mode: AI generates images, rewrites in 3 languages, publishes to website, and posts to all social platforms automatically.', 'Selv med Telegram-moderering legger manuelle trinn seg opp. Fullstendig autonom modus: AI genererer bilder, omskriver på 3 språk, publiserer på nettstedet og poster på alle sosiale plattformer automatisk.', 'Навіть із Telegram-модерацією ручні кроки накопичуються. Повністю автономний режим: AI генерує зображення, переписує на 3 мовах, публікує на сайті та постить у всі соцмережі автоматично.', 'Even with Telegram moderation, the pipeline had manual steps: tap to generate image, tap to rewrite, tap to publish, tap to post socially. For high-volume periods (10+ articles), these taps add up.', 'Selv med Telegram-moderering hadde pipelinen manuelle trinn: trykk for å generere bilde, trykk for å omskrive, trykk for å publisere, trykk for å poste sosialt. For perioder med høyt volum (10+ artikler) legger disse trykkene seg opp.', 'Навіть із Telegram-модерацією пайплайн мав ручні кроки: тап для генерації зображення, тап для рерайту, тап для публікації, тап для постингу в соцмережі. При великих обсягах (10+ статей) ці тапи накопичуються.', 'auto-publish-news Edge Function orchestrates the entire pipeline. Telegram messages reduced to 4 in auto mode (from 8+ in manual). Per-source toggle: some sources get full auto, others stay manual. Auto-advance with configurable delays between steps. schedule-publisher manages timing windows and rate limiting.', 'auto-publish-news Edge Function orkestrerer hele pipelinen. Telegram-meldinger redusert til 4 i automodus (fra 8+ i manuell). Per-kilde-bryter: noen kilder får full auto, andre forblir manuelle. Auto-avansering med konfigurerbare forsinkelser mellom trinn. schedule-publisher styrer tidsvinduer og frekvensbegrensning.', 'auto-publish-news Edge Function оркеструє весь пайплайн. Telegram-повідомлення скорочені до 4 в автоматичному режимі (з 8+ у ручному). Перемикач по джерелу: деякі джерела отримують повний авто, інші залишаються ручними. Автопросування з налаштовуваними затримками між кроками. schedule-publisher керує часовими вікнами та rate limiting.', 'Publication latency dropped from 15 minutes (manual) to 2 minutes (auto). The moderator''s role shifted from "process every article" to "review exceptions." Output capacity: unlimited, constrained only by API rate limits.', 'Publiseringsforsinkelse falt fra 15 minutter (manuell) til 2 minutter (auto). Moderatorens rolle endret seg fra "behandle hver artikkel" til "gjennomgå unntak." Utgangskapasitet: ubegrenset, begrenset kun av API-frekvensbegrensninger.', 'Затримка публікації впала з 15 хвилин (ручна) до 2 хвилин (авто). Роль модератора змінилася з "обробляти кожну статтю" на "переглядати виключення." Потужність: необмежена, обмежена лише rate limits API.', '{"Supabase Edge Functions","Deno","Telegram Bot API","GitHub Actions"}', '{"#AutoPublish","#Automation","#ContentPipeline","#TelegramBot","#Serverless"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p21', 'portfolio', 'bot_scraping', 'MTKruto — downloading 2GB videos through Telegram''s back door', 'MTKruto — nedlasting av 2GB videoer gjennom Telegrams bakdør', 'MTKruto — завантаження 2GB відео через чорний хід Telegram', 'Telegram Bot API has a 20MB download limit. MTKruto uses MTProto protocol (same as official apps) to download files up to 2GB — no size restrictions.', 'Telegram Bot API har en nedlastingsgrense på 20MB. MTKruto bruker MTProto-protokollen (samme som offisielle apper) for å laste ned filer opptil 2GB — ingen størrelsesbegrensninger.', 'Telegram Bot API має ліміт завантаження 20MB. MTKruto використовує протокол MTProto (той самий, що в офіційних додатках) для завантаження файлів до 2GB — без обмежень розміру.', 'Telegram Bot API has a strict 20MB file download limit. News videos from Telegram channels are often 50-200MB. Some investigative reports are 500MB+. The Bot API simply can''t handle them.', 'Telegram Bot API har en streng grense på 20MB for filnedlasting. Nyhetsvideoer fra Telegram-kanaler er ofte 50-200MB. Noen undersøkende reportasjer er 500MB+. Bot API kan rett og slett ikke håndtere dem.', 'Telegram Bot API має суворий ліміт завантаження файлів у 20MB. Новинні відео з Telegram-каналів часто 50-200MB. Деякі розслідувальні репортажі — 500MB+. Bot API просто не може їх обробити.', 'MTKruto connects as a Telegram client (not a bot). Downloads happen via MTProto protocol, supporting files up to 2GB. The downloaded file is then uploaded to YouTube (unlisted) for web embedding, or directly to LinkedIn/Instagram/Facebook via their respective APIs. GitHub Actions handle the heavy lifting (Edge Functions have /tmp size limits: 256MB free, 512MB pro).', 'MTKruto kobler til som en Telegram-klient (ikke en bot). Nedlastinger skjer via MTProto-protokollen, og støtter filer opptil 2GB. Den nedlastede filen lastes deretter opp til YouTube (uoppført) for nettinnbygging, eller direkte til LinkedIn/Instagram/Facebook via deres respektive API-er. GitHub Actions håndterer det tunge arbeidet (Edge Functions har /tmp-størrelsesbegrensninger: 256MB gratis, 512MB pro).', 'MTKruto підключається як Telegram-клієнт (не бот). Завантаження відбувається через протокол MTProto, підтримуючи файли до 2GB. Завантажений файл потім завантажується на YouTube (unlisted) для вбудовування на сайт, або безпосередньо в LinkedIn/Instagram/Facebook через їхні API. GitHub Actions виконують важку роботу (Edge Functions мають обмеження /tmp: 256MB free, 512MB pro).', 'No more "video too large" failures. Even hour-long documentary clips get processed. The MTProto approach also gives access to channel metadata and message history that Bot API can''t reach.', 'Ingen flere "video for stor"-feil. Selv timevis lange dokumentarklipp blir behandlet. MTProto-tilnærmingen gir også tilgang til kanalmetadata og meldingshistorikk som Bot API ikke kan nå.', 'Більше жодних помилок "відео завелике". Навіть годинні документальні кліпи обробляються. Підхід MTProto також дає доступ до метаданих каналу та історії повідомлень, недоступних через Bot API.', '{"MTKruto","MTProto","GitHub Actions","YouTube API","Deno"}', '{"#MTKruto","#Telegram","#MTProto","#VideoProcessing","#Workaround"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p22', 'portfolio', 'bot_scraping', 'RSS-to-Telegram Bridge — 32 sources, one moderation queue', 'RSS-til-Telegram-bro — 32 kilder, én modereringskø', 'RSS-to-Telegram міст — 32 джерела, одна черга модерації', 'Content from 6 Telegram channels and 26 RSS feeds is normalized into one format and funneled through a single Telegram-based moderation queue.', 'Innhold fra 6 Telegram-kanaler og 26 RSS-feeder normaliseres til ett format og sendes gjennom én enkelt Telegram-basert modereringskø.', 'Контент із 6 Telegram-каналів та 26 RSS-стрічок нормалізується в один формат і проходить через єдину чергу модерації на базі Telegram.', 'Content comes from diverse sources: 6 Telegram channels, 26 RSS feeds. Each has different formats, update frequencies, and quality levels. The moderator needs a single, unified queue — not 32 separate inboxes.', 'Innhold kommer fra forskjellige kilder: 6 Telegram-kanaler, 26 RSS-feeder. Hver har forskjellige formater, oppdateringsfrekvenser og kvalitetsnivåer. Moderatoren trenger én enkelt, samlet kø — ikke 32 separate innbokser.', 'Контент приходить із різних джерел: 6 Telegram-каналів, 26 RSS-стрічок. Кожне має різні формати, частоту оновлень та рівні якості. Модератор потребує єдину уніфіковану чергу — а не 32 окремі інбокси.', 'realtime-scraper.yml runs every 10 minutes for Telegram channels (round-robin to avoid rate limits). rss-monitor-v2.yml runs every 30 minutes for RSS feeds (batched: 8 sources per batch, 4 batches). Both routes funnel articles through pre-moderate-news (AI filtering), then into the Telegram bot queue. The news_sources table tracks each source''s type, fetch interval, and last fetch time.', 'realtime-scraper.yml kjører hvert 10. minutt for Telegram-kanaler (round-robin for å unngå frekvensbegrensninger). rss-monitor-v2.yml kjører hvert 30. minutt for RSS-feeder (batched: 8 kilder per batch, 4 batcher). Begge ruter sender artikler gjennom pre-moderate-news (AI-filtrering), deretter inn i Telegram-botkøen. news_sources-tabellen sporer hver kildes type, henteintervall og siste hentetidspunkt.', 'realtime-scraper.yml запускається кожні 10 хвилин для Telegram-каналів (round-robin для уникнення rate limits). rss-monitor-v2.yml запускається кожні 30 хвилин для RSS-стрічок (пакетно: 8 джерел на пакет, 4 пакети). Обидва маршрути проводять статті через pre-moderate-news (AI-фільтрація), потім у чергу Telegram-бота. Таблиця news_sources відстежує тип кожного джерела, інтервал отримання та час останнього отримання.', '32 sources, 1 moderation queue, 1 workflow. The round-robin approach prevents hitting Telegram''s rate limits. Batch processing for RSS keeps GitHub Actions runtime under 10 minutes. Source management is fully configurable from the admin panel.', '32 kilder, 1 modereringskø, 1 arbeidsflyt. Round-robin-tilnærmingen forhindrer treff på Telegrams frekvensbegrensninger. Batchbehandling for RSS holder GitHub Actions-kjøretid under 10 minutter. Kildestyring er fullt konfigurerbar fra adminpanelet.', '32 джерела, 1 черга модерації, 1 воркфлоу. Підхід round-robin запобігає потраплянню на rate limits Telegram. Пакетна обробка RSS тримає час виконання GitHub Actions під 10 хвилин. Керування джерелами повністю налаштовується з адмінки.', '{"GitHub Actions","Supabase Edge Functions","Telegram Bot API","RSS","Deno"}', '{"#RSS","#TelegramBot","#ContentScraping","#Automation","#RoundRobin"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p23', 'portfolio', 'media_production', '43 Edge Functions — a serverless backend that scales to zero', '43 Edge Functions — en serverløs backend som skalerer til null', '43 Edge Functions — серверлес бекенд, що масштабується до нуля', 'Traditional backend servers cost money 24/7. 43 Deno Edge Functions on Supabase scale to zero when idle and deploy independently in ~10 seconds each.', 'Tradisjonelle backend-servere koster penger 24/7. 43 Deno Edge Functions på Supabase skalerer til null ved inaktivitet og deployes uavhengig på ~10 sekunder hver.', 'Традиційні бекенд-сервери коштують грошей 24/7. 43 Deno Edge Functions на Supabase масштабуються до нуля при простої та деплояться незалежно за ~10 секунд кожна.', 'Traditional backend servers cost money 24/7 whether you use them or not. For a portfolio/news site with variable traffic, paying for always-on infrastructure is wasteful. But the backend logic is complex: 43 distinct operations from scraping to AI processing to social posting.', 'Tradisjonelle backend-servere koster penger 24/7 uansett om du bruker dem eller ikke. For en portefølje-/nyhetsside med variabel trafikk er det sløsing å betale for alltid-på infrastruktur. Men backend-logikken er kompleks: 43 distinkte operasjoner fra skraping til AI-behandling til sosial posting.', 'Традиційні бекенд-сервери коштують грошей 24/7, незалежно від використання. Для портфоліо/новинного сайту зі змінним трафіком платити за постійно ввімкнену інфраструктуру — марнотратство. Але бекенд-логіка складна: 43 окремі операції від скрейпінгу до AI-обробки до постингу в соцмережі.', '43 functions in supabase/functions/, each with its own index.ts. Shared helpers in _shared/ (10 files: YouTube, GitHub Actions, Facebook, social media, slugs, duplicates, Telegram formatting, etc.). Deploy: supabase functions deploy <name> --no-verify-jwt. Each function has version logging for deployment verification.', '43 funksjoner i supabase/functions/, hver med sin egen index.ts. Delte hjelpere i _shared/ (10 filer: YouTube, GitHub Actions, Facebook, sosiale medier, slugs, duplikater, Telegram-formatering osv.). Deploy: supabase functions deploy <name> --no-verify-jwt. Hver funksjon har versjonslogging for deployverifisering.', '43 функції в supabase/functions/, кожна зі своїм index.ts. Спільні хелпери в _shared/ (10 файлів: YouTube, GitHub Actions, Facebook, соцмережі, slugs, дублікати, Telegram-форматування тощо). Деплой: supabase functions deploy <name> --no-verify-jwt. Кожна функція має логування версій для верифікації деплою.', 'Backend cost: $0/month on Supabase free tier (upgrading to pro only for /tmp storage on video processing). Cold start: <500ms. Deployment: individual function redeploy in ~10 seconds. The serverless approach means I never pay for idle time — which is 95% of the day.', 'Backend-kostnad: $0/mnd på Supabase gratis-nivå (oppgradering til pro kun for /tmp-lagring ved videobehandling). Kaldstart: <500ms. Deployment: individuell funksjonsredeploy på ~10 sekunder. Den serverløse tilnærmingen betyr at jeg aldri betaler for inaktiv tid — som utgjør 95% av dagen.', 'Вартість бекенду: $0/місяць на безкоштовному плані Supabase (апгрейд до pro лише для /tmp сховища при обробці відео). Холодний старт: <500ms. Деплой: перезапуск окремої функції за ~10 секунд. Серверлес підхід означає, що я ніколи не плачу за простій — а це 95% дня.', '{"Supabase Edge Functions","Deno","PostgreSQL","TypeScript"}', '{"#Serverless","#EdgeFunctions","#Supabase","#Deno","#ZeroCost"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p24', 'portfolio', 'media_production', 'Cascading Image Providers — when Plan A fails, there''s always Plan E', 'Kaskaderende bildeleverandører — når Plan A feiler, finnes alltid Plan E', 'Каскадні провайдери зображень — коли План A зазнає невдачі, завжди є План E', 'AI image generation is unreliable with a single provider. Cascading fallback chain (Grok -> Gemini) with per-provider analytics brought success rate from ~75% to 98%+.', 'AI-bildegenerering er upålitelig med én enkelt leverandør. Kaskaderende fallback-kjede (Grok -> Gemini) med analyse per leverandør økte suksessraten fra ~75% til 98%+.', 'AI-генерація зображень ненадійна з одним провайдером. Каскадний ланцюг фолбеку (Grok -> Gemini) з аналітикою по провайдерах підняв успішність з ~75% до 98%+.', 'AI image generation is unreliable. Grok has rate limits. Gemini sometimes returns inappropriate content. Together AI has quality inconsistencies. Depending on a single provider means accepting their failure rate.', 'AI-bildegenerering er upålitelig. Grok har frekvensbegrensninger. Gemini returnerer noen ganger upassende innhold. Together AI har kvalitetsinkonsistens. Å avhenge av én enkelt leverandør betyr å akseptere deres feilrate.', 'AI-генерація зображень ненадійна. Grok має rate limits. Gemini іноді повертає неприйнятний контент. Together AI має непослідовність якості. Залежність від одного провайдера означає прийняття їхнього відсотка збоїв.', 'Cascading order: Grok (XAI) -> Gemini (Google). Previous extended chain also included: Cloudflare FLUX -> Together AI -> Pollinations -> HuggingFace. Each provider has a 40-second timeout. image_provider_usage table tracks success/failure rates per provider per day. The admin panel shows provider statistics and allows reordering.', 'Kaskaderende rekkefølge: Grok (XAI) -> Gemini (Google). Tidligere utvidet kjede inkluderte også: Cloudflare FLUX -> Together AI -> Pollinations -> HuggingFace. Hver leverandør har 40 sekunders tidsavbrudd. image_provider_usage-tabellen sporer suksess-/feilrater per leverandør per dag. Adminpanelet viser leverandørstatistikk og tillater omorganisering.', 'Каскадний порядок: Grok (XAI) -> Gemini (Google). Попередній розширений ланцюг також включав: Cloudflare FLUX -> Together AI -> Pollinations -> HuggingFace. Кожен провайдер має тайм-аут 40 секунд. Таблиця image_provider_usage відстежує показники успіху/невдач по провайдерах за день. Адмінка показує статистику провайдерів та дозволяє змінювати порядок.', 'Image generation success rate: 98%+ (up from ~75% with a single provider). Provider selection is data-driven — the admin panel shows which providers are performing best, enabling informed decisions about the cascade order.', 'Suksessrate for bildegenerering: 98%+ (opp fra ~75% med én leverandør). Leverandørvalg er datadrevet — adminpanelet viser hvilke leverandører som presterer best, noe som muliggjør informerte beslutninger om kaskaderekkefølgen.', 'Успішність генерації зображень: 98%+ (з ~75% при одному провайдері). Вибір провайдерів — data-driven: адмінка показує, які провайдери працюють найкраще, дозволяючи приймати інформовані рішення щодо порядку каскаду.', '{"Grok","Google Gemini","Cloudflare AI","Together AI","HuggingFace","Supabase"}', '{"#CascadingFallback","#ImageGeneration","#AI","#Resilience","#MultiProvider"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p25', 'portfolio', 'media_production', 'Scheduled Publishing — the art of not flooding your audience', 'Planlagt publisering — kunsten å ikke oversvømme publikummet ditt', 'Планована публікація — мистецтво не заливати свою аудиторію', 'Auto-publishing 10 articles at once floods followers. A scheduling engine with configurable windows, rate limiting, and content weight classification ensures optimal posting rhythm.', 'Å autopublisere 10 artikler på én gang oversvømmer følgere. En planleggingsmotor med konfigurerbare vinduer, frekvensbegrensning og innholdsvektklassifisering sikrer optimal publiseringsrytme.', 'Автопублікація 10 статей одночасно заливає підписників. Планувальник із налаштовуваними вікнами, rate limiting та класифікацією ваги контенту забезпечує оптимальний ритм постингу.', 'Auto-publishing 10 articles at once creates a wall of content that followers can''t digest. Social media algorithms penalize rapid-fire posting. But holding articles for manual scheduling defeats the purpose of automation.', 'Å autopublisere 10 artikler på én gang skaper en vegg av innhold som følgere ikke kan fordøye. Sosiale medier-algoritmer straffer hurtigpublisering. Men å holde tilbake artikler for manuell planlegging motvirker formålet med automatisering.', 'Автопублікація 10 статей одночасно створює стіну контенту, який підписники не можуть перетравити. Алгоритми соцмереж карають за швидкострільний постинг. Але затримання статей для ручного планування зводить нанівець мету автоматизації.', 'schedule-publisher runs every 5 minutes via GitHub Actions. It checks for queued content, respects minimum 1-minute gaps between posts, and classifies content weight. Publishing windows prevent late-night posts. Sequential publish queue ensures LinkedIn, Instagram, and Facebook get their posts with proper spacing.', 'schedule-publisher kjører hvert 5. minutt via GitHub Actions. Den sjekker for innhold i kø, respekterer minimum 1 minutts mellomrom mellom innlegg, og klassifiserer innholdsvekt. Publiseringsvinduer forhindrer innlegg sent på natten. Sekvensiell publiseringskø sikrer at LinkedIn, Instagram og Facebook får sine innlegg med riktig mellomrom.', 'schedule-publisher запускається кожні 5 хвилин через GitHub Actions. Перевіряє вміст у черзі, дотримується мінімальних 1-хвилинних інтервалів між постами та класифікує вагу контенту. Вікна публікації запобігають нічним постам. Послідовна черга публікацій забезпечує LinkedIn, Instagram та Facebook правильні інтервали між постами.', 'Consistent posting rhythm without manual intervention. Followers see content at digestible intervals. Algorithm-friendly posting patterns. The weight classification ensures breaking news doesn''t wait behind a listicle.', 'Konsistent publiseringsrytme uten manuell intervensjon. Følgere ser innhold med fordøyelige mellomrom. Algoritmevennlige publiseringsmønstre. Vektklassifiseringen sikrer at siste nytt ikke venter bak en listicle.', 'Стабільний ритм публікацій без ручного втручання. Підписники бачать контент через зручні інтервали. Алгоритмо-дружні патерни постингу. Класифікація ваги забезпечує, що breaking news не чекає за лістиклом.', '{"GitHub Actions","Supabase Edge Functions","Deno"}', '{"#Scheduling","#ContentManagement","#Automation","#SocialMedia","#Algorithm"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p26', 'portfolio', 'media_production', '3-Tier Spam Protection — because contact forms attract bots like honey', '3-lags spambeskyttelse — fordi kontaktskjemaer tiltrekker boter som honning', '3-рівневий захист від спаму — бо контактні форми притягують ботів як мед', 'Contact form received 50+ spam submissions per day. Three invisible layers (honeypot, timestamp check, IP rate limiting) eliminated spam without CAPTCHA friction for real users.', 'Kontaktskjemaet mottok 50+ spam-innsendinger daglig. Tre usynlige lag (honeypot, tidsstempelsjekk, IP-frekvensbegrensning) eliminerte spam uten CAPTCHA-friksjon for ekte brukere.', 'Контактна форма отримувала 50+ спам-заявок на день. Три невидимі шари (honeypot, перевірка таймстемпу, rate limiting за IP) усунули спам без CAPTCHA-тертя для реальних користувачів.', 'The contact form on vitalii.no received 50+ spam submissions per day within the first week. Classic spam: SEO offers, casino links, crypto scams. CAPTCHA adds friction for real users.', 'Kontaktskjemaet på vitalii.no mottok 50+ spam-innsendinger per dag i løpet av den første uken. Klassisk spam: SEO-tilbud, kasinolenker, kryptosvindel. CAPTCHA legger til friksjon for ekte brukere.', 'Контактна форма на vitalii.no отримувала 50+ спам-заявок на день протягом першого тижня. Класичний спам: SEO-пропозиції, казино-посилання, крипто-скам. CAPTCHA додає тертя для реальних користувачів.', 'send-contact-email Edge Function checks all three layers before processing. Honeypot: a hidden field named something attractive to bots. If filled = rejected. Timestamp: form render time is stored, submission time is compared. <3 seconds between render and submit = rejected. Rate limit: IP tracked in-memory with 10-minute window.', 'send-contact-email Edge Function sjekker alle tre lag før behandling. Honeypot: et skjult felt med et botvennlig navn. Hvis utfylt = avvist. Tidsstempel: skjemaets rendretid lagres, innsendingstid sammenlignes. <3 sekunder mellom render og innsending = avvist. Frekvensbegrensning: IP sporet i minnet med 10-minutters vindu.', 'send-contact-email Edge Function перевіряє всі три шари перед обробкою. Honeypot: приховане поле з привабливою для ботів назвою. Якщо заповнене = відхилено. Таймстемп: час рендеру форми зберігається, час відправки порівнюється. <3 секунди між рендером і відправкою = відхилено. Rate limit: IP відстежується в пам''яті з 10-хвилинним вікном.', 'Spam dropped from 50+/day to 0-1/day. Zero false positives reported. Real users never see a CAPTCHA. The three layers catch different bot types: simple scrapers (honeypot), form-filling tools (timestamp), and persistent attackers (rate limit).', 'Spam falt fra 50+/dag til 0-1/dag. Null falske positiver rapportert. Ekte brukere ser aldri en CAPTCHA. De tre lagene fanger forskjellige bottyper: enkle skrapere (honeypot), skjemautfyllingsverktøy (tidsstempel) og vedvarende angripere (frekvensbegrensning).', 'Спам впав з 50+/день до 0-1/день. Нуль хибних спрацювань. Реальні користувачі ніколи не бачать CAPTCHA. Три шари ловлять різні типи ботів: прості скрейпери (honeypot), інструменти заповнення форм (таймстемп) та наполегливих атакуючих (rate limit).', '{"Supabase Edge Functions","Deno","Resend API"}', '{"#SpamProtection","#Security","#Honeypot","#RateLimiting","#ContactForm"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p27', 'portfolio', 'frontend_ux', 'BentoGrid Layout — six windows into one portfolio', 'BentoGrid-oppsett — seks vinduer inn i én portefølje', 'BentoGrid-макет — шість вікон в одне портфоліо', 'Traditional portfolios are linear scrolls. A 6-section interactive grid where every section is a portal with unique color pairs, animations, and hover interactions.', 'Tradisjonelle porteføljer er lineære skroller. Et 6-seksjoners interaktivt rutenett der hver seksjon er en portal med unike fargepar, animasjoner og hover-interaksjoner.', 'Традиційні портфоліо — це лінійні скроли. 6-секційна інтерактивна сітка, де кожна секція — портал з унікальними парами кольорів, анімаціями та hover-інтеракціями.', 'Traditional portfolio websites are linear scrolls. Visitors see sections in the developer''s order, not their own order of interest. A recruiter wants to see projects first. A designer wants to see skills. A potential client wants services.', 'Tradisjonelle porteføljesider er lineære skroller. Besøkende ser seksjoner i utviklerens rekkefølge, ikke sin egen interesserekkefølge. En rekrutterer vil se prosjekter først. En designer vil se ferdigheter. En potensiell kunde vil se tjenester.', 'Традиційні портфоліо-сайти — це лінійні скроли. Відвідувачі бачать секції в порядку розробника, а не в порядку власних інтересів. Рекрутер хоче бачити проєкти першими. Дизайнер хоче бачити навички. Потенційний клієнт хоче бачити послуги.', '6 sections (About, Services, Projects, Skills, News, Blog) in a CSS Grid. Each section has a unique color pair: background (40% opacity, 700ms transition) and hero text contrast. Hover triggers: HeroTextAnimation with liquid wave fill effect, section-specific child animations. 3+ second hover on Projects triggers an explosion grid. Touch-friendly on mobile via BentoGridMobile with bottom navigation.', '6 seksjoner (About, Services, Projects, Skills, News, Blog) i et CSS Grid. Hver seksjon har et unikt fargepar: bakgrunn (40% opasitet, 700ms overgang) og heltetekstkontrast. Hover utløser: HeroTextAnimation med flytende bølgefylleffekt, seksjonsspesifikke barneanimasjoner. 3+ sekunders hover på Projects utløser et eksplosjonsgitter. Berøringsvennlig på mobil via BentoGridMobile med bunnnavigasjon.', '6 секцій (About, Services, Projects, Skills, News, Blog) у CSS Grid. Кожна секція має унікальну пару кольорів: фон (40% непрозорості, 700ms перехід) і контраст тексту hero. Hover запускає: HeroTextAnimation з ефектом рідкого хвильового заповнення, секційно-специфічні дочірні анімації. 3+ секунди hover на Projects запускає сітку вибуху. Touch-friendly на мобільному через BentoGridMobile з нижньою навігацією.', 'Average session duration is significantly higher than typical portfolio sites. The non-linear exploration keeps visitors engaged. The color system creates visual identity — each section has its own personality while maintaining cohesion.', 'Gjennomsnittlig sesjonsvarighet er betydelig høyere enn typiske porteføljesider. Den ikke-lineære utforskningen holder besøkende engasjerte. Fargesystemet skaper visuell identitet — hver seksjon har sin egen personlighet mens sammenhengen opprettholdes.', 'Середня тривалість сесії значно вища, ніж у типових портфоліо-сайтів. Нелінійне дослідження тримає відвідувачів залученими. Кольорова система створює візуальну ідентичність — кожна секція має власну особистість, зберігаючи цілісність.', '{"Next.js","React","CSS Grid","GSAP","Framer Motion"}', '{"#BentoGrid","#Portfolio","#CSS","#Animation","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p28', 'portfolio', 'frontend_ux', 'Liquid Fill Animation — text that flows like water', 'Flytende fyllanimasjon — tekst som flyter som vann', 'Анімація рідкого заповнення — текст, що тече як вода', 'Standard text animations are everywhere. A wave animation fills text like a glass of water, using SVG polygon clip-path with sinusoidal wave for an organic, fluid feel.', 'Standard tekstanimasjoner er overalt. En bølgeanimasjon fyller tekst som et glass vann, med SVG polygon clip-path med sinusbølge for en organisk, flytende følelse.', 'Стандартні текстові анімації всюди. Хвильова анімація заповнює текст як склянку води, використовуючи SVG polygon clip-path з синусоїдальною хвилею для органічного, плавного відчуття.', 'Standard text animations (fade in, slide up) are everywhere. They don''t create memorable first impressions. The hero text needs to feel alive, not just appear.', 'Standard tekstanimasjoner (fade in, slide up) er overalt. De skaper ikke minneverdige førsteinntrykk. Helteteksten må føles levende, ikke bare dukke opp.', 'Стандартні текстові анімації (fade in, slide up) всюди. Вони не створюють пам''ятних перших вражень. Текст hero повинен відчуватися живим, а не просто з''являтися.', 'SVG polygon clip-path with dynamically calculated sinusoidal wave. requestAnimationFrame drives smooth 60fps animation. The wave offset creates the illusion of liquid surface. Fill speed: 8% per frame with easing. Glass baseline: transparent text with 0.5px stroke. Once filled: solid color with 400ms transition. Debounced: 150ms for subtitle (RTL), 300ms for description (LTR).', 'SVG polygon clip-path med dynamisk beregnet sinusbølge. requestAnimationFrame driver jevn 60fps-animasjon. Bølgeforskyvningen skaper illusjonen av en flytende overflate. Fyllhastighet: 8% per bilde med easing. Glass baseline: gjennomsiktig tekst med 0.5px strek. Når fylt: solid farge med 400ms overgang. Debounced: 150ms for undertittel (RTL), 300ms for beskrivelse (LTR).', 'SVG polygon clip-path із динамічно обчислюваною синусоїдальною хвилею. requestAnimationFrame забезпечує плавну анімацію 60fps. Зміщення хвилі створює ілюзію рідкої поверхні. Швидкість заповнення: 8% на кадр з easing. Glass baseline: прозорий текст з 0.5px обводкою. Після заповнення: суцільний колір з 400ms переходом. Debounced: 150ms для підзаголовка (RTL), 300ms для опису (LTR).', 'Every first-time visitor notices it. The animation is subtle enough for professional context but distinctive enough to be memorable. The debounced timing means it responds to hover without flickering during quick mouse movements.', 'Hver førstegangsbesøkende legger merke til det. Animasjonen er subtil nok for profesjonell kontekst, men distinkt nok til å være minneverdig. Den debouncede timingen betyr at den reagerer på hover uten flimring under raske musebevegelser.', 'Кожен відвідувач, який бачить це вперше, помічає. Анімація достатньо тонка для професійного контексту, але достатньо виразна, щоб запам''ятатися. Debounced тайминг означає, що вона реагує на hover без мерехтіння при швидких рухах миші.', '{"SVG","CSS","requestAnimationFrame","TypeScript"}', '{"#Animation","#SVG","#LiquidFill","#CSS","#FrontendMagic"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p29', 'portfolio', 'frontend_ux', 'Projects Explosion Grid — hover for 3 seconds and everything changes', 'Prosjekter-eksplosjonsgitter — hold musepekeren i 3 sekunder og alt endres', 'Сітка вибуху проєктів — наведи на 3 секунди і все зміниться', 'A project carousel shows one project at a time. After 3-second hover, the section explodes into a grid showing all projects simultaneously with staggered GSAP animations.', 'En prosjektkarusell viser ett prosjekt om gangen. Etter 3 sekunders hover eksploderer seksjonen inn i et rutenett som viser alle prosjekter samtidig med forskjøvede GSAP-animasjoner.', 'Карусель проєктів показує один проєкт за раз. Після 3-секундного hover секція вибухає в сітку, показуючи всі проєкти одночасно з поетапними GSAP-анімаціями.', 'A project carousel shows one project at a time. Visitors have to click through to discover all projects. Most won''t click more than 2-3 times. The full portfolio remains hidden.', 'En prosjektkarusell viser ett prosjekt om gangen. Besøkende må klikke seg gjennom for å oppdage alle prosjekter. De fleste klikker ikke mer enn 2-3 ganger. Hele porteføljen forblir skjult.', 'Карусель проєктів показує один проєкт за раз. Відвідувачам потрібно перегортати, щоб знайти всі проєкти. Більшість не кликнуть більше 2-3 разів. Повне портфоліо залишається прихованим.', '3-second hover threshold tracked with timer. When triggered: GSAP timeline animates cards from center outward. Grid sizes adapt: 2x2 for 4 projects, 3x3 for 9, up to 4x4. Each card staggers by index * 0.05 seconds with backOut easing (slight bounce). Neon gradient backgrounds per card (5 color schemes). Progress bar shows carousel position before explosion.', '3 sekunders hover-terskel sporet med timer. Når utløst: GSAP-tidslinje animerer kort fra midten og utover. Gitterstørrelser tilpasses: 2x2 for 4 prosjekter, 3x3 for 9, opptil 4x4. Hvert kort forskyves med index * 0.05 sekunder med backOut easing (lett sprett). Neon-gradientbakgrunner per kort (5 fargetemaer). Fremdriftslinje viser karusellposisjon før eksplosjon.', '3-секундний поріг hover відстежується таймером. Коли спрацьовує: GSAP timeline анімує карточки від центру назовні. Розміри сітки адаптуються: 2x2 для 4 проєктів, 3x3 для 9, до 4x4. Кожна карточка з''являється з затримкою index * 0.05 секунд з easing backOut (легкий стрибок). Неонові градієнтні фони для кожної карточки (5 кольорових схем). Прогрес-бар показує позицію каруселі перед вибухом.', 'Visitors who discover the explosion effect spend more time exploring projects. The 3-second threshold prevents accidental triggers while rewarding genuine interest. The bounce easing gives a playful, premium feel.', 'Besøkende som oppdager eksplosjonseffekten bruker mer tid på å utforske prosjekter. 3-sekunders terskelen forhindrer utilsiktede utløsninger mens den belønner genuin interesse. Sprett-easingen gir en leken, premium følelse.', 'Відвідувачі, які відкривають ефект вибуху, проводять більше часу за дослідженням проєктів. 3-секундний поріг запобігає випадковим спрацюванням, нагороджуючи справжній інтерес. Easing зі стрибком дає грайливе, преміум-відчуття.', '{"GSAP","React","CSS Grid","TypeScript"}', '{"#GSAP","#Animation","#InteractiveUI","#Portfolio","#HoverEffect"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p30', 'portfolio', 'frontend_ux', 'Three.js Particle Background — 200 particles, zero performance cost', 'Three.js partikkelbakgrunn — 200 partikler, null ytelseskostnad', 'Three.js частинковий фон — 200 частинок, нуль витрат на продуктивність', 'Animated backgrounds often kill mobile performance. 200 particles with aggressive optimization (capped pixel ratio, low-power GPU, mouse tracking) maintain 60fps even on old phones.', 'Animerte bakgrunner dreper ofte mobilytelse. 200 partikler med aggressiv optimalisering (begrenset pikselforhold, laveffekts GPU, musesporing) opprettholder 60fps selv på gamle telefoner.', 'Анімовані фони часто вбивають продуктивність на мобільних. 200 частинок з агресивною оптимізацією (обмежений pixel ratio, low-power GPU, відстеження миші) тримають 60fps навіть на старих телефонах.', 'Static backgrounds feel dead. But animated backgrounds often kill performance — especially on mobile. Previous attempts with full particle systems (1000+ particles) caused frame drops on mid-range phones.', 'Statiske bakgrunner føles døde. Men animerte bakgrunner dreper ofte ytelsen — spesielt på mobil. Tidligere forsøk med fulle partikkelsystemer (1000+ partikler) forårsaket bildetap på mellomklassetelefoner.', 'Статичні фони відчуваються мертвими. Але анімовані фони часто вбивають продуктивність — особливо на мобільних. Попередні спроби з повними системами частинок (1000+ частинок) викликали просідання кадрів на бюджетних телефонах.', 'Three.js with powerPreference: ''low-power'', antialias: true, alpha: true. 200 particles (tested as the sweet spot between visual density and performance). devicePixelRatio capped at Math.min(window.devicePixelRatio, 1.5). Mouse position tracked for interactive parallax effect. prefers-reduced-motion media query disables the effect entirely for accessibility.', 'Three.js med powerPreference: ''low-power'', antialias: true, alpha: true. 200 partikler (testet som det optimale punktet mellom visuell tetthet og ytelse). devicePixelRatio begrenset til Math.min(window.devicePixelRatio, 1.5). Museposisjon sporet for interaktiv parallakseeffekt. prefers-reduced-motion medieforespørsel deaktiverer effekten helt for tilgjengelighet.', 'Three.js з powerPreference: ''low-power'', antialias: true, alpha: true. 200 частинок (протестовано як оптимальний баланс між візуальною щільністю та продуктивністю). devicePixelRatio обмежений до Math.min(window.devicePixelRatio, 1.5). Позиція миші відстежується для інтерактивного паралакс-ефекту. Медіа-запит prefers-reduced-motion повністю вимикає ефект для доступності.', 'Consistent 60fps on all tested devices (including 5-year-old Android phones). The 200-particle count creates enough visual texture without computational waste. Mouse interaction adds a "living" quality that visitors notice subconsciously.', 'Konsistent 60fps på alle testede enheter (inkludert 5 år gamle Android-telefoner). 200-partikkeltallet skaper nok visuell tekstur uten beregningssløsing. Museinteraksjon legger til en "levende" kvalitet som besøkende legger merke til ubevisst.', 'Стабільні 60fps на всіх протестованих пристроях (включаючи 5-річні Android-телефони). 200 частинок створюють достатню візуальну текстуру без обчислювального марнотратства. Інтеракція з мишею додає "живу" якість, яку відвідувачі помічають підсвідомо.', '{"Three.js","WebGL","React","TypeScript"}', '{"#ThreeJS","#WebGL","#Particles","#Performance","#Accessibility"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p31', 'portfolio', 'frontend_ux', 'Mobile App-Style Layout — a website that feels like an app', 'Mobilapp-stil oppsett — en nettside som føles som en app', 'Мобільний макет у стилі додатку — сайт, що відчувається як додаток', 'Mobile portfolios typically shrink the desktop layout. A completely different React component with bottom navigation, swipe gestures, and safe area insets creates a native app feel.', 'Mobile porteføljer krymper vanligvis desktop-oppsettet. En helt annen React-komponent med bunnnavigasjon, sveipebevegelser og safe area-innsnitt skaper en nativ app-følelse.', 'Мобільні портфоліо зазвичай стискають десктопний макет. Повністю інший React-компонент із нижньою навігацією, жестами свайпу та safe area insets створює відчуття нативного додатку.', 'Mobile portfolio websites typically shrink the desktop layout. This creates tiny text, cramped sections, and frustrating navigation. The BentoGrid approach doesn''t work on a 375px screen.', 'Mobile porteføljesider krymper vanligvis desktop-oppsettet. Dette skaper liten tekst, trange seksjoner og frustrerende navigasjon. BentoGrid-tilnærmingen fungerer ikke på en 375px-skjerm.', 'Мобільні портфоліо-сайти зазвичай стискають десктопний макет. Це створює крихітний текст, стиснуті секції та фрустроваційну навігацію. Підхід BentoGrid не працює на 375px екрані.', 'BentoGridMobile component with 7 screens: Home (typewriter), About (word explosion), Services (rotating icons), Projects (swipe carousel, 50px threshold), Skills (category filter + grid), News (horizontal scroll), Blog (horizontal scroll). Glassmorphism bottom nav: backdrop-filter: blur(10px), semi-transparent. env(safe-area-inset-bottom) for iPhone notch. useIsMobile() hook (SSR-safe: initial false, update on mount).', 'BentoGridMobile-komponent med 7 skjermer: Home (skrivemaskin), About (ordeksplosjon), Services (roterende ikoner), Projects (sveipekarusell, 50px terskel), Skills (kategorifilter + rutenett), News (horisontal skrolling), Blog (horisontal skrolling). Glassmorfisme bunnnavigasjon: backdrop-filter: blur(10px), halvgjennomsiktig. env(safe-area-inset-bottom) for iPhone-hakk. useIsMobile() hook (SSR-trygt: initialt false, oppdaterer ved montering).', 'Компонент BentoGridMobile із 7 екранами: Home (друкарська машинка), About (вибух слів), Services (обертові іконки), Projects (свайп-карусель, поріг 50px), Skills (фільтр категорій + сітка), News (горизонтальний скрол), Blog (горизонтальний скрол). Glassmorphism нижня навігація: backdrop-filter: blur(10px), напівпрозора. env(safe-area-inset-bottom) для виїмки iPhone. Хук useIsMobile() (SSR-безпечний: початково false, оновлюється при монтуванні).', 'Mobile experience feels native, not adapted. Swipe gestures feel natural. Bottom navigation provides instant access to any section. Safe area handling means no content hidden behind notches or home indicators.', 'Mobilopplevelsen føles nativ, ikke tilpasset. Sveipebevegelser føles naturlige. Bunnnavigasjon gir umiddelbar tilgang til enhver seksjon. Safe area-håndtering betyr at ingen innhold skjules bak hakk eller hjemindikatorer.', 'Мобільний досвід відчувається нативним, а не адаптованим. Жести свайпу відчуваються природно. Нижня навігація забезпечує миттєвий доступ до будь-якої секції. Обробка safe area означає, що контент не ховається за виїмками чи home-індикаторами.', '{"React","Next.js","Framer Motion","Tailwind CSS","TypeScript"}', '{"#MobileFirst","#PWA","#Glassmorphism","#SwipeGestures","#ResponsiveDesign"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p32', 'portfolio', 'frontend_ux', 'Next.js Parallel Routes Modal — seamless article browsing', 'Next.js parallellruter modal — sømløs artikkelbla', 'Модалка на паралельних маршрутах Next.js — безшовний перегляд статей', 'Clicking a news article should show it without leaving the homepage, but the article also needs its own URL for SEO. Next.js parallel routes solve both with one component.', 'Å klikke på en nyhetsartikkel bør vise den uten å forlate hjemmesiden, men artikkelen trenger også sin egen URL for SEO. Next.js parallellruter løser begge med én komponent.', 'Клік на новину повинен показувати її без покидання головної, але стаття також потребує власний URL для SEO. Паралельні маршрути Next.js вирішують обидві задачі одним компонентом.', 'Clicking a news article on the homepage should show the article without leaving the page. But the article also needs its own URL for sharing and SEO. These are conflicting requirements: modal behavior (stay on page) vs page behavior (own URL).', 'Å klikke på en nyhetsartikkel på hjemmesiden bør vise artikkelen uten å forlate siden. Men artikkelen trenger også sin egen URL for deling og SEO. Dette er motstridende krav: modalatferd (bli på siden) vs sideatferd (egen URL).', 'Клік на новину на головній повинен показувати статтю без покидання сторінки. Але стаття також потребує власний URL для шерингу та SEO. Це суперечливі вимоги: поведінка модалки (залишатися на сторінці) проти поведінки сторінки (власний URL).', 'app/@modal/(.)news/[slug]/page.tsx intercepts the route with (.) prefix. When the homepage is the previous route, the article renders as an overlay modal with dark backdrop, close button, and scroll prevention. When navigated directly (pasted URL, search engine), the regular app/news/[slug]/page.tsx renders a full page. The article component is shared between both.', 'app/@modal/(.)news/[slug]/page.tsx fanger ruten med (.)-prefiks. Når hjemmesiden er den forrige ruten, rendres artikkelen som en overleggsmodal med mørk bakgrunn, lukkeknapp og skrollforebygging. Ved direkte navigasjon (limt URL, søkemotor) rendres vanlig app/news/[slug]/page.tsx som full side. Artikkelkomponenten deles mellom begge.', 'app/@modal/(.)news/[slug]/page.tsx перехоплює маршрут з префіксом (.). Коли головна — попередній маршрут, стаття рендериться як оверлей-модалка з темним фоном, кнопкою закриття та блокуванням скролу. При прямій навігації (вставлений URL, пошуковик) звичайний app/news/[slug]/page.tsx рендериться як повна сторінка. Компонент статті спільний для обох.', 'Visitors browse articles without losing their place on the homepage. Shared URLs work as full pages. SEO crawlers see full pages with proper metadata. The best of both worlds — no JavaScript routing hacks, just framework-native behavior.', 'Besøkende blar gjennom artikler uten å miste sin posisjon på hjemmesiden. Delte URL-er fungerer som fulle sider. SEO-crawlere ser fulle sider med riktig metadata. Det beste fra begge verdener — ingen JavaScript-rutinghacks, bare rammeverknativ atferd.', 'Відвідувачі переглядають статті без втрати місця на головній. Зашарені URL працюють як повні сторінки. SEO-краулери бачать повні сторінки з правильними метаданими. Найкраще з обох світів — жодних JavaScript хаків маршрутизації, лише нативна поведінка фреймворку.', '{"Next.js 15","React","App Router","TypeScript"}', '{"#NextJS","#ParallelRoutes","#Modal","#SEO","#AppRouter"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p33', 'portfolio', 'frontend_ux', 'Advanced Search — masonry grid with intelligent filtering', 'Avansert søk — masonry-gitter med intelligent filtrering', 'Розширений пошук — masonry-сітка з інтелектуальною фільтрацією', 'As content grew to 200+ articles, basic text search wasn''t enough. Full-text search with multi-filter, masonry grid, YouTube detection, and tag cloud for content discovery.', 'Etter hvert som innholdet vokste til 200+ artikler, var grunnleggende tekstsøk ikke nok. Fulltekstsøk med multifilter, masonry-gitter, YouTube-deteksjon og tag-sky for innholdsoppdagelse.', 'Коли контент виріс до 200+ статей, базового текстового пошуку стало недостатньо. Повнотекстовий пошук із мультифільтром, masonry-сіткою, детекцією YouTube та хмарою тегів для відкриття контенту.', 'As the content library grew to 200+ articles, finding specific content became painful. Simple text search wasn''t enough — users needed to filter by tags, date ranges, and content types simultaneously.', 'Etter hvert som innholdsbiblioteket vokste til 200+ artikler, ble det smertefullt å finne spesifikt innhold. Enkelt tekstsøk var ikke nok — brukerne trengte å filtrere etter tagger, datoperioder og innholdstyper samtidig.', 'Коли бібліотека контенту виросла до 200+ статей, знаходження конкретного контенту стало болісним. Простого текстового пошуку було недостатньо — користувачам потрібно було фільтрувати за тегами, діапазонами дат та типами контенту одночасно.', 'Full-text search with 300ms debounce. Multi-filter: query + tags (multi-select) + date range + content type. Masonry grid layout with natural image dimensions. YouTube detection: getYouTubeVideoId() parses multiple URL formats, getYouTubeThumbnail() fetches hqdefault quality with play overlay. Tag cloud sized by frequency. Header search icon expands right-to-left, overlaying language buttons.', 'Fulltekstsøk med 300ms debounce. Multifilter: søk + tagger (flervalg) + datoperiode + innholdstype. Masonry-gitter med naturlige bildedimensjoner. YouTube-deteksjon: getYouTubeVideoId() parser flere URL-formater, getYouTubeThumbnail() henter hqdefault-kvalitet med avspillingsoverlegg. Tag-sky dimensjonert etter frekvens. Søkeikon i header ekspanderer høyre-til-venstre, overlegger språkknapper.', 'Повнотекстовий пошук з 300ms debounce. Мультифільтр: запит + теги (множинний вибір) + діапазон дат + тип контенту. Masonry-сітка з природними розмірами зображень. Детекція YouTube: getYouTubeVideoId() парсить кілька форматів URL, getYouTubeThumbnail() отримує hqdefault якість з оверлеєм відтворення. Хмара тегів за частотою. Іконка пошуку в хедері розгортається справа наліво, перекриваючи кнопки мов.', 'Search page became a content discovery surface. Tag cloud reveals content patterns. Masonry grid makes browsing visually engaging. The expandable header search saves screen real estate while staying accessible.', 'Søkesiden ble en innholdsoppdagelsesflate. Tag-sky avslører innholdsmønstre. Masonry-gitteret gjør blaing visuelt engasjerende. Det utvidbare header-søket sparer skjermplass mens det forblir tilgjengelig.', 'Сторінка пошуку стала поверхнею відкриття контенту. Хмара тегів розкриває патерни контенту. Masonry-сітка робить перегляд візуально залучаючим. Розгортаний пошук у хедері зберігає екранний простір, залишаючись доступним.', '{"Next.js","React","Supabase","Tailwind CSS","TypeScript"}', '{"#Search","#MasonryGrid","#Filtering","#TagCloud","#ContentDiscovery"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p34', 'portfolio', 'frontend_ux', 'Glassmorphism Design System — consistency through transparency', 'Glassmorfisme designsystem — konsistens gjennom gjennomsiktighet', 'Дизайн-система Glassmorphism — консистентність через прозорість', 'Admin panel components grew organically with inconsistent styles. A glassmorphism design language applied everywhere ensures 17 components look cohesive with zero custom CSS.', 'Adminpanelkomponenter vokste organisk med inkonsistente stiler. Et glassmorfisme-designspråk brukt overalt sikrer at 17 komponenter ser sammenhengende ut med null tilpasset CSS.', 'Компоненти адмінки зростали органічно з непослідовними стилями. Дизайн-мова glassmorphism, застосована скрізь, забезпечує цілісний вигляд 17 компонентів з нульовим кастомним CSS.', 'Admin panel components were growing organically. Each developer (me, at different times) used slightly different card styles, shadows, and opacities. The result looked inconsistent.', 'Adminpanelkomponenter vokste organisk. Hver utvikler (meg, på forskjellige tidspunkter) brukte litt forskjellige kortstiler, skygger og opasiteter. Resultatet så inkonsistent ut.', 'Компоненти адмінки зростали органічно. Кожен розробник (я, у різний час) використовував трохи різні стилі карточок, тіні та непрозорості. Результат виглядав непослідовно.', 'Every admin component follows the established pattern. Cards: bg-white/10 backdrop-blur-lg rounded-xl border border-white/20. Buttons: motion.button with whileHover={{ scale: 1.05 }}. Platform colors: #0A66C2 LinkedIn, #1877F2 Facebook, #E4405F Instagram. Loading: Loader2 animate-spin. Error: bg-red-500/10 border-red-500/30. All via Tailwind utility classes — no custom CSS files.', 'Hver adminkomponent følger det etablerte mønsteret. Kort: bg-white/10 backdrop-blur-lg rounded-xl border border-white/20. Knapper: motion.button med whileHover={{ scale: 1.05 }}. Plattformfarger: #0A66C2 LinkedIn, #1877F2 Facebook, #E4405F Instagram. Lasting: Loader2 animate-spin. Feil: bg-red-500/10 border-red-500/30. Alt via Tailwind-verktøyklasser — ingen tilpassede CSS-filer.', 'Кожен компонент адмінки слідує встановленому патерну. Карточки: bg-white/10 backdrop-blur-lg rounded-xl border border-white/20. Кнопки: motion.button з whileHover={{ scale: 1.05 }}. Кольори платформ: #0A66C2 LinkedIn, #1877F2 Facebook, #E4405F Instagram. Завантаження: Loader2 animate-spin. Помилка: bg-red-500/10 border-red-500/30. Все через Tailwind utility класи — жодних кастомних CSS-файлів.', '17 admin components with zero visual inconsistency. New components copy-paste the pattern and look native immediately. The glassmorphism aesthetic is distinctive yet professional — dark backgrounds with translucent cards create depth without distraction.', '17 adminkomponenter med null visuell inkonsistens. Nye komponenter kopierer mønsteret og ser native ut umiddelbart. Glassmorfisme-estetikken er distinkt, men profesjonell — mørke bakgrunner med gjennomskinnelige kort skaper dybde uten distraksjon.', '17 компонентів адмінки з нульовою візуальною непослідовністю. Нові компоненти копіюють патерн і виглядають нативно одразу. Естетика glassmorphism виразна, але професійна — темні фони з напівпрозорими карточками створюють глибину без відволікання.', '{"Tailwind CSS","Framer Motion","React","TypeScript"}', '{"#Glassmorphism","#DesignSystem","#TailwindCSS","#AdminPanel","#UI"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p35', 'portfolio', 'devops_infra', 'Multilingual SEO — one site, three search engines', 'Flerspråklig SEO — én side, tre søkemotorer', 'Мультимовний SEO — один сайт, три пошукові системи', 'Content in 3 languages needs explicit signals for search engines. Full hreflang implementation, multilingual sitemap, and language-specific JSON-LD schemas ensure correct indexing.', 'Innhold på 3 språk trenger eksplisitte signaler for søkemotorer. Full hreflang-implementering, flerspråklig sitemap og språkspesifikke JSON-LD-skjemaer sikrer korrekt indeksering.', 'Контент 3 мовами потребує явних сигналів для пошукових систем. Повна реалізація hreflang, мультимовний sitemap та мовно-специфічні JSON-LD схеми забезпечують правильну індексацію.', 'Content exists in 3 languages but search engines need explicit signals about language relationships. Without proper hreflang tags and language-specific sitemaps, Google might index the Norwegian version for English queries, or miss the Ukrainian version entirely.', 'Innhold eksisterer på 3 språk, men søkemotorer trenger eksplisitte signaler om språkrelasjoner. Uten riktige hreflang-tagger og språkspesifikke sitemaps kan Google indeksere den norske versjonen for engelske søk, eller overse den ukrainske versjonen helt.', 'Контент існує 3 мовами, але пошукові системи потребують явних сигналів про мовні зв''язки. Без правильних hreflang тегів та мовно-специфічних sitemap Google може індексувати норвезьку версію для англійських запитів або повністю пропустити українську версію.', 'app/sitemap.ts generates dynamic sitemap with hreflang alternates for every article in 3 languages. Each article page has <link rel="alternate" hreflang="en|no|uk"> tags. Canonical URLs prevent duplicate content penalties. JSON-LD schemas (BlogPosting, NewsArticle) include inLanguage property. Open Graph og:locale set per language version.', 'app/sitemap.ts genererer dynamisk sitemap med hreflang-alternater for hver artikkel på 3 språk. Hver artikkelside har <link rel="alternate" hreflang="en|no|uk">-tagger. Kanoniske URL-er forhindrer duplikatinnholdsstraff. JSON-LD-skjemaer (BlogPosting, NewsArticle) inkluderer inLanguage-egenskap. Open Graph og:locale satt per språkversjon.', 'app/sitemap.ts генерує динамічний sitemap з hreflang alternатами для кожної статті 3 мовами. Кожна сторінка статті має теги <link rel="alternate" hreflang="en|no|uk">. Канонічні URL запобігають штрафам за дублюючий контент. JSON-LD схеми (BlogPosting, NewsArticle) включають властивість inLanguage. Open Graph og:locale встановлюється для кожної мовної версії.', 'Search engines correctly index and serve language-appropriate versions. Norwegian articles appear in Norwegian Google results. Ukrainian articles surface in Ukrainian searches. No duplicate content penalties despite 3x content volume.', 'Søkemotorer indekserer og viser språkpassende versjoner korrekt. Norske artikler vises i norske Google-resultater. Ukrainske artikler dukker opp i ukrainske søk. Ingen duplikatinnholdsstraff til tross for 3x innholdsvolum.', 'Пошукові системи правильно індексують і показують мовно-відповідні версії. Норвезькі статті з''являються в норвезьких результатах Google. Українські статті виходять в українських пошуках. Жодних штрафів за дублюючий контент попри 3x обсяг контенту.', '{"Next.js","JSON-LD","Open Graph","Sitemap","TypeScript"}', '{"#SEO","#Multilingual","#Hreflang","#JSONLD","#NextJS"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p36', 'portfolio', 'devops_infra', 'Dynamic OG Images — every share looks professional', 'Dynamiske OG-bilder — hver deling ser profesjonell ut', 'Динамічні OG-зображення — кожен шер виглядає професійно', 'Shared links default to generic images. Server-side OG image generation with Next.js Satori creates branded 16:9 images per article — zero manual design work.', 'Delte lenker viser generiske bilder som standard. Serverside OG-bildegenerering med Next.js Satori lager merkevarebyggende 16:9-bilder per artikkel — null manuelt designarbeid.', 'Зашарені посилання за замовчуванням мають загальні зображення. Серверна генерація OG-зображень з Next.js Satori створює брендовані 16:9 зображення для кожної статті — нуль ручної дизайнерської роботи.', 'Shared links on social media default to a generic site image or no image at all. Custom OG images per article dramatically improve click-through rates, but manually creating them is unfeasible for 5-10 articles daily.', 'Delte lenker på sosiale medier viser et generisk nettstedsbilde eller ingen bilde i det hele tatt som standard. Tilpassede OG-bilder per artikkel forbedrer klikkfrekvensen dramatisk, men å manuelt opprette dem er umulig for 5-10 artikler daglig.', 'Зашарені посилання в соцмережах за замовчуванням мають загальне зображення сайту або взагалі жодного. Кастомні OG-зображення для кожної статті різко покращують клікабельність, але ручне створення нереальне для 5-10 статей щодня.', 'app/opengraph-image.tsx uses Next.js OG Image generation (built on Satori). Each article gets a dynamically rendered image with: article title (truncated to 2 lines), category badge, vitalii.no branding, and gradient background matching the section color. Images are cached after first generation.', 'app/opengraph-image.tsx bruker Next.js OG Image-generering (bygget på Satori). Hver artikkel får et dynamisk rendret bilde med: artikkeltittel (avkortet til 2 linjer), kategoribadge, vitalii.no-merkevarebygging og gradientbakgrunn som matcher seksjonens farge. Bilder caches etter første generering.', 'app/opengraph-image.tsx використовує генерацію OG Image Next.js (побудовану на Satori). Кожна стаття отримує динамічно зрендерене зображення з: заголовком статті (обрізаним до 2 рядків), бейджем категорії, брендингом vitalii.no та градієнтним фоном, що відповідає кольору секції. Зображення кешуються після першої генерації.', 'Every shared link has a professional, branded image. Social media engagement on shared articles increased. Zero manual effort — the image exists the moment the article is published.', 'Hver delt lenke har et profesjonelt, merkevarebygd bilde. Engasjement i sosiale medier på delte artikler økte. Null manuell innsats — bildet eksisterer i det øyeblikket artikkelen publiseres.', 'Кожне зашарене посилання має професійне, брендоване зображення. Залученість у соцмережах для зашарених статей зросла. Нуль ручних зусиль — зображення існує в момент публікації статті.', '{"Next.js","Satori","Open Graph","React","TypeScript"}', '{"#OGImage","#SEO","#SocialMedia","#NextJS","#Satori"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p37', 'portfolio', 'devops_infra', 'GTM Integration Hub — one tag, all analytics', 'GTM-integrasjonshub — én tag, all analyse', 'GTM-хаб інтеграцій — один тег, вся аналітика', 'Four analytics platforms needed. Google Tag Manager loads once and manages GA4, Meta Pixel, LinkedIn Insight Tag, and custom events through a centralized dataLayer.', 'Fire analyseplattformer trengs. Google Tag Manager laster én gang og styrer GA4, Meta Pixel, LinkedIn Insight Tag og tilpassede hendelser gjennom en sentralisert dataLayer.', 'Потрібні чотири аналітичні платформи. Google Tag Manager завантажується один раз і керує GA4, Meta Pixel, LinkedIn Insight Tag та кастомними подіями через централізований dataLayer.', 'Four analytics platforms needed: GA4 (traffic), Meta Pixel (Facebook/Instagram ads), LinkedIn Insight Tag (audience insights), and custom event tracking. Installing each separately creates a maintenance nightmare and slows page load.', 'Fire analyseplattformer trengs: GA4 (trafikk), Meta Pixel (Facebook-/Instagram-annonser), LinkedIn Insight Tag (publikumsinnsikt) og tilpasset hendelsessporing. Å installere hver separat skaper et vedlikeholdsmarerritt og senker sidelastingen.', 'Потрібні чотири аналітичні платформи: GA4 (трафік), Meta Pixel (реклама Facebook/Instagram), LinkedIn Insight Tag (інсайти аудиторії) та кастомне відстеження подій. Встановлення кожної окремо створює кошмар підтримки та сповільнює завантаження сторінки.', '@next/third-parties GoogleTagManager component (ID: GTM-5XBL8L8S). TrackingContext provides hooks: trackPageView (automatic on route change), trackArticleView, trackShare, trackLanguageChange, trackSectionClick. Events pushed to (window as any).dataLayer to avoid Next.js type conflicts. Cookie consent gates analytics activation.', '@next/third-parties GoogleTagManager-komponent (ID: GTM-5XBL8L8S). TrackingContext tilbyr hooks: trackPageView (automatisk ved rutendring), trackArticleView, trackShare, trackLanguageChange, trackSectionClick. Hendelser pushes til (window as any).dataLayer for å unngå Next.js-typekonflikter. Cookie-samtykke styrer analyseaktivering.', 'Компонент @next/third-parties GoogleTagManager (ID: GTM-5XBL8L8S). TrackingContext надає хуки: trackPageView (автоматичний при зміні маршруту), trackArticleView, trackShare, trackLanguageChange, trackSectionClick. Події пушаться в (window as any).dataLayer для уникнення конфліктів типів Next.js. Cookie consent контролює активацію аналітики.', 'Single script load for 4 analytics platforms. Event tracking is centralized — add one dataLayer.push() call and all platforms receive the data. GTM''s console allows real-time debugging without code changes.', 'Én skriptlasting for 4 analyseplattformer. Hendelsessporing er sentralisert — legg til én dataLayer.push()-kall og alle plattformer mottar dataene. GTMs konsoll tillater sanntidsfeilsøking uten kodeendringer.', 'Одне завантаження скрипта для 4 аналітичних платформ. Відстеження подій централізоване — додай один виклик dataLayer.push() і всі платформи отримують дані. Консоль GTM дозволяє дебаг у реальному часі без змін коду.', '{"Google Tag Manager","GA4","Meta Pixel","LinkedIn Insight Tag","Next.js"}', '{"#GTM","#Analytics","#GA4","#MetaPixel","#Tracking"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p38', 'portfolio', 'devops_infra', 'Cookie Consent — Norwegian law, zero friction', 'Informasjonskapselsamtykke — norsk lov, null friksjon', 'Cookie Consent — норвезький закон, нуль тертя', 'Norwegian ekomloven requires explicit consent for analytics cookies. A minimal, honest consent UI with no dark patterns — analytics only activate after explicit opt-in.', 'Norsk ekomlov krever eksplisitt samtykke for analyseinformasjonskapsler. Et minimalt, ærlig samtykke-UI uten mørke mønstre — analyse aktiveres kun etter eksplisitt opt-in.', 'Норвезький ekomloven вимагає явної згоди на аналітичні cookie. Мінімальний, чесний UI згоди без dark patterns — аналітика активується лише після явного opt-in.', 'Norwegian ekomloven requires explicit consent for analytics cookies. GDPR adds complexity. But aggressive cookie banners destroy user experience. Most visitors click "accept all" without reading — the consent is meaningless but legally required.', 'Norsk ekomlov krever eksplisitt samtykke for analyseinformasjonskapsler. GDPR legger til kompleksitet. Men aggressive informasjonskapsel-bannere ødelegger brukeropplevelsen. De fleste besøkende klikker "godta alle" uten å lese — samtykket er meningsløst, men lovpålagt.', 'Норвезький ekomloven вимагає явної згоди на аналітичні cookie. GDPR додає складності. Але агресивні cookie-банери руйнують користувацький досвід. Більшість відвідувачів клікають "прийняти все" без читання — згода безглузда, але юридично обов''язкова.', 'CookieConsentContext manages state. Banner appears on first visit. Choice persisted in localStorage. Analytics (TrackingContext) checks consent before any tracking call. /informasjonskapsler page provides full cookie policy in Norwegian. GTM only fires tags when consent is granted.', 'CookieConsentContext styrer tilstand. Banner vises ved første besøk. Valg lagret i localStorage. Analyse (TrackingContext) sjekker samtykke før enhver sporingskall. /informasjonskapsler-siden gir full informasjonskapselpolicy på norsk. GTM utløser bare tagger når samtykke er gitt.', 'CookieConsentContext керує станом. Банер з''являється при першому відвідуванні. Вибір зберігається в localStorage. Аналітика (TrackingContext) перевіряє згоду перед будь-яким трекінговим викликом. Сторінка /informasjonskapsler надає повну політику cookie норвезькою. GTM запускає теги лише при наданні згоди.', 'Legal compliance with minimal UX impact. Banner shown once, never again after choice. Visitors who reject cookies get the full site experience minus analytics. The Norwegian-language policy page shows respect for the local audience.', 'Lovlig samsvar med minimal UX-påvirkning. Banner vist én gang, aldri igjen etter valg. Besøkende som avviser informasjonskapsler får full nettstedsopplevelse minus analyse. Den norskspråklige policysiden viser respekt for det lokale publikummet.', 'Юридична відповідність із мінімальним впливом на UX. Банер показується один раз, ніколи більше після вибору. Відвідувачі, що відхиляють cookie, отримують повний досвід сайту мінус аналітика. Сторінка політики норвезькою мовою показує повагу до місцевої аудиторії.', '{"React","Next.js","Google Tag Manager","localStorage","TypeScript"}', '{"#GDPR","#CookieConsent","#Privacy","#Norwegian","#Compliance"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p39', 'portfolio', 'devops_infra', '20 GitHub Actions Workflows — the invisible workforce', '20 GitHub Actions-arbeidsflyter — den usynlige arbeidsstyrken', '20 воркфлоу GitHub Actions — невидима робоча сила', '43 Edge Functions, scheduled scraping, video processing, and social posting — all automated through 20 GitHub Actions workflows with retry logic and concurrency control.', '43 Edge Functions, planlagt skraping, videobehandling og sosial posting — alt automatisert gjennom 20 GitHub Actions-arbeidsflyter med gjenprøvingslogikk og samtidighetskontroll.', '43 Edge Functions, заплановий скрейпінг, обробка відео та постинг у соцмережі — все автоматизовано через 20 воркфлоу GitHub Actions із retry-логікою та контролем конкуренції.', 'The project has 43 Edge Functions, scheduled scraping every 10 minutes, video processing that takes 5+ minutes per video, and social media posting that needs retry logic. Manual deployment and triggering is unsustainable.', 'Prosjektet har 43 Edge Functions, planlagt skraping hvert 10. minutt, videobehandling som tar 5+ minutter per video, og sosial medieposting som trenger gjenprøvingslogikk. Manuell deployment og utløsning er uholdbart.', 'Проєкт має 43 Edge Functions, запланований скрейпінг кожні 10 хвилин, обробку відео, що займає 5+ хвилин на відео, та постинг у соцмережі, що потребує retry-логіки. Ручний деплой та запуск нестійкі.', '20 workflows covering: deployment (2), content scraping (4), video processing (3), social media video (4), content management (5), utilities (2). Patterns: MAX_RETRIES=3, RETRY_DELAY=15, only retry on 5xx errors. Concurrency groups prevent parallel runs of the same scraper. Round-robin selection for channel scraping. Batch processing for RSS (8 sources per batch).', '20 arbeidsflyter som dekker: deployment (2), innholdsskraping (4), videobehandling (3), video for sosiale medier (4), innholdsbehandling (5), verktøy (2). Mønstre: MAX_RETRIES=3, RETRY_DELAY=15, gjenprøving kun på 5xx-feil. Samtidighetsgrupper forhindrer parallelle kjøringer av samme skraper. Round-robin-utvalg for kanalskraping. Batchbehandling for RSS (8 kilder per batch).', '20 воркфлоу, що покривають: деплой (2), скрейпінг контенту (4), обробка відео (3), відео для соцмереж (4), управління контентом (5), утиліти (2). Патерни: MAX_RETRIES=3, RETRY_DELAY=15, retry лише для 5xx помилок. Групи конкуренції запобігають паралельним запускам одного скрейпера. Round-robin вибір для скрейпінгу каналів. Пакетна обробка для RSS (8 джерел на пакет).', 'The system operates 24/7 without human intervention. Telegram channels are checked every 10 minutes. RSS feeds every 30 minutes. Videos process every 30 minutes. Social comments sync every 30 minutes. Metrics sync every 6 hours. One developer, zero ops team.', 'Systemet opererer 24/7 uten menneskelig inngripen. Telegram-kanaler sjekkes hvert 10. minutt. RSS-feeder hvert 30. minutt. Videoer behandles hvert 30. minutt. Sosiale kommentarer synkroniseres hvert 30. minutt. Metrikker synkroniseres hver 6. time. Én utvikler, null ops-team.', 'Система працює 24/7 без людського втручання. Telegram-канали перевіряються кожні 10 хвилин. RSS-стрічки кожні 30 хвилин. Відео обробляються кожні 30 хвилин. Коментарі в соцмережах синхронізуються кожні 30 хвилин. Метрики синхронізуються кожні 6 годин. Один розробник, нуль ops-команди.', '{"GitHub Actions","Supabase","curl","jq","Bash"}', '{"#GitHubActions","#CICD","#Automation","#DevOps","#Serverless"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p40', 'portfolio', 'devops_infra', 'Netlify via Actions Only — why auto-build is disabled', 'Netlify kun via Actions — hvorfor auto-build er deaktivert', 'Netlify лише через Actions — чому auto-build вимкнений', 'Netlify auto-builds triggered on every push, even for Edge Function changes. Disabled auto-build and deploy exclusively through GitHub Actions for consistent environments.', 'Netlify auto-builds utløstes ved hver push, selv for Edge Function-endringer. Deaktiverte auto-build og deployer utelukkende gjennom GitHub Actions for konsistente miljøer.', 'Netlify auto-builds спрацьовували при кожному push, навіть для змін Edge Functions. Вимкнув auto-build і деплою виключно через GitHub Actions для консистентних середовищ.', 'Netlify''s auto-build triggers on every push to main. But environment variables in Netlify''s build environment sometimes differed from local, causing subtle bugs. A push to fix an Edge Function would trigger an unnecessary Netlify rebuild.', 'Netlifys auto-build utløses ved hver push til main. Men miljøvariabler i Netlifys byggemiljø var noen ganger forskjellige fra lokale, noe som forårsaket subtile feil. En push for å fikse en Edge Function ville utløse en unødvendig Netlify-ombygging.', 'Netlify auto-build спрацьовував при кожному push до main. Але змінні середовища в build-середовищі Netlify іноді відрізнялися від локальних, що спричиняло тонкі баги. Push для фіксу Edge Function запускав непотрібний ребілд Netlify.', 'deploy.yml runs on push to main. It builds Next.js, then deploys to Netlify using NETLIFY_AUTH_TOKEN and NETLIFY_SITE_ID. deploy-supabase.yml runs only when files in supabase/** change — it handles Edge Function deployment and migrations. The two workflows are independent.', 'deploy.yml kjører ved push til main. Den bygger Next.js, deretter deployer til Netlify med NETLIFY_AUTH_TOKEN og NETLIFY_SITE_ID. deploy-supabase.yml kjører kun når filer i supabase/** endres — den håndterer Edge Function-deployment og migrasjoner. De to arbeidsflyterene er uavhengige.', 'deploy.yml запускається при push до main. Білдить Next.js, потім деплоїть на Netlify через NETLIFY_AUTH_TOKEN та NETLIFY_SITE_ID. deploy-supabase.yml запускається лише коли змінюються файли в supabase/** — обробляє деплой Edge Functions та міграції. Два воркфлоу незалежні.', 'No more phantom builds from Edge Function changes. Environment variables are consistent (GitHub Actions is the single source of truth). Build time saved on non-frontend changes. Deployment is predictable and debuggable.', 'Ingen flere fantombygg fra Edge Function-endringer. Miljøvariabler er konsistente (GitHub Actions er den eneste sannhetskilden). Byggetid spart på ikke-frontend-endringer. Deployment er forutsigbar og feilsøkbar.', 'Більше жодних фантомних білдів від змін Edge Functions. Змінні середовища консистентні (GitHub Actions — єдине джерело істини). Час білду зекономлений на не-фронтенд змінах. Деплой передбачуваний і дебажний.', '{"Netlify","GitHub Actions","Next.js","Supabase CLI"}', '{"#Netlify","#GitHubActions","#CICD","#Deployment","#DevOps"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p41', 'portfolio', 'devops_infra', 'Round-Robin Scraping — 6 channels, 10 minutes, zero rate limits', 'Round-robin skraping — 6 kanaler, 10 minutter, null frekvensbegrensninger', 'Round-robin скрейпінг — 6 каналів, 10 хвилин, нуль rate limits', 'Scraping all 6 Telegram channels at once risks rate limits and timeouts. Round-robin rotates one channel per run, checking each every ~60 minutes with zero rate limit hits.', 'Å skrape alle 6 Telegram-kanaler på én gang risikerer frekvensbegrensninger og tidsavbrudd. Round-robin roterer én kanal per kjøring, sjekker hver ~60 minutter uten frekvensbegrensningstreff.', 'Скрейпінг усіх 6 Telegram-каналів одночасно ризикує rate limits та таймаутами. Round-robin ротує один канал за запуск, перевіряючи кожен ~60 хвилин з нульовими rate limit хітами.', 'Scraping all 6 Telegram channels every 10 minutes could trigger Telegram''s rate limits. Batch scraping (all at once) also risks timeout — each channel might have 10+ new posts to process.', 'Å skrape alle 6 Telegram-kanaler hvert 10. minutt kan utløse Telegrams frekvensbegrensninger. Batchskraping (alle på én gang) risikerer også tidsavbrudd — hver kanal kan ha 10+ nye innlegg å behandle.', 'Скрейпінг усіх 6 Telegram-каналів кожні 10 хвилин може спрацювати rate limits Telegram. Пакетний скрейпінг (всі одночасно) також ризикує таймаутом — кожен канал може мати 10+ нових постів для обробки.', 'realtime-scraper.yml calculates the source index: INDEX = (minute / 10) % sourceCount. Concurrency group telegram-scraper with cancel-in-progress: false ensures only one run at a time — the next waits for the current to finish. Each run processes only one source, keeping execution time under 2 minutes.', 'realtime-scraper.yml beregner kildeindeksen: INDEX = (minutt / 10) % sourceCount. Samtidighetsgruppe telegram-scraper med cancel-in-progress: false sikrer kun én kjøring om gangen — neste venter på at den gjeldende fullføres. Hver kjøring behandler kun én kilde, og holder kjøretiden under 2 minutter.', 'realtime-scraper.yml обчислює індекс джерела: INDEX = (хвилина / 10) % sourceCount. Група конкуренції telegram-scraper з cancel-in-progress: false забезпечує лише один запуск одночасно — наступний чекає завершення поточного. Кожен запуск обробляє лише одне джерело, тримаючи час виконання під 2 хвилини.', 'Zero rate limit hits from Telegram. Each channel is checked every ~60 minutes (with 6 channels). Execution time is predictable and short. The concurrency guard prevents overlapping runs during slow network conditions.', 'Null frekvensbegrensningstreff fra Telegram. Hver kanal sjekkes hver ~60 minutter (med 6 kanaler). Kjøretid er forutsigbar og kort. Samtidighetsvakten forhindrer overlappende kjøringer under trege nettverksforhold.', 'Нуль хітів rate limit від Telegram. Кожен канал перевіряється кожні ~60 хвилин (при 6 каналах). Час виконання передбачуваний і короткий. Захист конкуренції запобігає перетинанню запусків при повільних мережевих умовах.', '{"GitHub Actions","Telegram Bot API","MTKruto","Bash"}', '{"#RoundRobin","#Scraping","#RateLimiting","#GitHubActions","#Telegram"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p42', 'portfolio', 'devops_infra', 'Retry Logic Pattern — because APIs fail on Tuesdays', 'Gjenprøvingslogikkmønster — fordi API-er feiler på tirsdager', 'Патерн retry-логіки — бо API падають по вівторках', 'External APIs occasionally return 5xx errors. Standardized retry pattern across all workflows: 3 attempts, 15-second delay, only on 5xx (not 4xx client errors).', 'Eksterne API-er returnerer av og til 5xx-feil. Standardisert gjenprøvingsmønster på tvers av alle arbeidsflyter: 3 forsøk, 15 sekunders forsinkelse, kun ved 5xx (ikke 4xx klientfeil).', 'Зовнішні API іноді повертають 5xx помилки. Стандартизований патерн retry у всіх воркфлоу: 3 спроби, 15-секундна затримка, лише для 5xx (не 4xx клієнтських помилок).', 'External APIs (Supabase Edge Functions, social media APIs, AI providers) occasionally return 5xx errors. A single failure shouldn''t break the entire pipeline.', 'Eksterne API-er (Supabase Edge Functions, sosiale medie-API-er, AI-leverandører) returnerer av og til 5xx-feil. En enkelt feil bør ikke bryte hele pipelinen.', 'Зовнішні API (Supabase Edge Functions, API соцмереж, AI-провайдери) іноді повертають 5xx помилки. Одна помилка не повинна ламати весь пайплайн.', 'Standardized across all workflows: 3 attempts maximum, 15-second delay between retries, only retry on 5xx errors (4xx are client errors — retrying won''t help). curl -w "\n%{http_code}" captures both body and status code. Response parsed with jq for structured error reporting.', 'Standardisert på tvers av alle arbeidsflyter: maks 3 forsøk, 15 sekunders forsinkelse mellom gjenprøvinger, gjenprøving kun ved 5xx-feil (4xx er klientfeil — gjenprøving hjelper ikke). curl -w "\n%{http_code}" fanger både kropp og statuskode. Respons parset med jq for strukturert feilrapportering.', 'Стандартизовано у всіх воркфлоу: максимум 3 спроби, 15-секундна затримка між retry, retry лише для 5xx помилок (4xx — клієнтські помилки, retry не допоможе). curl -w "\n%{http_code}" захоплює і тіло, і статус-код. Відповідь парситься jq для структурованого звітування про помилки.', 'Transient API failures are handled automatically. The 5xx-only retry policy prevents infinite loops on permanent errors. 15-second delay gives the remote service time to recover. 95%+ of retried requests succeed on the second attempt.', 'Forbigående API-feil håndteres automatisk. 5xx-kun gjenprøvingspolicyen forhindrer uendelige løkker ved permanente feil. 15 sekunders forsinkelse gir den eksterne tjenesten tid til å gjenopprette. 95%+ av gjenprøvde forespørsler lykkes på andre forsøk.', 'Тимчасові збої API обробляються автоматично. Retry-політика лише для 5xx запобігає нескінченним циклам при постійних помилках. 15-секундна затримка дає віддаленому сервісу час на відновлення. 95%+ повторених запитів успішні з другої спроби.', '{"GitHub Actions","curl","jq","Bash"}', '{"#RetryLogic","#ErrorHandling","#DevOps","#Resilience","#CICD"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p43', 'portfolio', 'frontend_ux', '10-Tab Dashboard — command center for one-person media operations', '10-faners dashboard — kommandosenter for én-persons medieoperasjoner', '10-вкладковий дашборд — командний центр для медіаоперацій однієї людини', 'Managing multi-platform content operations requires jumping between Telegram, Supabase, GitHub, and social apps. One dashboard with 10 tabs replaces them all.', 'Å administrere flerplattforms innholdsoperasjoner krever hopping mellom Telegram, Supabase, GitHub og sosiale apper. Ett dashboard med 10 faner erstatter dem alle.', 'Керування мультиплатформними контент-операціями вимагає перемикання між Telegram, Supabase, GitHub та соціальними додатками. Один дашборд з 10 вкладками замінює їх усі.', 'Managing a multi-platform content operation requires jumping between: Telegram (moderation), Supabase (database), GitHub (deployments), LinkedIn/Facebook/Instagram (social), and multiple AI services. Context switching kills productivity.', 'Å administrere en flerplattforms innholdsoperasjon krever hopping mellom: Telegram (moderering), Supabase (database), GitHub (deployments), LinkedIn/Facebook/Instagram (sosiale), og flere AI-tjenester. Kontekstbytte dreper produktivitet.', 'Керування мультиплатформними контент-операціями вимагає перемикання між: Telegram (модерація), Supabase (база даних), GitHub (деплої), LinkedIn/Facebook/Instagram (соцмережі) та кількома AI-сервісами. Переключення контексту вбиває продуктивність.', '10 tabs: Overview (stats + monitoring), Queue (pending moderation), News (CRUD), Blog (CRUD), Monitor (4-tier RSS), Social (post tracking), Analytics (engagement metrics), Comments (cross-platform), Skills (drag & drop), Settings (9 sub-tabs for sources, prompts, images, API keys, accounts, scheduling, automation, tags, debug).', '10 faner: Oversikt (statistikk + overvåking), Kø (ventende moderering), Nyheter (CRUD), Blogg (CRUD), Monitor (4-nivås RSS), Sosialt (innleggssporing), Analyse (engasjementsmetrikker), Kommentarer (kryssplattform), Ferdigheter (dra og slipp), Innstillinger (9 underfaner for kilder, prompter, bilder, API-nøkler, kontoer, planlegging, automatisering, tagger, feilsøking).', '10 вкладок: Огляд (статистика + моніторинг), Черга (очікуючі на модерацію), Новини (CRUD), Блог (CRUD), Монітор (4-рівневий RSS), Соціальне (відстеження постів), Аналітика (метрики залученості), Коментарі (крос-платформні), Навички (drag & drop), Налаштування (9 підвкладок для джерел, промптів, зображень, API-ключів, акаунтів, планування, автоматизації, тегів, дебагу).', 'All daily operations happen in one browser tab. Morning routine: check Overview for overnight activity, scan Queue for pending articles, glance at Analytics for engagement trends. The collapsible sidebar maximizes screen real estate. Each tab loads independently — no monolithic data fetch.', 'Alle daglige operasjoner skjer i én nettleserfane. Morgenrutine: sjekk Oversikt for nattlig aktivitet, skann Kø for ventende artikler, se på Analyse for engasjementstrender. Den sammenleggbare sidefeltet maksimerer skjermplassen. Hver fane laster uavhengig — ingen monolittisk datahenting.', 'Усі щоденні операції відбуваються в одній вкладці браузера. Ранкова рутина: перевірити Огляд на нічну активність, переглянути Чергу на очікуючі статті, глянути Аналітику на тренди залученості. Складана бокова панель максимізує екранний простір. Кожна вкладка завантажується незалежно — без монолітного отримання даних.', '{"React","Next.js","Supabase","Tailwind CSS","Framer Motion"}', '{"#AdminPanel","#Dashboard","#ContentManagement","#React","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p44', 'portfolio', 'frontend_ux', '4-Tier RSS Monitor — not all sources are created equal', '4-nivås RSS-monitor — ikke alle kilder er skapt like', '4-рівневий RSS-монітор — не всі джерела створені рівними', '26+ RSS feeds have wildly different quality. A tier system (Critical, High, Medium, Low) with drag-and-drop management and per-tier processing priority keeps high-value content surfacing first.', '26+ RSS-feeder har vilt forskjellig kvalitet. Et nivåsystem (Kritisk, Høy, Medium, Lav) med dra-og-slipp-administrasjon og prioritet per nivå holder høyverdi-innhold synlig først.', '26+ RSS-стрічок мають дуже різну якість. Система рівнів (Критичний, Високий, Середній, Низький) із drag-and-drop керуванням та пріоритетом обробки по рівнях тримає якісний контент на поверхні.', '26+ RSS feeds have wildly different qualities and publication frequencies. Treating them equally means high-value sources (Reuters, TechCrunch) compete for attention with low-quality content mills.', '26+ RSS-feeder har vilt forskjellige kvaliteter og publiseringsfrekvenser. Å behandle dem likt betyr at høykvalitetskilder (Reuters, TechCrunch) konkurrerer om oppmerksomhet med lavkvalitets innholdsfabrikker.', '26+ RSS-стрічок мають дуже різну якість та частоту публікацій. Рівне ставлення означає, що джерела високої якості (Reuters, TechCrunch) конкурують за увагу з контент-фабриками низької якості.', 'NewsMonitorManager component with 4 color-coded tier columns (Red, Orange, Yellow, Gray). Drag-and-drop sources between tiers. monitor-rss-sources Edge Function processes tiers with different batch sizes and priorities. Tier 1 sources are always in the first batch. Admin can toggle pre-moderation per source. Real-time article previews within each tier column.', 'NewsMonitorManager-komponent med 4 fargekodede nivåkolonner (Rød, Oransje, Gul, Grå). Dra og slipp kilder mellom nivåer. monitor-rss-sources Edge Function behandler nivåer med forskjellige batchstørrelser og prioriteter. Nivå 1-kilder er alltid i den første batchen. Admin kan toggle forhåndsmoderering per kilde. Sanntids artikkelforhåndsvisninger innenfor hver nivåkolonne.', 'Компонент NewsMonitorManager із 4 кольорово-кодованими колонками рівнів (Червоний, Помаранчевий, Жовтий, Сірий). Drag-and-drop джерел між рівнями. Edge Function monitor-rss-sources обробляє рівні з різними розмірами пакетів та пріоритетами. Джерела Рівня 1 завжди в першому пакеті. Адмін може перемикати премодерацію для кожного джерела. Прев''ю статей у реальному часі в кожній колонці рівня.', 'High-value content surfaces immediately. Low-priority sources don''t create noise. The drag-and-drop interface makes tier management intuitive. New sources start at Tier 4 and graduate upward based on content quality.', 'Høyverdi-innhold dukker opp umiddelbart. Lavprioritetskilder skaper ikke støy. Dra-og-slipp-grensesnittet gjør nivåadministrasjon intuitiv. Nye kilder starter på Nivå 4 og rykker opp basert på innholdskvalitet.', 'Якісний контент з''являється негайно. Низькопріоритетні джерела не створюють шуму. Інтерфейс drag-and-drop робить керування рівнями інтуїтивним. Нові джерела починають на Рівні 4 і просуваються вгору на основі якості контенту.', '{"React","Supabase","Framer Motion","Tailwind CSS","TypeScript"}', '{"#RSS","#ContentCuration","#TierSystem","#AdminPanel","#DragAndDrop"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p45', 'portfolio', 'frontend_ux', 'Skills Manager — your tech stack, your order', 'Ferdighetsbehandler — din tech stack, din rekkefølge', 'Менеджер навичок — твій tech stack, твій порядок', 'Portfolio skills need to be easily reorderable for different contexts. Drag-and-drop with Framer Motion, SimpleIcons CDN logos, category colors, and localStorage persistence.', 'Porteføljeferdigheter må enkelt kunne omorganiseres for ulike kontekster. Dra-og-slipp med Framer Motion, SimpleIcons CDN-logoer, kategorifargeri og localStorage-persistens.', 'Навички портфоліо мають легко переупорядковуватися для різних контекстів. Drag-and-drop з Framer Motion, логотипи SimpleIcons CDN, кольори категорій та збереження в localStorage.', 'Portfolio skills section needs to be easily reorderable. Different contexts call for different skill ordering — when applying for a React job, React should be first. For a DevOps role, cloud skills should lead.', 'Porteføljens ferdighetsseksjon må enkelt kunne omorganiseres. Ulike kontekster krever ulik ferdighetsrekkefølge — når du søker en React-jobb, bør React være først. For en DevOps-rolle bør skybaserte ferdigheter lede.', 'Секція навичок портфоліо повинна легко переупорядковуватися. Різні контексти вимагають різного порядку навичок — при подачі на React-позицію, React має бути першим. Для DevOps-ролі хмарні навички мають лідирувати.', 'Framer Motion Reorder component for smooth drag animations. 6 category colors: development (green), UI (purple), automation (blue), AI (orange), marketing (pink), integration (cyan). SimpleIcons CDN for tech logos (cdn.simpleicons.org/[name]). localStorage key: vitalii_skills_list. No authentication needed — it''s the visitor''s own portfolio view customization.', 'Framer Motion Reorder-komponent for jevne dra-animasjoner. 6 kategorifargeri: utvikling (grønn), UI (lilla), automatisering (blå), AI (oransje), markedsføring (rosa), integrasjon (cyan). SimpleIcons CDN for teknologilogoer (cdn.simpleicons.org/[name]). localStorage-nøkkel: vitalii_skills_list. Ingen autentisering nødvendig — det er besøkendes egen porteføljevisnings-tilpasning.', 'Компонент Framer Motion Reorder для плавних drag-анімацій. 6 кольорів категорій: розробка (зелений), UI (фіолетовий), автоматизація (синій), AI (помаранчевий), маркетинг (рожевий), інтеграція (бірюзовий). SimpleIcons CDN для технологічних логотипів (cdn.simpleicons.org/[name]). Ключ localStorage: vitalii_skills_list. Автентифікація не потрібна — це кастомізація перегляду портфоліо самого відвідувача.', 'Skill reordering takes 2 seconds of dragging. Icons provide instant recognition. Category colors group related skills visually. The localStorage approach means zero API calls for this purely presentational feature.', 'Ferdighetsomorganisering tar 2 sekunder med dra. Ikoner gir umiddelbar gjenkjennelse. Kategorifargeri grupperer relaterte ferdigheter visuelt. localStorage-tilnærmingen betyr null API-kall for denne rent presentasjonsmessige funksjonen.', 'Переупорядкування навичок займає 2 секунди перетягування. Іконки дають миттєве розпізнавання. Кольори категорій візуально групують пов''язані навички. Підхід localStorage означає нуль API-викликів для цієї чисто презентаційної функції.', '{"Framer Motion","React","SimpleIcons","localStorage","TypeScript"}', '{"#DragAndDrop","#FramerMotion","#Skills","#Portfolio","#localStorage"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p46', 'portfolio', 'other', '3-Language Content Pipeline — one article enters, three emerge', '3-språks innholdspipeline — én artikkel inn, tre ut', '3-мовний контент-пайплайн — одна стаття входить, три виходять', 'Three audiences expect native-quality content. AI rewrites (not translates) each article with language-specific prompts for tone, style, and cultural context.', 'Tre målgrupper forventer innhold av morsmålskvalitet. AI omskriver (ikke oversetter) hver artikkel med språkspesifikke prompter for tone, stil og kulturell kontekst.', 'Три аудиторії очікують контент рідної якості. AI переписує (а не перекладає) кожну статтю з мовно-специфічними промптами для тону, стилю та культурного контексту.', 'The portfolio serves three distinct audiences: international tech community (English), Norwegian professionals (Norwegian), and Ukrainian diaspora (Ukrainian). Each audience expects native-quality content, not machine translations.', 'Porteføljen betjener tre distinkte målgrupper: internasjonalt teknologisamfunn (engelsk), norske fagfolk (norsk) og ukrainsk diaspora (ukrainsk). Hver målgruppe forventer innhold av morsmålskvalitet, ikke maskinoversettelser.', 'Портфоліо обслуговує три різні аудиторії: міжнародну техспільноту (англійська), норвезьких професіоналів (норвезька) та українську діаспору (українська). Кожна аудиторія очікує контент рідної якості, а не машинні переклади.', 'Database stores separate fields per language: title_en/no/ua, content_en/no/ua, description_en/no/ua, slug_en/no/ua. process-news Edge Function rewrites the original article using language-specific prompts from ai_prompts table. TranslationContext on the frontend manages language state with 143+ translation keys. Hreflang tags connect all three versions for SEO. Language selector in header with flag indicators.', 'Database lagrer separate felt per språk: title_en/no/ua, content_en/no/ua, description_en/no/ua, slug_en/no/ua. process-news Edge Function omskriver den originale artikkelen ved bruk av språkspesifikke prompter fra ai_prompts-tabellen. TranslationContext på frontend styrer språktilstand med 143+ oversettelsesnøkler. Hreflang-tagger kobler alle tre versjoner for SEO. Språkvelger i header med flaggindikatorer.', 'База даних зберігає окремі поля для кожної мови: title_en/no/ua, content_en/no/ua, description_en/no/ua, slug_en/no/ua. Edge Function process-news переписує оригінальну статтю, використовуючи мовно-специфічні промпти з таблиці ai_prompts. TranslationContext на фронтенді керує мовним станом із 143+ ключами перекладу. Теги hreflang з''єднують усі три версії для SEO. Селектор мови в хедері з індикаторами прапорців.', 'Three complete content ecosystems from one editorial effort. Each language version reads naturally — not like a translated document. The shared slug structure (slug_en, slug_no, slug_ua) enables cross-language navigation without URL hacks.', 'Tre komplette innholdsøkosystemer fra én redaksjonell innsats. Hver språkversjon leses naturlig — ikke som et oversatt dokument. Den delte slug-strukturen (slug_en, slug_no, slug_ua) muliggjør kryssspråklig navigasjon uten URL-hacks.', 'Три повних контентних екосистеми з одного редакційного зусилля. Кожна мовна версія читається природно — а не як перекладений документ. Спільна slug-структура (slug_en, slug_no, slug_ua) забезпечує міжмовну навігацію без URL-хаків.', '{"Supabase","Azure OpenAI","Next.js","React","TypeScript"}', '{"#Internationalization","#i18n","#Multilingual","#ContentPipeline","#AI"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p47', 'portfolio', 'other', 'Auto Norway Detection — the algorithm that knows what Norwegians want', 'Auto Norge-deteksjon — algoritmen som vet hva nordmenn vil ha', 'Автовизначення Норвегії — алгоритм, який знає, чого хочуть норвежці', 'Some RSS articles are Norway-focused but manually detecting this adds another decision. AI detects Norwegian companies, cities, and cultural markers to auto-suggest Norwegian-first publication.', 'Noen RSS-artikler er Norges-fokuserte, men manuell deteksjon legger til en ekstra beslutning. AI oppdager norske selskaper, byer og kulturelle markører for å auto-foreslå norskførst-publisering.', 'Деякі RSS-статті фокусуються на Норвегії, але ручне визначення цього додає ще одне рішення. AI визначає норвезькі компанії, міста та культурні маркери для автопропозиції публікації норвезькою першою.', 'Some RSS sources publish Norwegian-focused articles (Equinor news, Oslo tech scene, Nordics policy). These should be published in Norwegian first, not English. But manually detecting which articles are "Norwegian relevant" adds another decision to the moderation pipeline.', 'Noen RSS-kilder publiserer Norge-fokuserte artikler (Equinor-nyheter, Oslo-teknologiscenen, nordisk politikk). Disse bør publiseres på norsk først, ikke engelsk. Men å manuelt oppdage hvilke artikler som er "Norges-relevante" legger til en ekstra beslutning i modereringspipelinen.', 'Деякі RSS-джерела публікують статті, орієнтовані на Норвегію (новини Equinor, техсцена Осло, політика Нордиків). Вони мають публікуватися норвезькою першою, а не англійською. Але ручне визначення, які статті "релевантні для Норвегії", додає ще одне рішення до пайплайну модерації.', 'During pre-moderation, the AI checks for Norway-relevant signals: company names (Equinor, Telenor, DNB), locations (Oslo, Bergen, Stavanger, Tromsoe), policy references (Stortinget, NAV, arbeidsmiljoloven), and cultural markers. When detected, the article is pre-flagged as language_suggestion: ''no''. Telegram bot shows "Norwegian detected" badge and pre-selects NO language for publishing.', 'Under forhåndsmoderering sjekker AI for Norge-relevante signaler: selskapsnavn (Equinor, Telenor, DNB), steder (Oslo, Bergen, Stavanger, Tromsø), policyreferanser (Stortinget, NAV, arbeidsmiljøloven) og kulturelle markører. Når oppdaget, forhåndsflagges artikkelen som language_suggestion: ''no''. Telegram-bot viser "Norsk oppdaget"-merke og forhåndsvelger NO-språk for publisering.', 'Під час премодерації AI перевіряє сигнали, релевантні для Норвегії: назви компаній (Equinor, Telenor, DNB), локації (Oslo, Bergen, Stavanger, Tromsoe), посилання на політику (Stortinget, NAV, arbeidsmiljoloven) та культурні маркери. Коли виявлено, стаття попередньо позначається як language_suggestion: ''no''. Telegram-бот показує бейдж "Виявлено норвезьку" та попередньо обирає мову NO для публікації.', 'Norwegian-relevant content is identified and published in the right language automatically. The Norwegian audience sees relevant content faster. The AI detection catches subtle Norway connections that keyword matching would miss.', 'Norges-relevant innhold identifiseres og publiseres på riktig språk automatisk. Det norske publikummet ser relevant innhold raskere. AI-deteksjonen fanger opp subtile Norge-koblinger som nøkkelordmatching ville ha oversett.', 'Контент, релевантний для Норвегії, ідентифікується та публікується правильною мовою автоматично. Норвезька аудиторія бачить релевантний контент швидше. AI-детекція ловить тонкі зв''язки з Норвегією, які пошук за ключовими словами пропустив би.', '{"Azure OpenAI","Supabase Edge Functions","Telegram Bot API","Deno"}', '{"#AI","#LanguageDetection","#Norway","#ContentPipeline","#Localization"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('p48', 'portfolio', 'other', 'Social Analytics Dashboard — Shield App for free', 'Sosial analysedashboard — Shield App gratis', 'Дашборд аналітики соцмереж — Shield App безкоштовно', 'Shield App costs $25/month for LinkedIn analytics. Built the same dashboard inside the admin panel using existing data infrastructure — with period comparison, CSV export, and multi-platform support.', 'Shield App koster $25/mnd for LinkedIn-analyse. Bygget det samme dashboardet inne i adminpanelet ved bruk av eksisterende datainfrastruktur — med periodesammenligning, CSV-eksport og flerplattformstøtte.', 'Shield App коштує $25/місяць за аналітику LinkedIn. Побудував той самий дашборд в адмінці, використовуючи існуючу інфраструктуру даних — із порівнянням періодів, CSV-експортом та мультиплатформною підтримкою.', 'Shield App ($25/month) tracks LinkedIn analytics: impressions, engagement rates, follower growth, content performance. I already have all the posting data flowing through my system. Paying $25/month for charts on data I already own feels wrong.', 'Shield App ($25/mnd) sporer LinkedIn-analyse: visninger, engasjementsrater, følgervekst, innholdsytelse. Jeg har allerede alle postingdata som flyter gjennom systemet mitt. Å betale $25/mnd for diagrammer over data jeg allerede eier føles feil.', 'Shield App ($25/місяць) відстежує аналітику LinkedIn: покази, рівні залученості, зростання підписників, ефективність контенту. Усі дані постингу вже проходять через мою систему. Платити $25/місяць за графіки даних, які я вже маю, відчувається неправильно.', 'sync-social-metrics Edge Function fetches post insights from Facebook Graph API (/{post_id}/insights) and Instagram Media API (/{media_id}/insights). Metrics: impressions, reach, likes, comments, shares, saves. follower_history table tracks daily follower counts. analytics_snapshots table aggregates daily metrics. Dashboard: 6 summary cards with % changes, engagement-over-time line chart, top posts ranking (sortable), platform comparison bars, follower growth chart, posting frequency bars, CSV export.', 'sync-social-metrics Edge Function henter innleggsinnsikt fra Facebook Graph API (/{post_id}/insights) og Instagram Media API (/{media_id}/insights). Metrikker: visninger, rekkevidde, likes, kommentarer, delinger, lagringer. follower_history-tabellen sporer daglige følgertall. analytics_snapshots-tabellen aggregerer daglige metrikker. Dashboard: 6 sammendragskort med %-endringer, engasjement-over-tid linjediagram, topp-innlegg-rangering (sorterbar), plattformsammenligningssøyler, følgervekstdiagram, publiseringsfrekvensssøyler, CSV-eksport.', 'Edge Function sync-social-metrics забирає інсайти постів із Facebook Graph API (/{post_id}/insights) та Instagram Media API (/{media_id}/insights). Метрики: покази, охоплення, лайки, коментарі, шери, збереження. Таблиця follower_history відстежує щоденну кількість підписників. Таблиця analytics_snapshots агрегує щоденні метрики. Дашборд: 6 карточок зведення з % змінами, лінійний графік залученості в часі, рейтинг топ-постів (сортований), стовпчики порівняння платформ, графік зростання підписників, стовпчики частоти публікацій, CSV-експорт.', 'Full analytics dashboard at $0/month. Currently tracking Facebook and Instagram with real data. LinkedIn stubbed for when Community Management API access arrives. Period comparison (7D/30D/90D/YTD) shows trends. CSV export provides data for external reporting.', 'Fullverdig analysedashboard til $0/mnd. Sporer for tiden Facebook og Instagram med ekte data. LinkedIn stubbet for når Community Management API-tilgang kommer. Periodesammenligning (7D/30D/90D/YTD) viser trender. CSV-eksport gir data for ekstern rapportering.', 'Повний дашборд аналітики за $0/місяць. Наразі відстежує Facebook та Instagram із реальними даними. LinkedIn заглушений до отримання доступу до Community Management API. Порівняння періодів (7D/30D/90D/YTD) показує тренди. CSV-експорт надає дані для зовнішньої звітності.', '{"Facebook Graph API","Instagram API","Recharts","Supabase","React"}', '{"#Analytics","#Dashboard","#ShieldApp","#ZeroCost","#SocialMedia"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j01', 'jobbot', 'ai_automation', 'AI Job Analyzer — knows you better than a recruiter', 'AI-jobbanalysator — kjenner deg bedre enn en rekrutterer', 'AI, який знає тебе краще за рекрутера', 'Hundreds of jobs appear daily on FINN.no, NAV.no, and LinkedIn. AI reads every listing and compares it against the full CV, returning a 0-100 score with pros, cons, and workplace aura.', 'Hundrevis av jobber dukker opp daglig på FINN.no, NAV.no og LinkedIn. AI leser hver annonse og sammenligner den med full CV, og returnerer en 0-100 poengsum med fordeler, ulemper og arbeidsplassaura.', 'Щодня на FINN.no, NAV.no та LinkedIn з''являються сотні вакансій. AI читає кожну і порівнює з повним CV, повертаючи score 0-100 з плюсами, мінусами та аурою робочого середовища.', 'Hundreds of jobs appear daily across FINN.no, NAV.no, and LinkedIn. Manually reading each one and objectively assessing fit is physically impossible. Subjectivity, fatigue, and missed opportunities define manual job searching in Norway.', 'Hundrevis av jobber dukker opp daglig på FINN.no, NAV.no og LinkedIn. Å manuelt lese hver enkelt og objektivt vurdere egnethet er fysisk umulig. Subjektivitet, tretthet og tapte muligheter definerer manuell jobbøking i Norge.', 'Щодня на FINN.no, NAV.no та LinkedIn з''являються сотні вакансій. Людина фізично не здатна прочитати кожну й об''єктивно оцінити відповідність. Суб''єктивність, втома та пропущені шанси — реальність ручного пошуку роботи в Норвегії.', 'Built an Edge Function that calls Azure OpenAI GPT-4 with a custom "Vibe & Fit Scanner" prompt. AI receives the full job text + structured CV and returns JSON with score (0-100), analysis (pros/cons), tasks, aura (workplace type), and radar (5-axis evaluation). Token costs are logged to system_logs. Batch analysis of 10+ jobs is delegated to GitHub Actions via repository_dispatch.', 'Bygget en Edge Function som kaller Azure OpenAI GPT-4 med en tilpasset "Vibe & Fit Scanner"-prompt. AI mottar full jobbtekst + strukturert CV og returnerer JSON med poengsum (0-100), analyse (fordeler/ulemper), oppgaver, aura (arbeidsplasstype) og radar (5-akset evaluering). Tokenkostnader logges. Batchanalyse av 10+ jobber delegeres til GitHub Actions.', 'Побудовано Edge Function, яка викликає Azure OpenAI GPT-4 з кастомним промптом "Vibe & Fit Scanner". AI отримує повний текст вакансії + структурований CV і повертає JSON з score (0-100), analysis (pros/cons), tasks, aura та radar (5 осей). Підрахунок токенів логується. Пакетний аналіз 10+ вакансій делегується в GitHub Actions через repository_dispatch.', 'Every job automatically receives an objective assessment in seconds. Hot jobs (score >= 50) instantly appear in Telegram with action buttons. The candidate only spends time on relevant positions, saving hours of daily scrolling.', 'Hver jobb får automatisk en objektiv vurdering på sekunder. Hot jobs (poengsum >= 50) vises umiddelbart i Telegram med handlingsknapper. Kandidaten bruker kun tid på relevante stillinger.', 'Кожна вакансія автоматично отримує об''єктивну оцінку за секунди. Hot jobs (score >= 50) миттєво потрапляють в Telegram з кнопками дій. Кандидат витрачає час лише на релевантні позиції.', '{"Azure OpenAI GPT-4","Deno Edge Functions","Supabase PostgreSQL","GitHub Actions"}', '{"#AzureOpenAI","#GPT4","#JobSearch","#AIRecruiting","#Norway","#MachineLearning"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j02', 'jobbot', 'ai_automation', 'AI Cover Letter in 8 Seconds — in Norwegian', 'AI-søknad på 8 sekunder — på norsk', 'Мотиваційний лист за 8 секунд — норвезькою', 'Writing a søknad (cover letter) in Norwegian is painful for foreigners. GPT-4 generates a personalized letter in bokmål with a Ukrainian translation for review, taking 8 seconds instead of 60 minutes.', 'Å skrive en søknad på norsk er smertefullt for utlendinger. GPT-4 genererer et personlig brev på bokmål med ukrainsk oversettelse for gjennomgang, på 8 sekunder i stedet for 60 minutter.', 'Написати søknad норвезькою — біль для іноземця. GPT-4 генерує персоналізований лист мовою bokmål з українським перекладом для перевірки, за 8 секунд замість 60 хвилин.', 'Writing a søknad in Norwegian requires knowledge of cultural nuances, formal bokmål style, and letter structure. One quality søknad takes 40-60 minutes. When applying to 10+ positions per week, it becomes a second job.', 'Å skrive en søknad på norsk krever kunnskap om kulturelle nyanser, formell bokmål-stil og brevstruktur. Én kvalitetsøknad tar 40-60 minutter. Når man søker på 10+ stillinger per uke, blir det en andre jobb.', 'Написати søknad норвезькою потребує знання культурних нюансів, формального стилю bokmål та структури листа. Один якісний søknad забирає 40-60 хвилин. При 10+ вакансіях на тиждень це стає другою роботою.', 'Edge Function generate_application takes job_id + user_id, pulls the full job listing and active CV profile from the database. GPT-4 generates cover_letter_no (Norwegian) and cover_letter_uk (Ukrainian) with clear structure: greeting, why this company, experience, motivation, closing. Each generation is saved with cost tracking.', 'Edge Function generate_application tar job_id + user_id, henter full jobbannonse og aktiv CV-profil fra databasen. GPT-4 genererer cover_letter_no (norsk) og cover_letter_uk (ukrainsk) med klar struktur. Hver generering lagres med kostnadssporing.', 'Edge Function generate_application бере job_id + user_id, витягує повну вакансію та активний CV профіль з БД. GPT-4 генерує cover_letter_no (норвезькою) та cover_letter_uk (українською) з чіткою структурою. Кожна генерація зберігається з cost tracking.', 'From button press to finished søknad in 8 seconds. The candidate reviews the Ukrainian version, edits if needed, approves, and the letter is ready to send. Productivity jumped from 2 letters per day to 15+.', 'Fra knappetrykk til ferdig søknad på 8 sekunder. Kandidaten gjennomgår den ukrainske versjonen, redigerer ved behov, godkjenner, og brevet er klart. Produktiviteten økte fra 2 brev per dag til 15+.', 'Від натискання кнопки до готового søknad — 8 секунд. Кандидат переглядає українську версію, редагує, натискає "Approve" — лист готовий. Продуктивність зросла з 2 листів на день до 15+.', '{"Azure OpenAI GPT-4","Deno Edge Functions","Supabase","TypeScript"}', '{"#CoverLetter","#Norwegian","#AIWriting","#Søknad","#Bokmål","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j03', 'jobbot', 'ai_automation', 'PDF Upload — structured profile in 12 seconds', 'PDF-opplasting — strukturert profil på 12 sekunder', 'Завантаж PDF — отримай структурований профіль', 'Manually filling 9 CV sections takes 30+ minutes. AI reads a PDF resume and extracts all data into structured JSON with personal info, work experience, education, skills, and languages.', 'Manuell utfylling av 9 CV-seksjoner tar 30+ minutter. AI leser en PDF-CV og trekker ut alle data til strukturert JSON med personlig informasjon, arbeidserfaring, utdanning, ferdigheter og språk.', 'Ручне заповнення 9 секцій CV займає 30+ хвилин. AI читає PDF-резюме та витягує всі дані в структурований JSON з персональною інформацією, досвідом, освітою, навичками та мовами.', 'Every candidate has a PDF resume, but the system needs structured data for auto-filling forms and generating cover letters. Manually filling 9 profile sections takes 30+ minutes and nobody wants to do it.', 'Hver kandidat har en PDF-CV, men systemet trenger strukturerte data for automatisk utfylling av skjemaer og generering av søknader. Manuell utfylling av 9 profilseksjoner tar 30+ minutter.', 'Кожен кандидат має резюме в PDF, але системі потрібні структуровані дані для автозаповнення форм та генерації søknad. Ручне заповнення 9 секцій профілю займає 30+ хвилин.', 'Edge Function analyze_profile accepts a PDF via Storage, extracts text, and sends it to GPT-4 for structuring. Returns JSON with 9 sections: personalInfo, workExperience, education, skills, languages, certifications, summary, references, additionalInfo. Result is stored as JSONB with versioning support.', 'Edge Function analyze_profile mottar en PDF via Storage, trekker ut tekst og sender den til GPT-4 for strukturering. Returnerer JSON med 9 seksjoner. Resultatet lagres som JSONB med versjoneringsstøtte.', 'Edge Function analyze_profile приймає PDF через Storage, витягує текст і відправляє в GPT-4 для структуризації. Повертає JSON з 9 секціями: personalInfo, workExperience, education, skills, languages, certifications, summary, references, additionalInfo. Зберігається як JSONB з версіонуванням.', '30 minutes of manual work became a single 12-second upload. The structured profile is immediately ready for auto-filling forms on any recruiting platform.', '30 minutter med manuelt arbeid ble til én 12-sekunders opplasting. Den strukturerte profilen er umiddelbart klar for automatisk utfylling på enhver rekrutteringsplattform.', '30 хвилин ручної роботи перетворились на один upload за 12 секунд. Структурований профіль одразу готовий для автозаповнення форм на будь-якій платформі.', '{"Azure OpenAI GPT-4","Supabase Storage","Deno Edge Functions","PDF parsing"}', '{"#PDF","#ResumeParser","#AI","#StructuredData","#CVProfile","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j04', 'jobbot', 'ai_automation', 'MetaClaw — the machine that learns from its mistakes', 'MetaClaw — maskinen som lærer av sine feil', 'Машина, що вчиться на своїх помилках', 'Skyvern fills forms on recruiting sites, but each site is unique. After every attempt, AI analyzes the full step log and generates a "skill guide" that improves future attempts on the same platform.', 'Skyvern fyller ut skjemaer på rekrutteringssider, men hver side er unik. Etter hvert forsøk analyserer AI hele stegloggen og genererer en "skill guide" som forbedrer fremtidige forsøk.', 'Skyvern заповнює форми на рекрутингових сайтах, але кожен сайт унікальний. Після кожної спроби AI аналізує повний лог кроків і генерує "skill guide", що покращує наступні спроби на тій же платформі.', 'Skyvern fills recruiting forms, but each site is unique. The first attempt often fails due to unknown fields, popups, or non-standard uploads. The next attempt on the same site repeats the same mistakes — the system does not learn.', 'Skyvern fyller ut rekrutteringsskjemaer, men hver side er unik. Første forsøk mislykkes ofte. Neste forsøk på samme side gjentar de samme feilene — systemet lærer ikke.', 'Skyvern заповнює форми на рекрутингових сайтах, але кожен сайт унікальний. Перша спроба часто провалюється через невідомі поля, popup чи нестандартний upload. Наступна спроба повторює ті ж помилки — система не вчиться.', 'After each Skyvern task, extract_memory_from_task() analyzes all steps, collected fields, and navigation flow. Then generate_skill_from_memory() sends this to Gemini 2.5 Flash to generate a concise SKILL GUIDE. The result is stored in site_form_memory and injected into every future navigation goal as a "PREVIOUS EXPERIENCE" section. Domains are normalized so experience transfers across sites of the same platform.', 'Etter hver Skyvern-oppgave analyserer extract_memory_from_task() alle steg og navigasjonsflyt. Deretter sender generate_skill_from_memory() dette til Gemini 2.5 Flash for å generere en SKILL GUIDE. Resultatet lagres i site_form_memory og injiseres i fremtidige navigasjonsmål. Domener normaliseres slik at erfaring overføres mellom sider på samme plattform.', 'Після кожної Skyvern задачі extract_memory_from_task() аналізує всі кроки та навігаційний потік. Далі generate_skill_from_memory() відправляє дані в Gemini 2.5 Flash для генерації SKILL GUIDE. Результат зберігається в site_form_memory і вставляється в кожну наступну навігаційну мету як секція "PREVIOUS EXPERIENCE". Домени нормалізуються для переносу досвіду між сайтами однієї платформи.', 'The system improves after every iteration. First attempt on Webcruiter: 60% success, third attempt: 90%+. Domain normalization means experience from one site transfers to all sites on the same platform.', 'Systemet forbedres etter hver iterasjon. Første forsøk på Webcruiter: 60% suksess, tredje forsøk: 90%+. Domenormalisering betyr at erfaring fra én side overføres til alle sider på samme plattform.', 'Система покращується після кожної ітерації. Перша спроба на Webcruiter — 60% успіху, третя — 90%+. Нормалізація доменів означає, що досвід з одного сайту переноситься на всі сайти тієї ж платформи.', '{"Gemini 2.5 Flash","Python","Skyvern API","Supabase PostgreSQL","JSONB"}', '{"#MetaClaw","#SelfLearning","#AIAgent","#WebAutomation","#FormMemory","#Gemini"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j05', 'jobbot', 'ai_automation', 'Job Aura — feel the vibe before the interview', 'Jobbaura — føl vibben før intervjuet', 'Аура вакансії — відчуй вайб до інтерв''ю', 'A relevance score shows if YOU fit the job, but does the JOB fit you? AI reads hidden signals in job text and classifies workplace "aura" into 6 types with a 5-axis radar chart.', 'En relevanspoengsum viser om DU passer til jobben, men passer JOBBEN til deg? AI leser skjulte signaler i jobbteksten og klassifiserer arbeidsplassens "aura" i 6 typer med et 5-akset radardiagram.', 'Score релевантності показує, чи підходиш ТИ вакансії, але чи підходить ВАКАНСІЯ тобі? AI читає приховані сигнали в тексті і класифікує "ауру" робочого середовища в 6 типів з 5-осьовим radar chart.', 'The relevance score shows if you fit the job, but not if the job fits you. Toxic environment, grind without prospects, or growth company with stock options — impossible to tell from dry text until you work there a month.', 'Relevanspoengsum viser om du passer til jobben, men ikke om jobben passer til deg. Giftig miljø, grind uten utsikter, eller vekstselskap med aksjeopsjoner — umulig å si fra tørr tekst.', 'Score релевантності показує, чи підходиш ТИ вакансії. Але чи підходить ВАКАНСІЯ тобі? Токсичне середовище, грайнд без перспектив або компанія зростання зі stock options — неможливо зрозуміти з сухого тексту.', 'Added an Aura system to the job-analyzer prompt with 6 types: Toxic (high turnover), Growth (stock options, learning budget), Balanced (work-life balance), Chill (remote, flexible), Grind (overtime culture), Neutral (standard corporate). Each aura has a hex color, tags, and explanation. A parallel radar chart has 5 axes: tech_stack fit, soft_skills fit, culture match, salary_potential, career_growth (0-100 each).', 'Lagt til et Aura-system i job-analyzer-prompten med 6 typer: Toxic, Growth, Balanced, Chill, Grind, Neutral. Hver aura har hex-farge, tagger og forklaring. Et parallelt radardiagram har 5 akser: tech_stack fit, soft_skills fit, culture match, salary_potential, career_growth (0-100 hver).', 'В промпт job-analyzer додано Aura-систему з 6 типів: Toxic, Growth, Balanced, Chill, Grind, Neutral. Кожна аура має hex-колір, теги та пояснення. Паралельний Radar chart з 5 осей: tech_stack fit, soft_skills fit, culture match, salary_potential, career_growth (кожен 0-100).', 'Candidates see not just "78% match" but also "Growth aura — Stock Options, Learning Budget, Fast Track." The radar chart visually shows strengths and weaknesses of the match. Informed decisions in 3 seconds instead of 15 minutes of reading.', 'Kandidater ser ikke bare "78% match" men også "Growth aura — Stock Options, Learning Budget, Fast Track." Radardiagrammet viser visuelt styrker og svakheter. Informerte beslutninger på 3 sekunder.', 'Кандидат бачить не лише "підходжу на 78%", а й "Growth aura — Stock Options, Learning Budget, Fast Track". Radar chart візуально показує сильні та слабкі сторони. Рішення за 3 секунди замість 15 хвилин читання.', '{"Azure OpenAI GPT-4","Radar Chart (Recharts)","React","JSONB","Deno"}', '{"#AuraScore","#RadarChart","#JobFit","#WorkplaceCulture","#AI","#VibeCheck"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j06', 'jobbot', 'bot_scraping', 'One Click — form filled on 10+ platforms', 'Ett klikk — skjema utfylt på 10+ plattformer', 'Один клік — і форма заповнена', 'Norwegian recruiting platforms are chaos: multi-step wizards, drag-and-drop uploads, CAPTCHA chains. Skyvern AI-powered browser automation fills forms on 10+ platforms in 2-5 minutes with zero user involvement.', 'Norske rekrutteringsplattformer er kaos: flerstegsveivisere, drag-and-drop-opplasting, CAPTCHA-kjeder. Skyven AI-drevet nettleserautomatisering fyller ut skjemaer på 10+ plattformer på 2-5 minutter uten brukerinvolvering.', 'Норвезькі рекрутингові платформи — хаос форм: multi-step wizards, drag-and-drop upload, CAPTCHA. Skyvern AI-автоматизація браузера заповнює форми на 10+ платформах за 2-5 хвилин без участі юзера.', 'Norwegian recruiting platforms are chaos: Webcruiter has 5-step forms with drag-and-drop, Easycruit requires registration before applying, Teamtailor hides fields behind tabs. Filling one form manually takes 10-15 minutes.', 'Norske rekrutteringsplattformer er kaos: Webcruiter har 5-trinns skjemaer med drag-and-drop, Easycruit krever registrering. Å fylle ut ett skjema manuelt tar 10-15 minutter.', 'Норвезькі рекрутингові платформи — це хаос форм. Webcruiter має 5-крокову форму з drag-and-drop, Easycruit вимагає реєстрацію, Teamtailor ховає поля за табами. Заповнити одну форму вручну — 10-15 хвилин.', 'Python worker auto_apply.py (4700+ lines) runs as a daemon, polling for applications with status "sending" every 10 seconds. For each application: extracts CV profile, forms a navigation goal for the specific site, launches Skyvern task via REST API, monitors status, handles results. Supports 10+ platforms: Webcruiter, Easycruit, Teamtailor, Jobylon, Lever, Recman, ReachMee, Varbi, HRManager, SuccessFactors, JobbNorge.', 'Python-worker auto_apply.py (4700+ linjer) kjører som en daemon og sjekker applikasjoner med status "sending" hvert 10. sekund. For hver applikasjon: trekker ut CV-profil, danner navigasjonsmål, starter Skyvern-oppgave via REST API. Støtter 10+ plattformer.', 'Python worker auto_apply.py (4700+ рядків) працює як демон, шукає заявки зі статусом "sending" кожні 10 секунд. Для кожної: витягує CV профіль, формує navigation goal для конкретного сайту, запускає Skyvern task через REST API. Підтримка 10+ платформ.', 'Candidate clicks "Send" in Telegram or Dashboard, and within 2-5 minutes the form is filled automatically on any of 10+ platforms. Average submission time dropped from 15 minutes to 3 minutes with zero user involvement.', 'Kandidaten klikker "Send" i Telegram eller Dashboard, og innen 2-5 minutter er skjemaet fylt ut automatisk. Gjennomsnittlig innsendingstid falt fra 15 til 3 minutter uten brukerinvolvering.', 'Кандидат натискає "Send" в Telegram або Dashboard — за 2-5 хвилин форма заповнена на будь-якій з 10+ платформ. Середній час подачі впав з 15 до 3 хвилин при нульовій участі.', '{"Skyvern Docker","Python asyncio","httpx","Supabase","REST API"}', '{"#BrowserAutomation","#Skyvern","#FormFilling","#WebAutomation","#Python","#Docker"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j07', 'jobbot', 'bot_scraping', '2FA via Telegram — when the bot becomes your fingers', '2FA via Telegram — når boten blir fingrene dine', '2FA через Telegram — коли бот стає твоїми пальцями', 'FINN.no requires 2FA for quick applications. Skyvern fills the form but hits the SMS code wall. A webhook bridge between Skyvern and Telegram lets the user send the code via chat, completing the full cycle in 30 seconds.', 'FINN.no krever 2FA for hurtige søknader. Skyvern fyller ut skjemaet men stopper ved SMS-koden. En webhook-bro mellom Skyvern og Telegram lar brukeren sende koden via chat på 30 sekunder.', 'FINN.no вимагає 2FA для швидкої подачі. Skyvern заповнює форму, але зупиняється на SMS-коді. Webhook-міст між Skyvern і Telegram дозволяє юзеру надіслати код через чат, завершуючи цикл за 30 секунд.', 'FINN.no, Norway''s largest job site, requires 2FA for "Enkel Søknad" (quick application). Skyvern fills the form, hits "Enter your SMS code," and freezes. Automation stops at the most critical step because 2FA requires a human.', 'FINN.no, Norges største jobbside, krever 2FA for "Enkel Søknad". Skyvern fyller ut skjemaet, treffer "Skriv inn SMS-kode" og fryser. Automatiseringen stopper på det viktigste trinnet.', 'FINN.no — найбільший сайт вакансій Норвегії — вимагає 2FA для "Enkel Søknad". Skyvern заповнює форму, натикається на "Введіть код з SMS" — і зависає. Автоматизація зупиняється на найважливішому кроці.', 'When Skyvern hits 2FA, the worker creates a record in finn_auth_requests with status code_requested and sends a Telegram message asking for the 6-digit code. The user replies with the code. The finn-2fa-webhook Edge Function polls every 10 seconds and returns the code to Skyvern when available, adapted for Skyvern''s 30-second HTTP timeout.', 'Når Skyvern treffer 2FA, oppretter workeren en post i finn_auth_requests og sender en Telegram-melding som ber om koden. Brukeren svarer med koden. finn-2fa-webhook Edge Function poller hvert 10. sekund og returnerer koden til Skyvern.', 'Коли Skyvern натикається на 2FA, worker створює запис у finn_auth_requests і відправляє Telegram-повідомлення з проханням коду. Юзер відповідає кодом. Edge Function finn-2fa-webhook полює кожні 10 секунд і повертає код Skyvern''у, адаптований під 30-секундний HTTP timeout.', 'The full "form, 2FA, submit" cycle takes about 30 seconds of human time: receive SMS, send digits in Telegram. Automation handles the rest. FINN Enkel Søknad is now fully automated.', 'Hele syklusen "skjema, 2FA, send" tar ca. 30 sekunder menneskelig tid: motta SMS, sende siffer i Telegram. FINN Enkel Søknad er nå fullt automatisert.', 'Повний цикл "форма, 2FA, відправка" займає ~30 секунд людського часу: отримати SMS, відправити цифри в Telegram. Решту робить автоматика. FINN Enkel Søknad повністю автоматизований.', '{"Skyvern","Telegram Bot API","Deno Edge Functions","Supabase","Python"}', '{"#2FA","#TelegramBot","#FINN","#Authentication","#WebhookBridge","#Norway"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j08', 'jobbot', 'bot_scraping', 'Auto-Registration — site accounts created automatically', 'Autoregistrering — nettstedskontoer opprettet automatisk', 'Реєстрація на сайтах — теж автоматична', 'Many recruiting platforms require registration before applying. A separate Python daemon handles registration: checks for existing accounts, generates secure passwords, asks unknown questions via Telegram, and saves credentials.', 'Mange rekrutteringsplattformer krever registrering før søking. En separat Python-daemon håndterer registrering: sjekker eksisterende kontoer, genererer sikre passord, spør ukjente spørsmål via Telegram og lagrer legitimasjon.', 'Багато рекрутингових платформ вимагають реєстрацію перед подачею. Окремий Python-демон обробляє реєстрацію: перевіряє існуючі акаунти, генерує безпечні паролі, питає незнайомі запитання через Telegram і зберігає credentials.', 'Many platforms (Webcruiter, Easycruit, JobbNorge) require registration before applying. Each site has different forms, different fields, different password requirements. Users must register on 5-7 sites manually before starting to apply.', 'Mange plattformer krever registrering før søking. Hver side har ulike skjemaer, felt og passordkrav. Brukere må registrere seg på 5-7 sider manuelt før de kan søke.', 'Багато платформ вимагають реєстрацію перед подачею. Кожен сайт — окрема форма, інші поля, інші вимоги до пароля. Юзер повинен зареєструватися на 5-7 сайтах вручну.', 'register_site.py is a separate Python daemon for registration. Generates secure 16-character passwords. Checks site_credentials in the DB to avoid duplicates. When Skyvern encounters an unknown field during registration, it creates a record in registration_questions, and the bot asks the user via Telegram (text or inline buttons). Successful credentials are saved with per-user isolation. Question timeout: 5 minutes.', 'register_site.py er en separat Python-daemon for registrering. Genererer sikre 16-tegns passord. Sjekker site_credentials for å unngå duplikater. Ved ukjente felt spør boten brukeren via Telegram. Vellykkede legitimasjoner lagres med brukersisolering.', 'register_site.py — окремий Python-демон для реєстрації. Генерує безпечні 16-символьні паролі. Перевіряє site_credentials в БД. Коли Skyvern зустрічає незнайоме поле — бот питає юзера через Telegram. Успішні credentials зберігаються з per-user ізоляцією. Timeout: 5 хвилин.', 'Instead of manual registration on 7 sites (30+ minutes), the user answers 2-3 questions in Telegram in 2 minutes. Credentials are saved permanently and automatically used for future applications.', 'I stedet for manuell registrering på 7 sider (30+ minutter), svarer brukeren på 2-3 spørsmål i Telegram på 2 minutter. Legitimasjoner lagres permanent.', 'Замість ручної реєстрації на 7 сайтах (30+ хвилин), юзер відповідає на 2-3 питання в Telegram за 2 хвилини. Credentials зберігаються назавжди і підставляються автоматично.', '{"Python","Skyvern Docker","Telegram Bot API","Supabase","secrets module"}', '{"#AutoRegistration","#CredentialManagement","#Skyvern","#Telegram","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j09', 'jobbot', 'bot_scraping', 'Login Failed? No problem — bot handles it', 'Innlogging mislyktes? Ikke noe problem — boten ordner det', 'Невірний пароль? Не проблема — бот розрулить', 'When Skyvern encounters a login failure, the system detects it in real time and asks the user via Telegram: update password or register from scratch. Auto-recovery with backoff retries resolves auth errors in 30 seconds.', 'Når Skyvern møter innloggingsfeil, oppdager systemet det i sanntid og spør brukeren via Telegram: oppdater passord eller registrer på nytt. Auto-gjenoppretting løser auth-feil på 30 sekunder.', 'Коли Skyvern натикається на помилку логіну, система виявляє це в реальному часі та питає юзера через Telegram: оновити пароль чи зареєструватися з нуля. Автовідновлення з backoff retry вирішує auth-помилки за 30 секунд.', 'Skyvern logs into a recruiting platform, but the password changed or was wrong. The task fails with login_failed error. The user finds out 30 minutes later when checking logs. Meanwhile, the application deadline may have passed.', 'Skyvern logger inn på en rekrutteringsplattform, men passordet er endret eller feil. Oppgaven feiler med login_failed. Brukeren finner ut av det 30 minutter senere.', 'Skyvern логіниться на платформу, але пароль змінився або був неправильним. Задача падає з помилкою login_failed. Юзер дізнається через 30 хвилин, а дедлайн міг пройти.', 'Added error code mapping with LLM evaluation to auto_apply.py. On login_failed, the worker identifies the domain and sends a Telegram message with inline buttons: "Update password" or "Register from scratch." Choosing "Yes" triggers a password update; choosing "No" triggers the registration flow. The entire retry chain is automatic with backoff [5s, 10s] and max 3 attempts.', 'Lagt til error code mapping i auto_apply.py. Ved login_failed sender workeren en Telegram-melding med knapper: "Oppdater passord" eller "Registrer på nytt." Hele gjenforsøkskjeden er automatisk med backoff og maks 3 forsøk.', 'В auto_apply.py додано error code mapping з LLM evaluation. При login_failed worker відправляє Telegram-повідомлення з кнопками: "Оновити пароль" або "Зареєструватись". Весь retry-ланцюжок автоматичний з backoff [5s, 10s] та максимум 3 спроби.', 'An auth error that previously blocked applications for an hour is now resolved in 30 seconds via Telegram. Auto-recovery plus registration from scratch without leaving the chat.', 'En auth-feil som tidligere blokkerte søknader i en time, løses nå på 30 sekunder via Telegram. Auto-gjenoppretting pluss registrering uten å forlate chatten.', 'Помилка авторизації, яка раніше блокувала подачу на годину, тепер вирішується за 30 секунд через Telegram. Автовідновлення + реєстрація з нуля без виходу з чату.', '{"Python","Skyvern","Telegram Bot API","Supabase","error code mapping"}', '{"#ErrorRecovery","#AutoRetry","#Login","#TelegramBot","#Resilience","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j10', 'jobbot', 'bot_scraping', 'Form Memory — every attempt makes the system smarter', 'Skjemahukommelse — hvert forsøk gjør systemet smartere', 'Пам''ять форм — кожна спроба робить систему розумнішою', 'A knowledge base about each recruiting platform: steps count, upload methods, rich text editors. Domains are normalized so experience from company1.webcruiter.no transfers to all Webcruiter sites. Confidence-based step optimization reduces costs by 40%.', 'En kunnskapsbase om hver rekrutteringsplattform: antall steg, opplastingsmetoder, rik tekst-editorer. Domener normaliseres slik at erfaring overføres mellom alle sider på samme plattform. Tillitsbasert stegoptimalisering reduserer kostnader med 40%.', 'База знань про кожну рекрутингову платформу: кількість кроків, методи upload, rich text editors. Домени нормалізуються — досвід з company1.webcruiter.no переноситься на всі Webcruiter сайти. Confidence-based оптимізація зменшує витрати на 40%.', 'Skyvern fills a form on webcruiter.no. First attempt fails due to non-standard file upload. Second — rich text editor. Third — success. But this experience is not saved. On the next Webcruiter site, everything starts from zero.', 'Skyvern fyller ut et skjema på webcruiter.no. Første forsøk mislykkes. Andre også. Tredje lykkes. Men denne erfaringen lagres ikke. På neste Webcruiter-side starter alt fra null.', 'Skyvern заповнює форму на webcruiter.no. Перша спроба провалюється через нестандартний file upload. Друга — rich text editor. Третя — успіх. Але досвід нікуди не зберігається — на наступному webcruiter-сайті все з нуля.', 'Table site_form_memory stores a JSON record after each attempt: form_fields, navigation_flow, total_steps, upload methods, rich text methods, success/failure counts. normalize_domain_for_memory() reduces 12+ known platforms to base domains. get_form_memory() returns the last successful record. Confidence-based _calc_max_steps() allocates fewer steps as success count grows, optimizing speed and cost.', 'Tabell site_form_memory lagrer JSON-post etter hvert forsøk med feltdata, navigasjonsflyt og suksess/feil-tellere. normalize_domain_for_memory() reduserer 12+ plattformer til basedomener. Tillitsbasert _calc_max_steps() tildeler færre steg når suksesstallet vokser.', 'Таблиця site_form_memory зберігає JSON-запис після кожної спроби: form_fields, navigation_flow, total_steps, методи upload, success/failure counts. normalize_domain_for_memory() зводить 12+ платформ до базових доменів. Confidence-based _calc_max_steps() зменшує кількість кроків з кожним успіхом.', 'Webcruiter: first attempt 25 steps, fifth 12 steps. Success rate grew from 60% to 92% thanks to accumulated experience. Skyvern token costs decreased by 40%.', 'Webcruiter: første forsøk 25 steg, femte 12 steg. Suksessrate økte fra 60% til 92%. Skyvern-tokenkostnader redusert med 40%.', 'Webcruiter: перша спроба — 25 кроків, п''ята — 12 кроків. Success rate зріс з 60% до 92%. Вартість Skyvern-токенів знизилась на 40%.', '{"Python","Supabase PostgreSQL","JSONB","Skyvern API"}', '{"#FormMemory","#PatternRecognition","#DomainNormalization","#Optimization","#Database"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j11', 'jobbot', 'bot_scraping', '7 platforms — 7 automation languages', '7 plattformer — 7 automatiseringspråk', '7 платформ — 7 мов автоматизації', 'Each Norwegian recruiting platform is its own universe. A module with 15+ template functions generates platform-specific navigation goals for Skyvern, with detect_site_type() recognizing 16+ platforms by domain.', 'Hver norsk rekrutteringsplattform er sitt eget univers. En modul med 15+ malfunksjoner genererer plattformspesifikke navigasjonsmål for Skyvern, med detect_site_type() som gjenkjenner 16+ plattformer etter domene.', 'Кожна норвезька рекрутингова платформа — це окремий всесвіт. Модуль з 15+ функціями-шаблонами генерує платформо-специфічні navigation goals для Skyvern, з detect_site_type() що розпізнає 16+ платформ за доменом.', 'Each Norwegian recruiting platform is a separate universe. Webcruiter has a multi-step wizard with mandatory CV upload. Easycruit starts with a popup cookie banner. Teamtailor hides the form behind a button. One generic script does not work.', 'Hver norsk rekrutteringsplattform er et eget univers. Webcruiter har flerstegsveiviser, Easycruit starter med cookie-popup, Teamtailor skjuler skjemaet bak en knapp. Ett generisk skript fungerer ikke.', 'Кожна рекрутингова платформа — це окремий всесвіт. Webcruiter має multi-step wizard з CV upload. Easycruit починає з cookie-popup. Teamtailor ховає форму за кнопкою. Один generic скрипт не працює.', 'navigation_goals.py contains 15+ template functions: _webcruiter_application(), _easycruit_application(), _teamtailor_application(), _successfactors_application(), _jobbnorge_application(), etc. Each generates a text instruction with specific rules like "DO NOT use drag-and-drop" or "Accept cookies FIRST." detect_site_type() recognizes 16+ platforms by domain. build_memory_section() adds previous experience from site_form_memory.', 'navigation_goals.py inneholder 15+ malfunksjoner for hver plattform, hver med spesifikke regler. detect_site_type() gjenkjenner 16+ plattformer etter domene. build_memory_section() legger til tidligere erfaring fra site_form_memory.', 'navigation_goals.py — модуль з 15+ функціями-шаблонами для кожної платформи з конкретними правилами. detect_site_type() розпізнає 16+ платформ за доменом. build_memory_section() додає попередній досвід з site_form_memory.', 'Instead of one generic "fill the form," 7 personalized scenarios adapted to each platform''s specifics. Success rate on supported platforms: 85%+. Adding a new platform takes 30 minutes of development.', 'I stedet for ett generisk "fyll ut skjemaet" — 7 personaliserte scenarier tilpasset hver plattform. Suksessrate på støttede plattformer: 85%+. Å legge til en ny plattform tar 30 minutter.', 'Замість одного "заповни форму" — 7 персоналізованих сценаріїв, адаптованих до кожної платформи. Success rate на підтримуваних платформах — 85%+. Нова платформа — 30 хвилин розробки.', '{"Python","Skyvern","Pattern matching","Template system"}', '{"#NavigationGoals","#PlatformSpecific","#Webcruiter","#Easycruit","#Teamtailor","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j12', 'jobbot', 'bot_scraping', 'The slider that broke all automation', 'Slideren som knekte all automatisering', 'Слайдер, який зламав всю автоматизацію', 'Some recruiting forms use slider inputs for experience years or salary. Drag-and-drop fails in headless Chrome. A patched Skyvern handler with DataTransfer drop fallback fixes the entire category of forms.', 'Noen rekrutteringsskjemaer bruker slider-input for erfaringsår eller lønn. Drag-and-drop feiler i headless Chrome. En patchet Skyvern-handler med DataTransfer drop-fallback løser hele kategorien.', 'Деякі рекрутингові форми використовують slider для досвіду чи зарплати. Drag-and-drop не працює в headless Chrome. Патч Skyvern handler з DataTransfer drop fallback фіксить цілу категорію форм.', 'Some recruiting forms use slider/range inputs for "Years of experience" or "Desired salary." Skyvern tries drag-and-drop — and fails. Browser drag events do not work reliably in headless Chrome. One form with one slider blocks the entire application.', 'Noen skjemaer bruker slider/range-input for "År med erfaring" eller "Ønsket lønn." Skyvern prøver drag-and-drop — og feiler. Étt skjema med én slider blokkerer hele søknaden.', 'Деякі форми використовують slider/range input для "Скільки років досвіду?" або "Бажана зарплата". Skyvern намагається drag-and-drop — і провалюється. Один слайдер блокує всю подачу.', 'Added special instructions to navigation goals: "For slider/range inputs: DO NOT try to drag. Click the slider to focus, use input_text with the numeric value, fallback to JavaScript element.value." Also patched the Skyvern handler_patched.py with DataTransfer drop fallback, mounted via docker-compose volume.', 'Lagt til spesielle instruksjoner i navigasjonsmål for slidere. Patchet Skyvern handler_patched.py med DataTransfer drop-fallback, montert via docker-compose volume.', 'В navigation goals додано інструкцію для слайдерів: "Не drag-and-drop, а click + input_text або JavaScript element.value." Також пропатчено handler_patched.py з DataTransfer drop fallback через docker-compose volume mount.', 'Forms with sliders that always failed now complete on the first attempt. One patched file unblocked an entire category of forms.', 'Skjemaer med slidere som alltid feilet, fullføres nå på første forsøk. Én patchet fil låste opp en hel kategori av skjemaer.', 'Форми зі слайдерами, що раніше завжди провалювались, тепер заповнюються з першої спроби. Патч одного файлу розблокував цілу категорію форм.', '{"Skyvern","Docker compose volume mount","Python","JavaScript injection"}', '{"#SliderFix","#DragAndDrop","#Headless","#Docker","#BrowserHack","#Workaround"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j13', 'jobbot', 'bot_scraping', '5 patterns for one finnkode', '5 mønstre for én finnkode', '5 паттернів для одного finnkode', 'FINN.no has dozens of URL variations for one job listing. A cascading regex system with 5 patterns achieves 100% extraction rate on 2000+ test URLs, plus deadline parsing from 5 date formats.', 'FINN.no har dusinvis av URL-variasjoner for én jobbannonse. Et cascading regex-system med 5 mønstre oppnår 100% uttrekksrate på 2000+ test-URLer, pluss fristparsing fra 5 datoformater.', 'FINN.no має десятки варіацій URL для однієї вакансії. Cascading regex-система з 5 паттернами досягає 100% extraction rate на 2000+ тестових URL, плюс парсинг дедлайнів з 5 форматів дат.', 'FINN.no has dozens of URL variations for one job: /job/123, /job/fulltime/123, /?finnkode=123, /ad/123.html. The finnkode is the key for building the direct application URL. If the parser can''t extract it, automated application is impossible.', 'FINN.no har dusinvis av URL-variasjoner for én jobb. Finnkode er nøkkelen for å bygge direkte søknads-URL. Hvis parseren ikke kan trekke den ut, er automatisert søking umulig.', 'FINN.no має десятки варіацій URL для однієї вакансії. Finnkode — це ключ для побудови прямого URL подачі. Якщо парсер не витягне його — автоматична подача неможлива.', 'Implemented extractFinnkode() with 5 regex patterns in priority order: ?finnkode=, /job/digits, /ad/digits, /digits at end, /job/slug/digits. HTML is parsed via Cheerio. Deadlines are extracted from meta tags, JSON-LD, and page text in 5 formats. Critical URL format for applications: finn.no/job/apply?adId=XXXXX (NOT /job/apply/XXXXX which returns 404).', 'Implementert extractFinnkode() med 5 regex-mønstre i prioritetsrekkefølge. HTML parses via Cheerio. Frister trekkes ut fra metatagger, JSON-LD og sidetekst i 5 formater. Kritisk URL-format: finn.no/job/apply?adId=XXXXX.', 'Реалізовано extractFinnkode() з 5 regex-паттернами в порядку пріоритету. HTML парситься через Cheerio. Дедлайни витягуються з мета-тегів, JSON-LD та тексту в 5 форматах. Критичний формат URL для подачі: finn.no/job/apply?adId=XXXXX.', '100% finnkode extraction rate on 2000+ test URLs. Zero lost jobs due to inability to extract the ID. Correct URL format means zero 404 errors during application.', '100% finnkode-uttrekksrate på 2000+ test-URLer. Null tapte jobber. Korrekt URL-format betyr null 404-feil under søking.', '100% extraction rate finnkode на 2000+ тестових URL. Жодна вакансія не втрачена. Правильний формат URL — нуль 404 помилок при подачі.', '{"Deno","Cheerio","Regex","TypeScript","HTML parsing"}', '{"#WebScraping","#FINN","#Regex","#URLParsing","#DataExtraction","#Norway"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j14', 'jobbot', 'bot_scraping', 'The government API nobody knows about', 'Det offentlige APIet ingen kjenner til', 'Державний API, якого ніхто не знає', 'NAV.no (Arbeidsplassen) is rendered via JavaScript, breaking HTML scrapers monthly. Its public JSON API provides stable structured data without HTML parsing, running 6+ months without a single break.', 'NAV.no (Arbeidsplassen) rendres via JavaScript, noe som bryter HTML-skrapere månedlig. Deres offentlige JSON API gir stabile strukturerte data uten HTML-parsing, kjørt i 6+ måneder uten ett eneste brudd.', 'NAV.no (Arbeidsplassen) рендериться через JavaScript, ламаючи HTML-скрапери щомісяця. Його публічний JSON API дає стабільні структуровані дані без HTML parsing, працюючи 6+ місяців без жодного збою.', 'NAV.no (Arbeidsplassen) is Norway''s government job platform, but HTML scraping is unreliable: the page renders via JavaScript, content is dynamic, structure changes monthly. Classic scraping breaks after every site update.', 'NAV.no (Arbeidsplassen) er Norges offentlige jobbplattform, men HTML-scraping er upålitelig: siden rendres via JavaScript, innholdet er dynamisk, strukturen endres månedlig.', 'NAV.no (Arbeidsplassen) — державна платформа вакансій Норвегії. HTML-скрапінг ненадійний: сторінка рендериться через JavaScript, контент динамічний, структура змінюється щомісяця.', 'Implemented NAV enhancer (nav-enhancer.ts) in the job-scraper Edge Function using the Arbeidsplassen Public API to get structured data: title, company, location, deadline, description, contact info, application URL. The API returns clean JSON without HTML parsing. Fallback to HTML parsing if the API is unavailable.', 'Implementert NAV-enhancer (nav-enhancer.ts) i job-scraper Edge Function ved bruk av Arbeidsplassen Public API for strukturerte data. APIet returnerer ren JSON. Fallback til HTML-parsing hvis APIet er utilgjengelig.', 'Реалізовано NAV enhancer (nav-enhancer.ts) в Edge Function job-scraper з використанням Arbeidsplassen Public API для структурованих даних. API повертає чистий JSON без HTML parsing. Fallback на HTML parsing, якщо API не відповідає.', 'Stable NAV.no scraping for 6+ months without a single break. The FINN HTML scraper needed 4 fixes in the same period. JSON API means reliability and clean structured data without regex.', 'Stabil NAV.no-scraping i 6+ måneder uten ett eneste brudd. FINN HTML-scraperen trengte 4 fikser i samme periode. JSON API betyr pålitelighet.', 'Стабільний скрапінг NAV.no вже 6+ місяців без жодного збою. HTML-скрапер FINN потребував 4 фікси за той же період. JSON API — надійність без regex.', '{"Deno","NAV Public API","JSON","TypeScript","HTTP fetch"}', '{"#NAV","#PublicAPI","#Arbeidsplassen","#GovernmentAPI","#StructuredData","#Norway"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j15', 'jobbot', 'bot_scraping', 'LinkedIn without login — 0% ban risk', 'LinkedIn uten innlogging — 0% utestengelsesrisiko', 'LinkedIn без логіну — 0% ризик бану', 'LinkedIn aggressively fights scraping with account bans and CAPTCHA. Guest view scraping with rate limiting and User-Agent rotation provides 6 months of uninterrupted data collection with zero risk to professional profiles.', 'LinkedIn kjemper aggressivt mot scraping med kontoutestengelser og CAPTCHA. Guest view-scraping med hastighetsbegrensning og User-Agent-rotasjon gir 6 måneders uavbrutt datainnsamling uten risiko.', 'LinkedIn агресивно бореться зі скрапінгом: бани акаунтів, CAPTCHA. Скрапінг guest view з rate limiting та User-Agent rotation дає 6 місяців безперебійного збору даних без ризику для профілю.', 'LinkedIn is essential for IT job search in Norway, but it aggressively fights scraping: account bans, CAPTCHA, rate limiting. Using login credentials for scraping risks losing your professional profile.', 'LinkedIn er essensiell for IT-jobbøk i Norge, men kjemper aggressivt mot scraping: kontoutestengelser, CAPTCHA. Å bruke innlogging for scraping risikerer profesjonell profil.', 'LinkedIn — обов''язкове джерело вакансій для IT в Норвегії. Але LinkedIn агресивно бореться зі скрапінгом: бани, CAPTCHA, rate limiting. Логін для скрапінгу = ризик втратити профіль.', 'Implemented LinkedIn Guest API scraping: requests to public job search with parameters location=Norway and keywords from user settings. Parsing JSON-LD and HTML guest view for job details. Rate limiting: max 50 requests per cycle with randomized 1-3 second delays. User-Agent rotation. Results: up to 1000 jobs per scan cycle.', 'Implementert LinkedIn Guest API-scraping: forespørsler til offentlig jobbsøk. Parsing av JSON-LD og HTML guest view. Hastighetsbegrensning: maks 50 forespørsler per syklus med randomisert forsinkelse. User-Agent-rotasjon.', 'Реалізовано LinkedIn Guest API scraping: запити до публічного пошуку з параметрами location=Norway. Парсинг JSON-LD та HTML guest view. Rate limiting: макс 50 запитів з рандомізованою затримкою. User-Agent rotation. До 1000 вакансій за цикл.', '6 months of uninterrupted LinkedIn scraping without a single ban or CAPTCHA. Zero risk to accounts. Three sources (FINN + NAV + LinkedIn) cover 95%+ of the Norwegian IT job market.', '6 måneder uavbrutt LinkedIn-scraping uten en eneste utestengelse. Null risiko. Tre kilder (FINN + NAV + LinkedIn) dekker 95%+ av det norske IT-jobbmarkedet.', '6 місяців безперебійного скрапінгу LinkedIn без жодного бану. Нуль ризику для акаунту. Три джерела (FINN + NAV + LinkedIn) покривають 95%+ норвезького IT-ринку.', '{"HTTP fetch","JSON-LD parsing","Cheerio","Rate limiting","Deno"}', '{"#LinkedIn","#GuestScraping","#ZeroRisk","#RateLimiting","#JobSearch","#WebScraping"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j16', 'jobbot', 'bot_scraping', 'One job — three sites — zero duplicates', 'Én jobb — tre sider — null duplikater', 'Одна вакансія — три сайти — нуль дублів', 'Companies post the same job on FINN, LinkedIn, and NAV simultaneously. Cross-source deduplication using normalized company names and titles reduces job count by 15-20% and eliminates wasted AI analysis tokens.', 'Selskaper publiserer samme jobb på FINN, LinkedIn og NAV samtidig. Krysskildedeuplisering med normaliserte firmanavn reduserer jobbtall med 15-20% og eliminerer bortkastede AI-analysetokens.', 'Компанії публікують одну вакансію на FINN, LinkedIn та NAV одночасно. Cross-source дедуплікація з нормалізованими назвами компаній зменшує кількість вакансій на 15-20% і економить AI-токени.', 'A company posts the same job on FINN.no, LinkedIn, and NAV.no. The scraper collects all three, and the candidate sees "Software Developer at Telenor" three times. This clutters the job list, breaks statistics, and wastes AI tokens analyzing the same thing thrice.', 'Et selskap publiserer samme jobb på FINN.no, LinkedIn og NAV.no. Skraperen samler alle tre, og kandidaten ser jobben tre ganger. Dette søpler jobblisten og kaster bort AI-tokens.', 'Компанія публікує вакансію одночасно на FINN, LinkedIn та NAV. Скрапер збирає всі три — кандидат бачить одну вакансію тричі. Це засмічує список і витрачає AI-токени на аналіз одного й того ж.', 'Deduplication at insert level: before adding a new job, search the DB by user_id + normalized company + normalized title + location similarity. Normalization: toLowerCase(), trim, removal of legal suffixes (AS, ASA, A/S), removal of special characters. If a match is found, the job is updated with an alternative source URL instead of duplicated.', 'Deduplisering på insert-nivå: før ny jobb legges til, søk i DB etter normalisert firma + tittel + beliggenhet. Normalisering: toLowerCase(), trim, fjerning av juridiske suffikser. Ved treff oppdateres jobben med alternativ kilde-URL.', 'Дедуплікація на рівні insert: перед додаванням нової вакансії — пошук в БД за normalized company + title + location. Нормалізація: toLowerCase(), trim, видалення юридичних суфіксів (AS, ASA). При збігу — оновлення з альтернативним source URL.', 'Deduplication reduced job count by 15-20% with the same search queries. Zero duplicate analyses = AI token savings. Candidates see a clean feed without duplicates.', 'Deduplisering reduserte jobbtallet med 15-20%. Null dobbeltanalyser = AI-tokenbesparelser. Kandidater ser en ren feed uten duplikater.', 'Дедуплікація знизила кількість вакансій на 15-20%. Нуль подвійних аналізів = економія AI-токенів. Кандидат бачить чисту стрічку без дублів.', '{"PostgreSQL","TypeScript","String normalization","Supabase"}', '{"#Deduplication","#DataQuality","#CrossSource","#Normalization","#PostgreSQL"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j17', 'jobbot', 'bot_scraping', 'Shadow DOM — the FINN.no boss we outsmarted', 'Shadow DOM — FINN.no-bossen vi overlisted', 'Shadow DOM — бос FINN.no, якого ми перехитрили', 'FINN.no uses Shadow DOM for the "Enkel Søknad" button, making it invisible to standard parsers. Three-level detection via HTML text search plus direct URL navigation bypasses Shadow DOM entirely.', 'FINN.no bruker Shadow DOM for "Enkel Søknad"-knappen, noe som gjør den usynlig for standard parsere. Tre-nivå deteksjon via HTML-tekstsøk pluss direkte URL-navigasjon omgår Shadow DOM helt.', 'FINN.no використовує Shadow DOM для кнопки "Enkel Søknad", що робить її невидимою для стандартних парсерів. Три рівні детекції через пошук тексту в HTML плюс пряма навігація по URL повністю обходять Shadow DOM.', 'FINN.no uses Shadow DOM for the "Enkel Søknad" (quick apply) button. Standard CSS selectors and XPath cannot see it. Skyvern, Cheerio, and any parser "doesn''t know" the button exists. The system cannot determine the application form type — a critical parameter for automation.', 'FINN.no bruker Shadow DOM for "Enkel Søknad"-knappen. Standard CSS-velgere og XPath kan ikke se den. Systemet kan ikke bestemme skjematypen — en kritisk parameter for automatisering.', 'FINN.no використовує Shadow DOM для кнопки "Enkel Søknad". Стандартний CSS selector чи XPath її не бачить. Система не може визначити тип форми подачі — критичний параметр для автоматизації.', 'Three-level detection: 1) Search for "enkel søknad" text in HTML source (case-insensitive). 2) Priority check: if "Søk her" button exists (external form), it takes priority over "Enkel Søknad" to prevent false positives. 3) For submission — direct navigation to finn.no/job/apply?adId={finnkode} instead of trying to click the Shadow DOM button.', 'Tre-nivå deteksjon: 1) Søk etter "enkel søknad"-tekst i HTML-kilde. 2) Prioritetssjekk: "Søk her" har prioritet over "Enkel Søknad." 3) Direkte navigasjon til finn.no/job/apply?adId={finnkode} i stedet for å klikke Shadow DOM-knappen.', 'Три рівні детекції: 1) Пошук тексту "enkel søknad" в HTML source. 2) Пріоритет: кнопка "Søk her" має пріоритет над "Enkel Søknad" для запобігання false positives. 3) Пряма навігація на finn.no/job/apply?adId={finnkode} замість кліку по Shadow DOM.', '100% accurate detection of form type on FINN.no. Zero false positives after implementing the "Søk her" priority check. Shadow DOM is no longer an obstacle — we simply bypass it.', '100% nøyaktig deteksjon av skjematype på FINN.no. Null falske positiver etter "Søk her"-prioritetssjekk. Shadow DOM er ikke lenger et hinder.', '100% точна детекція типу форми на FINN.no. Нуль false positives після впровадження пріоритету "Søk her". Shadow DOM більше не перешкода — ми його просто обходимо.', '{"Cheerio","HTML text search","Regex","Deno","URL construction"}', '{"#ShadowDOM","#FINN","#Workaround","#HTMLParsing","#DetectionLogic","#WebScraping"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j18', 'jobbot', 'bot_scraping', '3200 lines of Telegram magic — the bot that replaced UI', '3200 linjer Telegram-magi — boten som erstattet UI', '3200 рядків Telegram магії — бот, що замінив UI', 'A 3200+ line Deno Edge Function serves as a full mobile client: scan jobs, view analysis, generate cover letters, approve and submit — all within one Telegram chat. 95% of daily interaction happens here.', 'En 3200+ linjer Deno Edge Function fungerer som en komplett mobilklient: skann jobber, vis analyse, generer søknader, godkjenn og send — alt i én Telegram-chat. 95% av daglig interaksjon skjer her.', '3200+ рядків Deno Edge Function — повноцінний мобільний клієнт: сканування вакансій, аналіз, генерація søknad, підтвердження та відправка — все в одному Telegram-чаті. 95% щоденної взаємодії тут.', 'A web dashboard is convenient on desktop, but 80% of the time the user is on mobile. Receiving a notification, opening a browser, logging in, finding the job, pressing a button — that''s 5 steps. And the application deadline might be "today."', 'Et nett-dashboard er praktisk på desktop, men 80% av tiden er brukeren på mobil. Å motta varsling, åpne nettleser, logge inn, finne jobben, trykke knapp — det er 5 steg.', 'Веб-дашборд зручний за комп''ютером, але 80% часу юзер на телефоні. Сповіщення, відкрити браузер, залогінитись, знайти вакансію, натиснути кнопку — 5 кроків. А дедлайн може бути "сьогодні."', 'telegram-bot/index.ts — 3200+ lines Deno Edge Function (v15.0). Commands: /start (stats + buttons), /scan (launch scan), /report (daily report), /link (account binding), /code (2FA). Callback queries for inline buttons: write cover letter, view, approve, send, batch apply, cancel. URL pipeline: user sends a link, bot scrapes, analyzes, and shows score with action buttons. Multi-user: every handler starts with getUserIdFromChat().', 'telegram-bot/index.ts — 3200+ linjer Deno Edge Function. Kommandoer: /start, /scan, /report, /link, /code. Callback-queries for inline-knapper. URL-pipeline: brukeren sender lenke, boten skraper og analyserer. Multi-user: hver handler starter med getUserIdFromChat().', 'telegram-bot/index.ts — 3200+ рядків Deno Edge Function. Команди: /start, /scan, /report, /link, /code. Callback queries для inline кнопок: написати søknad, переглянути, підтвердити, відправити, batch apply. URL pipeline: юзер надсилає лінк — бот скрапить, аналізує, показує score з кнопками. Multi-user через getUserIdFromChat().', '95% of daily system interaction is through Telegram. From new job notification to submitted cover letter — 4 button presses in 30 seconds. The bot became the primary interface.', '95% av daglig systeminteraksjon er gjennom Telegram. Fra ny jobbvarsling til innsendt søknad — 4 knappetrykk på 30 sekunder. Boten ble det primære grensesnittet.', '95% щоденної взаємодії — через Telegram. Від сповіщення про вакансію до відправки søknad — 4 натиски кнопок за 30 секунд. Бот став основним інтерфейсом.', '{"Deno","Telegram Bot API","Supabase","TypeScript","Cheerio"}', '{"#TelegramBot","#ChatBot","#MobileFirst","#EdgeFunction","#Deno","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j19', 'jobbot', 'bot_scraping', 'Drop a link — get analysis in 15 seconds', 'Send en lenke — få analyse på 15 sekunder', 'Кинь лінк — отримай аналіз за 15 секунд', 'Any job URL sent to the Telegram bot is automatically scraped, saved to the database, analyzed by AI, and returned with a score and action buttons. From link to full analysis in 15 seconds.', 'Enhver jobb-URL sendt til Telegram-boten blir automatisk skrapet, lagret i databasen, analysert av AI og returnert med poengsum og handlingsknapper. Fra lenke til full analyse på 15 sekunder.', 'Будь-який URL вакансії, відправлений в Telegram бот, автоматично скрапиться, зберігається в БД, аналізується AI та повертається з оцінкою і кнопками дій. Від лінку до повного аналізу за 15 секунд.', 'A friend sends a job link in chat. The user opens it, reads for 5 minutes, tries to assess fit. Or doesn''t read at all — too lazy. The link gets lost in the message feed. A good opportunity missed.', 'En venn sender en jobblenke i chat. Brukeren åpner den, leser i 5 minutter, prøver å vurdere egnethet. Eller leser ikke i det hele tatt. Lenken går tapt. En god mulighet går tapt.', 'Друг скидає лінк на вакансію. Юзер відкриває, читає 5 хвилин, намагається оцінити відповідність. Або не читає — лінь. Лінк губиться в стрічці. Гарна вакансія пропущена.', 'URL pipeline in telegram-bot: the text handler checks messages for URLs (regex for finn.no, nav.no, linkedin.com, and any other domains). If found: 1) Scrape job details via extract_job_text. 2) Save to jobs DB. 3) Run job-analyzer for AI scoring. 4) Send result: score, aura, pros/cons, action buttons. URL handler has priority BEFORE other message handlers.', 'URL-pipeline i telegram-bot: teksthandler sjekker meldinger for URLer. Hvis funnet: skrape, lagre, analysere, sende resultat med poengsum og knapper. URL-handler har prioritet FØR andre meldingshandlere.', 'URL pipeline в telegram-bot: text handler перевіряє повідомлення на URL. Якщо знайдено: 1) Скрапить деталі через extract_job_text. 2) Зберігає в БД. 3) AI-аналіз. 4) Відправляє результат: score, aura, кнопки дій. URL handler має пріоритет ПЕРЕД іншими обробниками.', 'From sending a link to full analysis with score — 15 seconds. The user instantly sees "78% match, Growth aura" and can act. No link gets lost — everything enters the system.', 'Fra sending av lenke til full analyse med poengsum — 15 sekunder. Brukeren ser umiddelbart "78% match, Growth aura." Ingen lenke går tapt.', 'Від відправки лінку до повного аналізу з оцінкою — 15 секунд. Юзер одразу бачить "78% match, Growth aura" і може діяти. Жоден лінк не губиться.', '{"Telegram Bot API","Deno","Cheerio","Azure OpenAI","Supabase"}', '{"#URLPipeline","#InstantAnalysis","#TelegramBot","#OneClick","#AI","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j20', 'jobbot', 'bot_scraping', 'Inline buttons — full workflow in one chat', 'Inline-knapper — full arbeidsflyt i én chat', 'Inline кнопки — весь workflow в одному чаті', 'Every job message has inline buttons for ALL next actions: Write, View, Approve, Send. One chat = full pipeline. The "seen job to submitted application" conversion doubled.', 'Hver jobbmelding har inline-knapper for ALLE neste handlinger: Skriv, Vis, Godkjenn, Send. Én chat = full pipeline. Konverteringen "sett jobb til innsendt søknad" ble doblet.', 'Кожне повідомлення з вакансією має inline кнопки для ВСІХ наступних дій: Написати, Переглянути, Підтвердити, Відправити. Один чат = повний pipeline. Конверсія "побачив вакансію, подав заявку" зросла вдвічі.', 'Showing job analysis is half the battle. Then the candidate must: open web dashboard, find the job, click "Write søknad," wait, confirm, send. 6 steps, 2 platforms, 5 minutes. But the Telegram message already has the job info.', 'Å vise jobbanalyse er bare halvparten. Kandidaten må deretter åpne dashboard, finne jobben, klikke "Skriv søknad", vente, bekrefte, sende. 6 steg, 2 plattformer, 5 minutter.', 'Показати аналіз — половина. Далі потрібно: відкрити дашборд, знайти вакансію, натиснути "Написати søknad", дочекатися, підтвердити, відправити. 6 кроків, 2 платформи, 5 хвилин.', 'Every job message contains InlineKeyboardMarkup with buttons: Write søknad, View, Approve, Send to company, Update application type. The callback handler parses prefix + id, performs the action, and updates the message with new buttons. For batch FINN Easy: /apply command collects all approved applications and sends them in batch.', 'Hver jobbmelding inneholder InlineKeyboardMarkup med knapper: Skriv søknad, Vis, Godkjenn, Send, Oppdater type. Callback-handler parser prefix + id, utfører handling og oppdaterer meldingen. For batch FINN Easy: /apply samler godkjente søknader.', 'Кожне повідомлення містить InlineKeyboardMarkup з кнопками: Написати søknad, Переглянути, Підтвердити, Відправити, Оновити тип. Callback handler парсить prefix + id, виконує дію, оновлює повідомлення. Для batch FINN Easy: /apply збирає approved заявки.', 'Full cycle from notification to submitted application — 4 button presses, 30 seconds, without leaving Telegram. The "seen job to submitted application" conversion doubled.', 'Full syklus fra varsling til innsendt søknad — 4 knappetrykk, 30 sekunder, uten å forlate Telegram. Konverteringen doblet seg.', 'Повний цикл від сповіщення до відправки — 4 натиски кнопок, 30 секунд, без виходу з Telegram. Конверсія "побачив, подав" зросла вдвічі.', '{"Telegram Bot API","InlineKeyboardMarkup","Callback queries","Deno"}', '{"#InlineButtons","#ChatUI","#Workflow","#OneChat","#TelegramBot","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j21', 'jobbot', 'bot_scraping', 'Smart Confirmation — show everything before sending', 'Smart bekreftelse — vis alt før sending', 'Покажи все перед відправкою — Smart Confirmation', 'Before submitting an application, the bot shows a full preview: name, email, phone, cover letter excerpt, and site credentials. Each field is editable via inline buttons. Zero "sent with wrong email" incidents.', 'Før innsending viser boten full forhåndsvisning: navn, e-post, telefon, søknadsutdrag og nettstedlegitimasjon. Hvert felt kan redigeres via inline-knapper. Null "sendt med feil e-post"-hendelser.', 'Перед відправкою бот показує повний preview: ім''я, email, телефон, фрагмент søknad та credentials сайту. Кожне поле редагується через inline кнопки. Нуль випадків "відправив з невірним email."', 'User clicks "Send" — but what name will be in the form? What email? What phone? If the profile has the wrong number, automated sending without confirmation means a lost application.', 'Brukeren klikker "Send" — men hvilket navn står i skjemaet? Hvilken e-post? Automatisk sending uten bekreftelse betyr tapte søknader.', 'Юзер натискає "Відправити" — яке ім''я буде в формі? Який email? Який телефон? Автоматична відправка без підтвердження — це загублена заявка.', 'When pressing "Send to Company," the bot pulls from the DB: active CV profile (name, email, phone), cover letter (first 200 chars), site credentials, form type. Forms a preview message with inline buttons: Edit email, Edit phone, Edit cover letter, Confirm and send, Cancel. When editing — the bot asks for the new value via text and updates the DB.', 'Ved trykk på "Send" henter boten CV-profil, søknad og legitimasjoner fra DB. Viser forhåndsvisning med redigerbare felt via inline-knapper. Ved redigering spør boten om ny verdi og oppdaterer DB.', 'При натисканні "Відправити" бот витягує з БД: CV профіль, søknad, credentials сайту. Формує preview з inline кнопками: редагувати email, телефон, søknad, підтвердити, скасувати. При редагуванні — запитує нове значення і оновлює БД.', 'Zero "sent with wrong email" cases after implementing Smart Confirmation. The user sees the full picture in 2 seconds and confidently presses "Confirm."', 'Null "sendt med feil e-post"-tilfeller etter Smart Confirmation. Brukeren ser hele bildet på 2 sekunder og trykker trygt "Bekreft."', 'Нуль випадків "відправив з невірним email" після Smart Confirmation. Юзер бачить повну картину за 2 секунди і впевнено натискає "Підтвердити."', '{"Telegram Bot API","Supabase","Inline Keyboard","TypeScript"}', '{"#SmartConfirmation","#PreviewBeforeSend","#QualityControl","#UX","#TelegramBot"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j22', 'jobbot', 'bot_scraping', 'The bot that asks what it doesn''t know', 'Boten som spør om det den ikke vet', 'Бот, що питає те, чого не знає', 'When Skyvern encounters unknown form fields like "Do you live in Norway?", it pauses and asks the user via Telegram with inline button options. Answers are cached so the same question is never asked twice.', 'Når Skyvern møter ukjente skjemafelt som "Bor du i Norge?", stopper det og spør brukeren via Telegram med inline-knapper. Svar caches slik at samme spørsmål aldri stilles to ganger.', 'Коли Skyvern зустрічає незнайомі поля форми на кшталт "Bor du i Norge?", він зупиняється і питає юзера через Telegram з inline кнопками. Відповіді кешуються — те саме питання ніколи не задається двічі.', 'A Webcruiter form asks "Bor du i Norge?" (Do you live in Norway?) — this field is not in the CV profile. Skyvern stops because it cannot guess. Previously this meant task failure. Such questions number in dozens: driving license, security clearance, availability date.', 'Et Webcruiter-skjema spør "Bor du i Norge?" — dette feltet er ikke i CV-profilen. Skyvern stopper fordi den ikke kan gjette. Slike spørsmål er det dusinvis av.', 'Форма Webcruiter питає "Bor du i Norge?" — цього поля немає в CV профілі. Skyvern зупиняється — він не може вгадувати. Раніше це означало провал задачі. Таких питань — десятки.', 'Table registration_questions stores questions from Skyvern. The worker creates a record and sends a Telegram message with the question text + inline buttons with obvious options (Ja/Nei, 1-2 years/3-5 years/5+ years). Users can also answer with text. The worker polls for answers with a 5-minute timeout. Answers are cached and reused for the same questions on other sites.', 'Tabell registration_questions lagrer spørsmål fra Skyvern. Workeren sender Telegram-melding med spørsmålstekst + inline-knapper. Svar caches og gjenbrukes for samme spørsmål på andre sider. Timeout på 5 minutter.', 'Таблиця registration_questions зберігає питання від Skyvern. Worker відправляє Telegram-повідомлення з inline кнопками з варіантами. Відповіді кешуються і підставляються для тих самих питань на інших сайтах. Timeout: 5 хвилин.', 'Forms with non-standard fields no longer fail. The user answers 2-3 questions in Telegram, and the form fills completely. Answer caching reduces the number of questions with each attempt.', 'Skjemaer med ikke-standardfelt feiler ikke lenger. Brukeren svarer på 2-3 spørsmål i Telegram. Svarcaching reduserer antall spørsmål med hvert forsøk.', 'Форми з нестандартними полями більше не провалюються. Юзер відповідає на 2-3 питання в Telegram. Кешування відповідей зменшує кількість питань з кожною спробою.', '{"Telegram Bot API","Supabase","Skyvern","InlineKeyboard","Python"}', '{"#MissingFields","#QA","#Interactive","#TelegramBot","#FormFilling","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j23', 'jobbot', 'bot_scraping', 'Pocket job card — compact card with aura', 'Lommekort — kompakt kort med aura', 'Вакансія в кишені — компактна картка з аурою', 'AI analysis returns tons of data, but nobody reads walls of text on mobile. Compact "job cards" show score, aura emoji, company, deadline, and action buttons — fitting one phone screen. Details expand on tap.', 'AI-analyse returnerer masse data, men ingen leser tekstvegger på mobil. Kompakte "jobbkort" viser poengsum, aura-emoji, firma, frist og handlingsknapper — på én mobilskjerm. Detaljer utvides ved trykk.', 'AI-аналіз повертає купу даних, але ніхто не читає стіни тексту на мобільному. Компактні "job cards" показують score, aura emoji, компанію, дедлайн та кнопки дій — на один екран. Деталі розгортаються натиском.', 'AI analysis returns lots of data: score, aura, 5-axis radar, pros/cons, tasks, deadline, company, location, form type. Sending it all in one message creates a wall of text. Telegram limits messages to 4096 characters. Nobody reads long messages on mobile.', 'AI-analyse returnerer mye data. Å sende alt i én melding lager en tekstvegg. Telegram begrenser meldinger til 4096 tegn. Ingen leser lange meldinger på mobil.', 'AI-аналіз повертає купу даних: score, aura, radar, pros/cons, tasks, deadline. Все в одному повідомленні — стіна тексту. Telegram обмежує повідомлення до 4096 символів. Ніхто не читає довгі повідомлення.', 'Compact job card format: aura_emoji + company + title, Score + aura status, Deadline, form type + action buttons. "Details" button expands: pros/cons, tasks, radar scores, full URL. Cover letters truncated to 1500 chars with "Full text" button. Aura emoji mapping: Toxic, Growth, Balanced, Chill, Grind, Neutral. HTML formatting for compactness.', 'Kompakt jobbkortformat: aura_emoji + firma + tittel, poengsum, frist, skjematype + knapper. "Detaljer" utvider: fordeler/ulemper, oppgaver, radar. Søknader avkortet til 1500 tegn. Aura-emoji-kartlegging for 6 typer.', 'Компактний формат job card: aura_emoji + company + title, Score + aura status, Deadline, form type + кнопки. "Детальніше" розгортає: pros/cons, tasks, radar. Cover letters обрізаються до 1500 символів. Aura emoji mapping для 6 типів. HTML formatting для компактності.', 'A compact message fits one phone screen. The "apply or not" decision is made in 3 seconds. Details available with one tap. Zero messages truncated by Telegram''s character limit.', 'En kompakt melding passer på én mobilskjerm. Beslutningen "søke eller ikke" tas på 3 sekunder. Detaljer tilgjengelig med ett trykk. Null meldinger avkortet av Telegram.', 'Компактне повідомлення вміщується в один екран. Рішення "подаватись чи ні" за 3 секунди. Деталі — одним натиском. Нуль повідомлень, обрізаних Telegram.', '{"Telegram Bot API","HTML formatting","Emoji system","TypeScript"}', '{"#JobCard","#CompactUI","#Aura","#TelegramBot","#MobileUX","#InformationDesign"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j24', 'jobbot', 'frontend_ux', 'Dashboard — the pulse of job hunting', 'Dashboard — pulsen i jobbøkingen', 'Dashboard — пульс пошуку роботи', 'A full analytics dashboard with metric cards (jobs, applications, success rate, AI cost), a pipeline stacked bar chart, and a Leaflet map of Norway with color-coded job markers. Full picture in 3 seconds.', 'Et komplett analyse-dashboard med metrikkort, pipeline stablet søylediagram og Leaflet-kart over Norge med fargekodede jobbmarkører. Hele bildet på 3 sekunder.', 'Повний аналітичний Dashboard з metric cards (вакансії, заявки, success rate, AI cost), pipeline stacked bar chart та Leaflet-карта Норвегії з кольоровими маркерами. Повна картина за 3 секунди.', 'The candidate does not know where they stand. How many jobs found this week? How many applications in progress? What''s the conversion rate? Without analytics, job hunting is chaotic poking in the dark. Motivation drops when you can''t see progress.', 'Kandidaten vet ikke hvor de står. Hvor mange jobber funnet? Hvor mange søknader pågår? Uten analyse er jobbøking kaotisk. Motivasjonen faller når man ikke ser fremgang.', 'Кандидат не знає, де він стоїть. Скільки вакансій знайдено? Скільки подач в процесі? Без аналітики пошук роботи — хаотичне тикання в темряві. Мотивація падає, коли не бачиш прогресу.', 'DashboardPage.tsx with three sections: 1) Metric Cards — Total Jobs, Applications, Success Rate, AI Cost with weekly trends. 2) Stacked Bar Chart — Recharts pipeline: New, Analyzed, Written, Approved, Sent, Submitted. 3) Job Map — Leaflet map of Norway with color-coded markers (green=submitted, yellow=in progress, red=rejected). DateRangePicker for period filtering. Real-time data via Supabase RLS queries.', 'DashboardPage.tsx med tre seksjoner: 1) Metrikkort med ukentlige trender. 2) Stablet søylediagram — Recharts pipeline. 3) Jobbkart — Leaflet-kart over Norge med fargekodede markører. DateRangePicker for periodfiltrering.', 'DashboardPage.tsx з трьома секціями: 1) Metric Cards з тижневими трендами. 2) Stacked Bar Chart — Recharts pipeline. 3) Job Map — Leaflet карта Норвегії з кольоровими маркерами. DateRangePicker для фільтрації.', 'The candidate opens the dashboard and sees in 3 seconds: "this week 47 jobs, 12 applications, 3 submitted, cost $2.40." Motivation grows with concrete numbers. The pipeline chart shows bottlenecks requiring action.', 'Kandidaten åpner dashboardet og ser på 3 sekunder: "denne uken 47 jobber, 12 søknader, 3 innsendt, kostnad $2,40." Pipeline-diagrammet viser flaskehalser.', 'Кандидат відкриває dashboard і за 3 секунди бачить: "цього тижня 47 вакансій, 12 подач, 3 submitted, cost $2.40." Pipeline chart показує "затори" і що потребує дії.', '{"React 19","Recharts","Leaflet","TypeScript","Supabase","Tailwind CSS"}', '{"#Dashboard","#DataVisualization","#Recharts","#Analytics","#React","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j25', 'jobbot', 'frontend_ux', 'Map of 160+ Norwegian cities — jobs on the map', 'Kart over 160+ norske byer — jobber på kartet', 'Карта 160+ норвезьких міст — вакансії на мапі', 'Instead of expensive Google Geocoding API, a built-in cache of 160+ Norwegian city coordinates plus postal code fallback gives free, instant job map visualization on Leaflet.', 'I stedet for dyr Google Geocoding API, gir en innebygd cache med 160+ norske bykoordinater pluss postnummer-fallback gratis, umiddelbar jobbkartvisualisering på Leaflet.', 'Замість дорогого Google Geocoding API — вбудований кеш координат 160+ норвезьких міст плюс fallback на поштові коди дає безкоштовну миттєву візуалізацію вакансій на Leaflet.', 'Jobs have location text: "Oslo," "Gjøvik," "Hunndalen," "Bismo." But where is that on a map? Especially for an immigrant who doesn''t know Hunndalen is 5km from Gjøvik. A text list gives no spatial understanding. Google Geocoding costs $5/1000 requests.', 'Jobber har stedsnavntekst, men hvor er det på kartet? Spesielt for en innvandrer. Google Geocoding koster $5/1000 forespørsler.', 'Вакансії мають текстову локацію: "Oslo," "Gjøvik," "Hunndalen." Де це на карті? Особливо для іммігранта. Google Geocoding коштує $5/1000 запитів.', 'JobMap.tsx with Leaflet: CITY_COORDS — 160+ entries from Oslo to Tromsø, including user-specific regions (Gjøvik, Hunndalen, Raufoss). POSTAL_RANGES — 4-digit prefix to coordinates. extractLocation() scans text for city names (case-insensitive, with ø/o transliteration) and postal codes. Color-coded markers: green (submitted), blue (analyzed), yellow (in progress), grey (new).', 'JobMap.tsx med Leaflet: CITY_COORDS — 160+ oppføringer. POSTAL_RANGES — 4-sifret postnummer til koordinater. extractLocation() skanner tekst for bynavn med ø/o-translitterering. Fargekodede markører.', 'JobMap.tsx з Leaflet: CITY_COORDS — 160+ записів від Oslo до Tromsø. POSTAL_RANGES — 4-значний поштовий код до координат. extractLocation() сканує текст на назви міст (з транслітерацією ø/o). Кольорові маркери.', 'A live map of Norway with job markers. The candidate sees clusters in Innlandet, Oslo, Bergen. Click on a marker shows job name and score popup. Zero geocoding API costs.', 'Et levende kart over Norge med jobbmarkører. Kandidaten ser klynger i Innlandet, Oslo, Bergen. Klikk på markør viser popup med jobb og poengsum. Null geocoding-kostnader.', 'Жива карта Норвегії з маркерами вакансій. Кандидат бачить кластери в Innlandet, Oslo, Bergen. Клік на маркер — popup з назвою та score. Нуль витрат на geocoding.', '{"Leaflet","React","TypeScript","GeoJSON","Static coordinates cache"}', '{"#JobMap","#Leaflet","#Geocoding","#Norway","#DataVisualization","#FreeAPI"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j26', 'jobbot', 'frontend_ux', '88KB table — the frontend monster that works', '88KB tabell — frontend-monsteret som fungerer', '88KB таблиця — фронтенд-монстр, який працює', 'The largest project component at 88KB: column filters, company exclusion lists, bulk actions, sort, search, date range, expandable rows, Excel/PDF export. Virtual scrolling handles 500+ rows without lag.', 'Den største prosjektkomponenten på 88KB: kolonnefiltre, firmautelukking, massehandlinger, sortering, søk, datointervall, utvidbare rader, Excel/PDF-eksport. Virtual scrolling håndterer 500+ rader uten forsinkelse.', 'Найбільший компонент проекту 88KB: фільтри по колонках, exclusion list компаній, bulk actions, sort, search, date range, expandable rows, Excel/PDF export. Virtual scrolling тримає 500+ рядків без лагів.', 'After a week of scanning, the DB has 200+ jobs. Finding "IT jobs in Gjøvik with score > 70 for the last week, excluding recruiter companies" requires 10 filter clicks and 5 minutes of scrolling with a regular table.', 'Etter en uke med skanning har DB 200+ jobber. Å finne spesifikke jobber krever 10 filterklikk og 5 minutter med scrolling med en vanlig tabell.', 'Після тижня сканування в БД 200+ вакансій. Знайти "IT в Gjøvik, score > 70 за останній тиждень, без рекрутерів" — 10 кліків фільтрів і 5 хвилин скролінгу.', 'JobTable.tsx at 88KB is the largest component. Features: 1) Column filters — dropdown by status, form type, source; text search. 2) Company exclusion — "Block Adecco" hides all their jobs permanently. 3) DateRangePicker with presets. 4) Sort by score, date, company, deadline. 5) Bulk actions — checkbox selection for batch approve/send. 6) Expandable rows — pros/cons, tasks, aura, radar. 7) Excel/PDF export. Virtual scrolling for 500+ rows.', 'JobTable.tsx på 88KB med kolonnefiltre, firmaekskludering, datovelger, sortering, massehandlinger, utvidbare rader, Excel/PDF-eksport og virtual scrolling for 500+ rader.', 'JobTable.tsx 88KB з фільтрами по колонках, exclusion компаній, DateRangePicker, sort, bulk actions з checkbox selection, expandable rows, Excel/PDF export. Virtual scrolling для 500+ рядків.', 'Finding "IT in Gjøvik, score > 70" — 3 clicks, 2 seconds. Excluding recruiters — 1 click. Batch approving 5 jobs — 2 clicks. The table handles 500+ rows without lag thanks to virtual scrolling.', 'Finne "IT i Gjøvik, poengsum > 70" — 3 klikk, 2 sekunder. Ekskludere rekrutterere — 1 klikk. Godkjenne 5 jobber i batch — 2 klikk. 500+ rader uten forsinkelse.', 'Знайти "IT в Gjøvik, score > 70" — 3 кліки, 2 секунди. Exclude рекрутерів — 1 клік. Approve 5 вакансій пакетом — 2 кліки. 500+ рядків без лагів.', '{"React 19","TypeScript","Tailwind CSS","Virtual scrolling","Lucide icons"}', '{"#DataTable","#Filtering","#BulkActions","#React","#VirtualScrolling","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j27', 'jobbot', 'frontend_ux', 'Excel export with hyperlinks — HR will appreciate it', 'Excel-eksport med hyperlenker — HR vil sette pris på det', 'Export в Excel з гіперлінками — HR оцінить', 'One-click Excel export with clickable job URLs, color-coded scores, custom column selection, and auto-fit widths. PDF export with candidate name header for official purposes. Export history saved in DB.', 'Ett-klikks Excel-eksport med klikkbare jobb-URLer, fargekodede poengsummer, tilpasset kolonnevalg og auto-tilpasset bredde. PDF-eksport med kandidatnavn i topptekst for offisielle formål.', 'Export в Excel одним кліком з клікабельними URL, кольоровим score, вибором колонок та auto-fit ширини. PDF export з іменем кандидата для офіційних цілей. Історія експортів в БД.', 'The candidate wants to share a job list with a NAV career consultant or save for offline review. Copy-paste loses formatting. Screenshots aren''t clickable. PDF can''t be filtered. A proper Excel file with smart formatting is needed.', 'Kandidaten vil dele en jobbliste med NAV-karrierrådgiver eller lagre for offline gjennomgang. Kopiering mister formatering. Skjermbilder er ikke klikkbare.', 'Кандидат хоче поділитися списком вакансій з консультантом NAV або зберегти офлайн. Copy-paste втрачає форматування. Скріншот не клікабельний. Потрібен нормальний Excel.', 'Export module uses xlsx library for Excel and jsPDF for PDF. Excel: user selects columns via checkbox modal, hyperlinks via { t: "s", v: title, l: { Target: url } }, color-coded scores (green > 70, yellow 40-70, red < 40), auto-fit column width. PDF: header with candidate name, date, table with wrap text, page number footer. Both saved in export_history.', 'Eksportmodul bruker xlsx for Excel og jsPDF for PDF. Excel: brukeren velger kolonner, hyperlenker, fargekodede poengsummer, auto-tilpasset bredde. PDF: topptekst med kandidatnavn. Begge lagret i export_history.', 'Модуль export використовує xlsx для Excel та jsPDF для PDF. Excel: вибір колонок, гіперлінки, кольорове кодування score, auto-fit ширини. PDF: header з ім''ям кандидата. Обидва зберігаються в export_history.', 'One click — an Excel file with 50 jobs, clickable links, color-coded scores, ready to send to a NAV consultant. PDF for printing and official purposes. Export history saved in the DB.', 'Ett klikk — Excel-fil med 50 jobber, klikkbare lenker, fargekodede poengsummer, klar til å sende til NAV-rådgiver. PDF for utskrift. Eksporthistorikk lagret i DB.', 'Один клік — Excel з 50 вакансіями, клікабельними лінками, кольоровим score, готовий для консультанта NAV. PDF для друку. Історія експортів в БД.', '{"xlsx","jsPDF","React","TypeScript","Supabase"}', '{"#ExcelExport","#PDF","#DataExport","#Hyperlinks","#Spreadsheet","#Productivity"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j28', 'jobbot', 'frontend_ux', 'CV Editor — 9 sections, full control', 'CV-editor — 9 seksjoner, full kontroll', 'CV Editor — 9 секцій, повний контроль', 'A structured CV editor with 9 expandable sections: personal info, work experience, education, skills, languages, certifications, summary, references, additional info. Drag-and-drop reordering, auto-save, changes instantly available for forms.', 'En strukturert CV-editor med 9 utvidbare seksjoner: personlig informasjon, arbeidserfaring, utdanning, ferdigheter, språk, sertifiseringer, sammendrag, referanser. Drag-and-drop, autolagring.', 'Структурований CV editor з 9 розгортальними секціями: персональні дані, досвід, освіта, навички, мови, сертифікації, summary, рекомендації, додаткова інформація. Drag-and-drop, auto-save.', 'AI extracted CV from PDF, but there''s an error in work experience: wrong date, inaccurate position title. To fix it: open PDF editor, find section, edit, re-upload, re-parse. 20 minutes to change one date.', 'AI hentet CV fra PDF, men det er en feil i arbeidserfaring. For å fikse: åpne PDF-editor, finne seksjon, redigere, laste opp på nytt. 20 minutter for å endre én dato.', 'AI витягнув CV з PDF, але в досвіді помилка: wrong date. Для виправлення: PDF-редактор, знайти секцію, редагувати, re-upload, re-parse. 20 хвилин на зміну однієї дати.', 'ProfileEditor.tsx — structured CV editor with 9 sections: Personal Info, Work Experience, Education, Skills, Languages, Certifications, Summary, References, Additional Info. Each section is an expandable card with add/edit/delete. Drag-and-drop for reordering. Auto-save on change. Data stored in JSONB structured_content, immediately available for form auto-filling and cover letter generation.', 'ProfileEditor.tsx — strukturert CV-editor med 9 seksjoner, hver som utvidbart kort med add/edit/delete. Drag-and-drop for omorganisering. Autolagring. Data lagret i JSONB, umiddelbart tilgjengelig for automatisk skjemautfylling.', 'ProfileEditor.tsx — structured CV editor з 9 секціями. Кожна секція — expandable card з add/edit/delete. Drag-and-drop для reorder. Auto-save при зміні. Дані в JSONB structured_content, миттєво доступні для форм та søknad.', 'Changing a date in work experience — 3 seconds, 2 clicks. Adding a new language — 5 seconds. All changes instantly available for forms and cover letters. Zero need to re-upload PDF.', 'Endre en dato i arbeidserfaring — 3 sekunder, 2 klikk. Legge til nytt språk — 5 sekunder. Alle endringer umiddelbart tilgjengelige. Null behov for ny PDF-opplasting.', 'Зміна дати в досвіді — 3 секунди, 2 кліки. Нова мова — 5 секунд. Зміни миттєво доступні для форм та søknad. Нуль потреби re-upload PDF.', '{"React 19","TypeScript","JSONB","Supabase","Tailwind CSS","Lucide icons"}', '{"#CVEditor","#StructuredData","#ProfileManagement","#JSONB","#React","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j29', 'jobbot', 'frontend_ux', 'Three languages — one button', 'Tre språk — én knapp', 'Три мови — одна кнопка', 'Full i18n with three languages (UK/NO/EN) where the choice is saved in the database, not localStorage. The entire system adapts: UI, AI analysis, Telegram messages. Language persists across devices.', 'Full i18n med tre språk (UK/NO/EN) der valget lagres i databasen, ikke localStorage. Hele systemet tilpasses: UI, AI-analyse, Telegram-meldinger. Språket bevares på tvers av enheter.', 'Повний i18n з трьома мовами (UK/NO/EN), де вибір зберігається в БД, а не localStorage. Вся система адаптується: UI, AI-аналіз, Telegram-повідомлення. Мова зберігається між пристроями.', 'Platform users are Ukrainians in Norway. Some understand Norwegian, some only English, some want their native Ukrainian. A hardcoded interface language means 66% unsatisfied users. Language that resets on reload is even worse.', 'Plattformbrukere er ukrainere i Norge. Noen forstår norsk, noen bare engelsk, noen vil ha ukrainsk. Hardkodet språk betyr 66% misfornøyde brukere.', 'Користувачі — українці в Норвегії. Хтось розуміє норвезьку, хтось лише англійську, хтось хоче українську. Hardcoded мова = 66% незадоволених юзерів.', 'services/translations.ts with three branches (en, no, uk), each with ~200 keys. LanguageContext.tsx loads preferred_analysis_language from user_settings on login and saves changes back to DB. Language switcher in sidebar with three flags. AI analysis (job-analyzer) receives a language parameter and generates pros/cons in the corresponding language. Telegram bot also adapts.', 'services/translations.ts med tre grener og ~200 nøkler. LanguageContext.tsx laster foretrukket språk fra user_settings og lagrer endringer i DB. Språkbytter i sidebar. AI-analyse mottar språkparameter. Telegram-bot tilpasser seg også.', 'services/translations.ts з трьома гілками та ~200 ключами. LanguageContext.tsx завантажує мову з user_settings при логіні та зберігає зміни в БД. Перемикач в sidebar. AI-аналіз отримує language parameter. Telegram-бот теж адаптується.', 'User chooses language once — the entire system adapts: UI, AI analysis, Telegram messages. Logging in from another device — language is already saved. Three languages cover 100% of the target audience.', 'Brukeren velger språk én gang — hele systemet tilpasses: UI, AI-analyse, Telegram-meldinger. Innlogging fra annen enhet — språket er allerede lagret. Tre språk dekker 100% av målgruppen.', 'Юзер обирає мову раз — вся система адаптується: UI, AI-аналіз, Telegram. Логін з іншого пристрою — мова збережена. Три мови покривають 100% аудиторії.', '{"React Context","TypeScript","i18n","Supabase","Deno"}', '{"#Internationalization","#i18n","#Ukrainian","#Norwegian","#MultiLanguage","#UX"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j30', 'jobbot', 'frontend_ux', 'New jobs appear on their own — no F5 needed', 'Nye jobber dukker opp av seg selv — ingen F5 nødvendig', 'Нові вакансії з''являються самі — без F5', 'Supabase Realtime WebSocket subscription pushes new jobs to the dashboard instantly. INSERT adds to the feed, UPDATE refreshes scores, metric cards recalculate. Debounced for batch updates.', 'Supabase Realtime WebSocket-abonnement pusher nye jobber til dashboardet umiddelbart. INSERT legger til i feeden, UPDATE oppdaterer poengsummer, metrikkort beregnes på nytt. Debounced for masseoppateringer.', 'Supabase Realtime WebSocket subscription пушить нові вакансії на Dashboard миттєво. INSERT додає в стрічку, UPDATE оновлює score, metric cards перераховуються. Debounce для batch updates.', 'The user watches the Dashboard. A scheduled scanner finds 5 new jobs. But the Dashboard shows old data. The user presses F5, waits 3 seconds. Or doesn''t — and misses a hot job with deadline "today."', 'Brukeren ser på Dashboard. En planlagt skanner finner 5 nye jobber. Men Dashboard viser gamle data. Brukeren trykker F5 og venter 3 sekunder. Eller ikke — og går glipp av en hot jobb.', 'Юзер дивиться Dashboard. Scanner знаходить 5 нових вакансій. Dashboard показує старі дані. F5, 3 секунди. Або не натисне — і пропустить hot job з дедлайном "сьогодні."', 'Supabase Realtime subscription on the jobs table filtered by user_id. On INSERT — new job added to state without re-fetch. On UPDATE (e.g., score appears after analysis) — specific row updated. Dashboard metric cards recalculate. 2-second debounce for batch updates. Notification badge on Sidebar shows count of new items since last view.', 'Supabase Realtime-abonnement på jobs-tabellen filtrert etter user_id. Ved INSERT legges ny jobb til uten re-fetch. Ved UPDATE oppdateres raden. 2-sekunders debounce for masseoppateringer. Varslingsbadge på Sidebar.', 'Supabase Realtime subscription на таблицю jobs з фільтром по user_id. При INSERT — новий job додається без re-fetch. При UPDATE — оновлюється конкретний рядок. Debounce 2 секунди для batch updates. Notification badge на Sidebar.', 'New jobs appear in real time — like messages in a chat. The Dashboard is always current. Metric cards update automatically. Zero F5 presses needed.', 'Nye jobber dukker opp i sanntid — som meldinger i en chat. Dashboard er alltid oppdatert. Metrikkort oppdateres automatisk. Null F5-trykk nødvendig.', 'Нові вакансії з''являються в реальному часі — як повідомлення в чаті. Dashboard завжди актуальний. Metric cards оновлюються автоматично. Жодного F5.', '{"Supabase Realtime","WebSocket","React useState","TypeScript"}', '{"#RealTime","#WebSocket","#LiveUpdate","#Supabase","#React","#NoRefresh"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j31', 'jobbot', 'other', 'Everyone sees only their own — Row Level Security', 'Alle ser bare sitt eget — Row Level Security', 'Кожен бачить тільки своє — Row Level Security', 'RLS enabled on ALL tables with policies WHERE user_id = auth.uid(). Even a direct SQL query cannot bypass it. Data isolation tested: login as user B shows 0 jobs, 0 applications, $0 cost.', 'RLS aktivert på ALLE tabeller med policyer WHERE user_id = auth.uid(). Selv direkte SQL-spørringer kan ikke omgå det. Dataisolering testet: innlogging som bruker B viser 0 jobber, 0 søknader.', 'RLS включено на ВСІХ таблицях з політиками WHERE user_id = auth.uid(). Навіть прямий SQL не обійде. Тест: логін як юзер Б — 0 jobs, 0 applications, $0 cost.', 'The system became multi-user. User A and User B have jobs, cover letters, credentials. A SELECT without filter shows User A the cover letters of User B. And credentials are login passwords to recruiting sites. Leaking them is a catastrophe.', 'Systemet ble flerbruker. En SELECT uten filter viser bruker A søknadene til bruker B. Og legitimasjoner er innloggingspassord til rekrutteringssider. Lekkasje er katastrofalt.', 'Система стала multi-user. SELECT без фільтра — юзер А бачить søknad юзера Б. А credentials — це логіни та паролі. Витік = катастрофа.', 'RLS enabled on ALL tables: jobs, applications, cv_profiles, user_settings, site_credentials, site_form_memory, system_logs, export_history, registration_flows. Policies: SELECT/INSERT/UPDATE/DELETE WHERE user_id = auth.uid(). For Edge Functions with service role key (which bypasses RLS) — mandatory .eq("user_id", userId) in every query. Repair function fix-jobs-rls for post-migration fixes.', 'RLS aktivert på ALLE tabeller med SELECT/INSERT/UPDATE/DELETE WHERE user_id = auth.uid(). For Edge Functions med service role key — obligatorisk .eq("user_id", userId) i hver spørring. Reparasjonsfunksjon fix-jobs-rls.', 'RLS включено на ВСІХ таблицях: jobs, applications, cv_profiles, site_credentials та інших. Політики: SELECT/INSERT/UPDATE/DELETE WHERE user_id = auth.uid(). Для Edge Functions з service role key — обов''язковий .eq("user_id", userId). Edge Function fix-jobs-rls для ремонту.', 'Complete data isolation between users at the database level. Even a bug in application code won''t cause a leak — RLS blocks it. Tested: login as user B shows 0 jobs, 0 applications, $0.00 cost.', 'Fullstendig dataisolering mellom brukere på databasenivå. Selv en feil i applikasjonskoden forårsaker ikke lekkasje. Testet: bruker B ser 0 jobber, $0,00 kostnad.', 'Повна ізоляція даних між юзерами на рівні БД. Навіть баг в коді не призведе до витоку — RLS заблокує. Тест: логін як юзер Б — 0 jobs, 0 applications, $0.00.', '{"PostgreSQL RLS","Supabase","SQL policies","auth.uid()"}', '{"#RowLevelSecurity","#RLS","#PostgreSQL","#DataIsolation","#Security","#MultiUser"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j32', 'jobbot', 'other', 'User_id everywhere — paranoid isolation', 'User_id overalt — paranoid isolering', 'User_id скрізь — параноїдальна ізоляція', 'Edge Functions and Python workers use service role key that bypasses RLS. A complete audit ensures every query has a user_id filter — double isolation at both database and application layers.', 'Edge Functions og Python-workere bruker service role key som omgår RLS. En komplett revisjon sikrer at hver spørring har user_id-filter — dobbel isolering på både database- og applikasjonsnivå.', 'Edge Functions та Python workers використовують service role key, що bypass RLS. Повний аудит гарантує user_id фільтр у КОЖНОМУ запиті — подвійна ізоляція на рівні БД та application.', 'RLS works for frontend queries (with JWT). But Edge Functions and Python workers use service role key — it bypasses RLS. One forgotten .eq("user_id", userId) = data leak. And there are hundreds of such queries across scheduled-scanner, job-analyzer, generate_application, auto_apply.py, api.ts.', 'RLS fungerer for frontend-spørringer (med JWT). Men Edge Functions og Python-workere bruker service role key som omgår RLS. En glemt .eq("user_id", userId) = datalekkasje.', 'RLS працює для frontend запитів (з JWT). Але Edge Functions та Python worker використовують service role key — він bypass RLS. Один забутий .eq("user_id", userId) = витік даних.', 'Audit of ALL Supabase queries in the project. Every .from("table").select() verified for .eq("user_id", ...). In scheduled-scanner: loop for each user with auto_scan_enabled — all inner queries filtered by that user''s ID. In telegram-bot: getUserIdFromChat(chatId) at the start of every handler. In auto_apply.py: user_id extracted from application record and passed to every subsequent query.', 'Revisjon av ALLE Supabase-spørringer. Hver .from("table").select() verifisert for .eq("user_id", ...). I telegram-bot: getUserIdFromChat() i starten av hver handler. I auto_apply.py: user_id fra application record.', 'Аудит ВСІХ Supabase запитів. Кожен .from("table").select() перевірено на .eq("user_id", ...). В telegram-bot: getUserIdFromChat() на початку кожного handler. В auto_apply.py: user_id з application record в кожен запит.', 'Double isolation: RLS at PostgreSQL level + application-level user_id filter. Even if service role key is compromised, every query is restricted to a specific user_id. Zero data leak incidents.', 'Dobbel isolering: RLS på PostgreSQL-nivå + applikasjonsnivå user_id-filter. Null datalekkasjer.', 'Подвійна ізоляція: RLS на рівні PostgreSQL + application-level user_id filter. Навіть при компрометації service role key — кожен запит обмежений user_id. Нуль витоків.', '{"Supabase","PostgreSQL","TypeScript","Python","Code audit"}', '{"#MultiUser","#DataIsolation","#SecurityAudit","#DefenseInDepth","#UserID"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j33', 'jobbot', 'other', 'Passwords for 11 sites — secure and convenient', 'Passord for 11 sider — sikkert og praktisk', 'Паролі до 11 сайтів — безпечно і зручно', 'Centralized credential management for 11+ recruiting sites with per-user RLS isolation, cryptographically secure password generation, and auto-selection by domain. Dashboard UI with masked passwords shown on click.', 'Sentralisert legitimasjonshåndtering for 11+ rekrutteringssider med RLS-isolering per bruker, kryptografisk sikker passordgenerering og automatisk valg etter domene. Dashboard-UI med maskerte passord.', 'Централізоване управління credentials для 11+ рекрутингових сайтів з per-user RLS ізоляцією, криптографічно безпечна генерація паролів та автовибір за доменом. Dashboard UI з маскуванням паролів.', 'Automation requires logins on Webcruiter, Easycruit, JobbNorge, Teamtailor, Recman, FINN, Jobylon, ReachMee, Varbi, HRManager, SuccessFactors. That''s 11+ email/password pairs. Storing in .env doesn''t scale for multi-user. Plain text storage is a security nightmare.', 'Automatisering krever innlogging på 11+ plattformer. Lagring i .env skalerer ikke for flerbruker. Klartekstlagring er et sikkerhetsmareritt.', 'Для автоматизації потрібні логіни на 11+ платформах. .env не масштабується для multi-user. Plain text — security nightmare.', 'Table site_credentials with per-user RLS isolation. Worker checks credentials before each task: if they exist — login; if not — registration via register_site.py. Passwords generated by generate_secure_password(16): uppercase + lowercase + digit + special char. On login failure — bot asks for updated password via Telegram. Dashboard Settings page for viewing/editing credentials (password masked with dots, shown on click).', 'Tabell site_credentials med RLS-isolering per bruker. Worker sjekker legitimasjoner før oppgaver. Passord generert med generate_secure_password(16). Dashboard Settings for visning/redigering med maskerte passord.', 'Таблиця site_credentials з per-user RLS. Worker перевіряє credentials перед задачею. Паролі генеруються generate_secure_password(16). Dashboard Settings для перегляду/редагування з маскуванням паролів.', 'Centralized management for 11+ sites with per-user isolation. Automatic secure password generation. Worker auto-selects the right credential per domain. Zero hardcoded passwords.', 'Sentralisert håndtering for 11+ sider med brukerisolering. Automatisk sikker passordgenerering. Null hardkodede passord.', 'Централізоване управління для 11+ сайтів з per-user ізоляцією. Автоматична генерація secure passwords. Нуль хардкоду паролів.', '{"Supabase PostgreSQL","RLS","Python secrets","TypeScript","React"}', '{"#CredentialManager","#SecurityByDesign","#PasswordGeneration","#MultiUser","#RLS"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j34', 'jobbot', 'other', 'Supabase SDK hangs — but we don''t', 'Supabase SDK henger — men vi gjør det ikke', 'Supabase SDK зависає — а ми ні', 'Supabase auth SDK methods hang indefinitely due to a bug. A complete bypass reads sessions directly from localStorage, uses REST API with AbortController timeouts. Auth loads in 500ms instead of infinite spinner.', 'Supabase auth SDK-metoder henger på ubestemt tid på grunn av en feil. En komplett omgåelse leser sesjoner direkte fra localStorage, bruker REST API med AbortController-timeouts. Auth laster på 500ms.', 'Supabase auth SDK методи зависають через баг. Повний обхід читає session з localStorage, використовує REST API з AbortController timeouts. Auth завантажується за 500ms замість вічного спінера.', 'supabase.auth.getSession() hangs indefinitely. supabase.auth.signOut() also hangs. onAuthStateChange never fires. This is a Supabase JS SDK bug from an auth-js update. The user sees an infinite spinner instead of the Dashboard. Or cannot sign out.', 'supabase.auth.getSession() henger på ubestemt tid. signOut() henger også. onAuthStateChange utløses aldri. En Supabase JS SDK-feil. Brukeren ser en uendelig spinner.', 'supabase.auth.getSession() зависає. signOut() теж. onAuthStateChange не викликається. Баг Supabase JS SDK. Юзер бачить вічний спінер замість Dashboard.', 'AuthContext.tsx — complete bypass of Supabase auth SDK. On mount: reads STORAGE_KEY from localStorage, parses JSON, extracts access_token and user. fetchWithTimeout(5000) — fetch wrapper with AbortController. fetchUserRoleDirect() — direct REST request to /rest/v1/user_settings. Sign out: localStorage.removeItem() + window.location.reload(). Sign in: direct POST to /auth/v1/token with 5-second timeout.', 'AuthContext.tsx — komplett omgåelse av Supabase auth SDK. Leser session fra localStorage, bruker fetchWithTimeout(5000) med AbortController. Direkte REST-forespørsler for autentisering.', 'AuthContext.tsx — повний обхід Supabase auth SDK. Читає session з localStorage, парсить JSON. fetchWithTimeout(5000) з AbortController. Прямі REST запити для автентифікації. Sign out через localStorage.removeItem().', 'Auth works stably with 500ms load time instead of infinite hang. Sign out is instant. Zero dependency on buggy SDK auth methods. The workaround has been running for 6+ months without issues.', 'Auth fungerer stabilt med 500ms lastetid. Utlogging er umiddelbar. Null avhengighet av buggy SDK. Løsningen har kjørt i 6+ måneder.', 'Auth працює стабільно, 500ms замість вічного зависання. Sign out миттєвий. Нуль залежності від buggy SDK. Workaround працює 6+ місяців.', '{"React Context","localStorage","AbortController","REST API","TypeScript"}', '{"#AuthWorkaround","#SupabaseBug","#localStorage","#Timeout","#Resilience","#Frontend"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j35', 'jobbot', 'devops_infra', 'Push to main = Edge Functions updated', 'Push til main = Edge Functions oppdatert', 'Push to main = Edge Functions оновлені', 'GitHub Actions auto-deploys all 14 Edge Functions on push to main. Three no-JWT functions deployed separately, the rest in a loop. Zero manual deploys, zero forgotten functions.', 'GitHub Actions auto-deployer alle 14 Edge Functions ved push til main. Tre no-JWT-funksjoner deployes separat, resten i en løkke. Null manuelle deployer, null glemte funksjoner.', 'GitHub Actions автоматично деплоїть всі 14 Edge Functions при push до main. Три no-JWT функції окремо, решта в циклі. Нуль ручних deploy, нуль забутих функцій.', '14 Edge Functions. Manual deploy for each one. 3 functions need --no-verify-jwt, the rest need JWT. Forget to deploy one — production breaks. Forget --no-verify-jwt for telegram-bot — the webhook stops working. Human error waits around the corner.', '14 Edge Functions. Manuell deploy for hver. 3 funksjoner trenger --no-verify-jwt. Glem å deploye én — produksjon går ned. Menneskelig feil venter.', '14 Edge Functions. Ручний deploy кожної. 3 функції потребують --no-verify-jwt. Забув задеплоїти одну — production ламається. Людська помилка чекає.', 'GitHub Actions workflow deploy-supabase-functions.yml: triggers on push to main with path filter supabase/functions/** + manual workflow_dispatch. Steps: 1) Checkout. 2) Setup Supabase CLI. 3) Deploy telegram-bot, scheduled-scanner, finn-2fa-webhook with --no-verify-jwt. 4) Loop through all other functions (excluding _shared). Secret: SUPABASE_ACCESS_TOKEN.', 'GitHub Actions deploy-supabase-functions.yml: trigger ved push til main med stifilter + manuell workflow_dispatch. Deployer 3 no-JWT-funksjoner separat, resten i løkke.', 'GitHub Actions deploy-supabase-functions.yml: trigger на push до main з path filter + manual workflow_dispatch. 3 no-JWT функції окремо, решта в циклі. Secret: SUPABASE_ACCESS_TOKEN.', 'Git push — within 2 minutes all 14 Edge Functions are updated in production. Zero manual work. Zero forgotten deploys. JWT/no-JWT configuration is fixed in code, not in the developer''s head.', 'Git push — innen 2 minutter er alle 14 Edge Functions oppdatert i produksjon. Null manuelt arbeid. Null glemte deployer.', 'Git push — за 2 хвилини всі 14 Edge Functions оновлені в production. Нуль ручних дій. Нуль забутих deploy. JWT/no-JWT конфігурація в коді.', '{"GitHub Actions","Supabase CLI","YAML","CI/CD pipeline"}', '{"#GitHubActions","#AutoDeploy","#EdgeFunctions","#CICD","#DevOps","#Supabase"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j36', 'jobbot', 'devops_infra', 'Each user — their own scan time', 'Hver bruker — sin egen skannetid', 'Кожен юзер — свій час сканування', 'Instead of scanning all users simultaneously every hour, each user has a scan_time_utc setting. GitHub Actions cron runs hourly, and the Edge Function only scans users whose time matches the current UTC hour.', 'I stedet for å skanne alle brukere samtidig hver time, har hver bruker en scan_time_utc-innstilling. GitHub Actions cron kjører hver time, og Edge Function skanner kun brukere med riktig tid.', 'Замість одночасного сканування всіх юзерів щогодини, кожен має scan_time_utc. GitHub Actions cron запускається щогодини, Edge Function сканує лише юзерів, чий час збігається з поточною UTC-годиною.', 'Scheduled scan ran with forceRun=true — all users scanned simultaneously every hour. User A wants a scan at 7:00 (before work), User B at 12:00 (lunch), User C at 18:00 (after work). Simultaneous scanning creates unnecessary load on FINN.no and triggers rate limiting.', 'Planlagt skanning kjørte alle brukere samtidig hver time. Samtidig skanning skaper unødvendig belastning på FINN.no og trigger hastighetsbegrensning.', 'Scheduled scan з forceRun=true — всі юзери одночасно щогодини. Одночасний скан = непотрібне навантаження на FINN.no та rate limiting.', 'scheduled-scan.yml: cron at "0 * * * *" (every hour). Calls scheduled-scanner Edge Function with forceRun=false. Inside the function: SELECT users with auto_scan_enabled=true, for each user check if scan_time_utc matches current UTC hour. Manual workflow_dispatch with force_run=true for debug scans all users. Logging: "Skipping user X: scan_time_utc=14, current_hour=09."', 'scheduled-scan.yml: cron "0 * * * *". Kaller scheduled-scanner med forceRun=false. Inne i funksjonen: sjekk om brukerens scan_time_utc stemmer med gjeldende UTC-time. Manuell workflow_dispatch med force_run=true for debug.', 'scheduled-scan.yml: cron "0 * * * *". Виклик scheduled-scanner з forceRun=false. Всередині: для кожного юзера перевірка scan_time_utc == currentUTCHour. Manual workflow_dispatch з force_run=true для debug.', 'Each user is scanned at their chosen time. Load on FINN.no is distributed evenly throughout the day. Rate limiting does not trigger. Users get fresh jobs exactly when they''re ready to review them.', 'Hver bruker skannes til valgt tid. Belastningen på FINN.no fordeles jevnt gjennom dagen. Hastighetsbegrensning utløses ikke.', 'Кожен юзер сканується в свій час. Навантаження на FINN.no розподілене рівномірно. Rate limiting не спрацьовує. Свіжі вакансії саме тоді, коли юзер готовий.', '{"GitHub Actions cron","Deno Edge Functions","PostgreSQL","UTC timezone"}', '{"#Cron","#PerUserScheduling","#DistributedLoad","#GitHubActions","#Automation"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j37', 'jobbot', 'devops_infra', '60 minutes instead of 30 seconds — AI in GitHub Actions', '60 minutter i stedet for 30 sekunder — AI i GitHub Actions', '60 хвилин замість 30 секунд — AI в GitHub Actions', 'Supabase Edge Functions have a 30-second timeout. Batch AI analysis of 10+ jobs exceeds this. An architectural split delegates scraping to Edge Functions and AI analysis to GitHub Actions workers with 60-minute timeout.', 'Supabase Edge Functions har 30-sekunders timeout. Batch AI-analyse av 10+ jobber overskrider dette. Et arkitektonisk splitt delegerer scraping til Edge Functions og AI-analyse til GitHub Actions-workere med 60-minutters timeout.', 'Supabase Edge Functions мають 30-секундний timeout. Пакетний AI-аналіз 10+ вакансій перевищує ліміт. Архітектурний split: скрапінг в Edge Functions, AI-аналіз в GitHub Actions з 60-хвилинним timeout.', 'Azure OpenAI analysis of one job takes ~3 seconds. 10 jobs = 30 seconds. But Supabase Edge Functions have a hard 30-second timeout. With 10+ new jobs, the function times out, leaving half unanalyzed.', 'Azure OpenAI-analyse av én jobb tar ~3 sekunder. 10 jobber = 30 sekunder. Supabase Edge Functions har 30-sekunders timeout. Med 10+ nye jobber faller funksjonen ut.', 'Azure OpenAI аналіз однієї вакансії — ~3 секунди. 10 вакансій — 30 секунд. Supabase Edge Function має 30-секундний timeout. При 10+ вакансіях функція падає.', 'Architectural split: 1) scheduled-scanner Edge Function (30s) scrapes FINN/NAV/LinkedIn, saves to DB, extracts details. 2) Triggers analyze-jobs.yml via POST /repos/{owner}/{repo}/dispatches with GITHUB_PAT. 3) analyze-jobs.yml runs analyze_worker.py — Python script with Azure OpenAI that batch-analyzes jobs without time limits. 4) Telegram notification for hot jobs (score >= 50).', 'Arkitektonisk splitt: 1) Edge Function skraper og lagrer. 2) Trigger GitHub Actions via repository_dispatch. 3) Python-worker analyserer uten tidsbegrensning. 4) Telegram-varsling for hot jobs.', 'Архітектурний split: 1) Edge Function скрапить і зберігає. 2) Trigger GitHub Actions через repository_dispatch. 3) Python worker аналізує без лімітів часу. 4) Telegram-нотифікація для hot jobs.', 'Edge Function never times out: scraping + saving = 10-15 seconds. AI analysis of 50+ jobs = 3 minutes in GitHub Actions without any limits. Scaling without architecture changes.', 'Edge Function timer aldri ut: scraping + lagring = 10-15 sekunder. AI-analyse av 50+ jobber = 3 minutter i GitHub Actions. Skalering uten arkitekturendringer.', 'Edge Function ніколи не timeout: скрапінг + збереження = 10-15 секунд. AI-аналіз 50+ вакансій = 3 хвилини в GitHub Actions. Масштабування без зміни архітектури.', '{"GitHub Actions","repository_dispatch","Python","Azure OpenAI","Deno"}', '{"#TimeoutWorkaround","#GitHubActions","#AsyncProcessing","#Scalability","#Architecture"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j38', 'jobbot', 'other', 'Supabase — the entire backend in one platform', 'Supabase — hele backend i én plattform', 'Supabase — весь backend в одній платформі', 'One Supabase project covers everything: PostgreSQL with JSONB, Auth with JWT, 14 Edge Functions, Storage for PDFs, Realtime WebSocket, auto-generated REST API, and RLS. Monthly cost ~$25 vs ~$100+ for equivalent AWS stack.', 'Ett Supabase-prosjekt dekker alt: PostgreSQL med JSONB, Auth med JWT, 14 Edge Functions, Storage, Realtime WebSocket, auto-generert REST API og RLS. Månedlig kostnad ~$25 vs ~$100+ for tilsvarende AWS.', 'Один Supabase проект покриває ВСЕ: PostgreSQL з JSONB, Auth з JWT, 14 Edge Functions, Storage для PDF, Realtime WebSocket, авто-REST API та RLS. ~$25/міс замість ~$100+ за еквівалентний AWS.', 'A typical project needs: database, authentication, serverless functions, file storage, real-time subscriptions, REST API, row-level security. That''s 5+ different services: Firebase + Auth0 + AWS Lambda + S3 + Pusher. Configuration, billing, keys — exponential complexity.', 'Et typisk prosjekt trenger 5+ ulike tjenester. Konfigurasjon, fakturering, nøkler — eksponentiell kompleksitet.', 'Типовий проект потребує 5+ різних сервісів: Firebase + Auth0 + AWS Lambda + S3 + Pusher. Конфігурація, billing, ключі — exponential complexity.', 'One Supabase project covers everything: PostgreSQL with 10+ tables and JSONB fields, Auth with email/password and JWT, 14 Deno Edge Functions for scraping/AI/bot/webhooks, Storage for PDF uploads, Realtime for live dashboard updates, RLS for per-user data isolation, auto-generated REST API for direct queries from AuthContext. One URL and one service role key for all components.', 'Ett Supabase-prosjekt dekker alt: PostgreSQL, Auth, 14 Edge Functions, Storage, Realtime, RLS, auto-generert REST API. Én URL og én service role key for alle komponenter.', 'Один Supabase проект покриває ВСЕ: PostgreSQL з JSONB, Auth з JWT, 14 Edge Functions, Storage для PDF, Realtime, RLS, авто-REST API. Один URL та один service role key.', 'Zero DevOps overhead: no servers to manage, no Docker for the database. From idea to production in one supabase init. Monthly cost: ~$25 (Pro plan) instead of ~$100+ for equivalent AWS stack.', 'Null DevOps-overhead: ingen servere, ingen Docker for database. Fra idé til produksjon med én supabase init. Månedlig kostnad: ~$25 i stedet for ~$100+.', 'Zero DevOps overhead: жодного сервера, жодного Docker. Від ідеї до production — один supabase init. ~$25/міс замість ~$100+ для AWS.', '{"Supabase","PostgreSQL","Deno","Auth","Storage","Realtime","RLS"}', '{"#Supabase","#FullStack","#BaaS","#PostgreSQL","#ServerlessBackend","#OneStopShop"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j39', 'jobbot', 'other', 'Every AI call — CC''d to accounting', 'Hvert AI-kall — kopi til regnskapet', 'Кожен AI-виклик — в copy до бухгалтерії', 'Real-time token cost tracking for every Azure OpenAI call. Dashboard shows current spend, system_logs has detailed breakdown. Average weekly cost: $2-5 for an active user analyzing 200 jobs + 30 cover letters.', 'Sanntids tokenkostnadssporing for hvert Azure OpenAI-kall. Dashboard viser gjeldende forbruk. Gjennomsnittlig ukentlig kostnad: $2-5 for en aktiv bruker som analyserer 200 jobber + 30 søknader.', 'Real-time tracking вартості токенів для кожного Azure OpenAI виклику. Dashboard показує поточні витрати, system_logs — детальний breakdown. Середні витрати: $2-5/тиждень на 200 вакансій + 30 søknad.', 'Azure OpenAI GPT-4 is not free. Input: $2.50/1M tokens, Output: $10.00/1M tokens. Analyzing 200 jobs per week + generating 30 cover letters means unpredictable bills. Users don''t know how much they''ve spent until billing arrives.', 'Azure OpenAI GPT-4 er ikke gratis. Å analysere 200 jobber + generere 30 søknader betyr uforutsigbare regninger. Brukere vet ikke forbruket før regningen kommer.', 'Azure OpenAI GPT-4 не безкоштовний. Input: $2.50/1M tokens, Output: $10.00/1M tokens. 200 вакансій + 30 søknad на тиждень — непередбачуваний рахунок.', 'In job-analyzer and generate_application: after each Azure OpenAI call, extract usage.prompt_tokens and usage.completion_tokens from the response. Formula: cost = (prompt_tokens * PRICE_INPUT + completion_tokens * PRICE_OUTPUT) / 1_000_000. Write to system_logs: user_id, event_type: "ai_cost", cost_usd, tokens, model, function_name. Dashboard MetricCard "AI Cost" shows SUM for the period. Admin page shows total cost per user.', 'I job-analyzer og generate_application: etter hvert kall, beregn kostnad fra usage-tokens. Skriv til system_logs. Dashboard MetricCard "AI Cost" viser SUM for perioden. Admin-side viser kostnad per bruker.', 'В job-analyzer та generate_application: після кожного виклику — витягуємо usage.prompt_tokens і completion_tokens. Формула: cost = tokens * price / 1M. Запис в system_logs. Dashboard MetricCard "AI Cost" показує SUM. Admin — cost per user.', 'Full cost transparency: users see cost in real time on Dashboard. Admin sees cost per user. Average weekly cost: $2-5 for an active user (200 jobs + 30 cover letters).', 'Full kostnadsåpenhet: brukere ser kostnad i sanntid. Admin ser kostnad per bruker. Gjennomsnittlig ukentlig kostnad: $2-5.', 'Повна прозорість витрат: юзер бачить cost в реальному часі. Admin — cost per user. Середній тижневий cost: $2-5 для активного юзера.', '{"Azure OpenAI","Token counting","Supabase system_logs","React MetricCard"}', '{"#CostTracking","#AzureOpenAI","#TokenUsage","#Billing","#Transparency","#FinOps"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j40', 'jobbot', 'other', 'One file patch — and drag-and-drop works', 'Én filoppdatering — og drag-and-drop fungerer', 'Патч одного файлу — і drag-and-drop працює', 'Skyvern Docker cannot do drag-and-drop file upload. A patched handler.py with DataTransfer injection instead of mouse events, mounted via docker-compose volume, unblocks all drop-zone recruiting platforms.', 'Skyvern Docker kan ikke gjøre drag-and-drop-filopplasting. En patchet handler.py med DataTransfer-injeksjon, montert via docker-compose volume, låser opp alle drop-zone-rekrutteringsplattformer.', 'Skyvern Docker не вміє drag-and-drop file upload. Патч handler.py з DataTransfer injection замість mouse events через docker-compose volume розблоковує всі drop-zone платформи.', 'Skyvern Docker cannot do drag-and-drop file upload. Webcruiter and other platforms have a drop zone: "Drag your file here." Skyvern sees the drop zone, tries to drag — nothing happens. DataTransfer API in headless Chrome works differently than in a regular browser.', 'Skyvern Docker kan ikke gjøre drag-and-drop-filopplasting. DataTransfer API i headless Chrome fungerer annerledes enn i en vanlig nettleser.', 'Skyvern Docker не вміє drag-and-drop file upload. DataTransfer API в headless Chrome працює інакше. Drop zone платформ не працюють з автоматизацією.', 'Created handler_patched.py based on Skyvern''s handler.py. In the upload_file section: instead of mouse drag events, implemented DataTransfer drop fallback: 1) Create DataTransfer object via JavaScript. 2) Inject file blob via dt.items.add(file). 3) Dispatch "drop" event on target element. 4) Fallback to input[type=file].click(). Docker-compose mount: ./handler_patched.py:/app/skyvern/webeye/actions/handler.py. Skyvern .env: BROWSER_LOCALE=nb-NO.', 'Opprettet handler_patched.py med DataTransfer drop-fallback i stedet for mus-drag-hendelser. Docker-compose volume mount overskriver original handler. Skyvern .env: BROWSER_LOCALE=nb-NO.', 'Створено handler_patched.py з DataTransfer drop fallback замість mouse drag events. Docker-compose mount перезаписує оригінальний handler. Skyvern .env: BROWSER_LOCALE=nb-NO.', 'File upload on Webcruiter, Easycruit, and other drag-and-drop platforms works on the first attempt. One patched file unblocked an entire category of sites. Skyvern updates don''t overwrite the patch (volume mount has priority).', 'Filopplasting på Webcruiter og andre drag-and-drop-plattformer fungerer på første forsøk. Skyvern-oppdateringer overskriver ikke patchen (volume mount har prioritet).', 'File upload на Webcruiter та інших drag-and-drop платформах працює з першої спроби. Один патч розблокував цілу категорію сайтів. Оновлення Skyvern не перезатирає патч.', '{"Docker compose","Volume mount","JavaScript DataTransfer API","Python"}', '{"#DockerPatch","#DragAndDrop","#Skyvern","#FileUpload","#OpenSource","#Workaround"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j41', 'jobbot', 'other', 'Push = Production in 15 seconds', 'Push = Produksjon på 15 sekunder', 'Push = Production за 15 секунд', 'Netlify auto-deploy from GitHub: push to main triggers a 15-second Vite build and 5-second CDN deploy. Preview URLs for every PR. Rollback with one click. Zero downtime.', 'Netlify auto-deploy fra GitHub: push til main utløser 15-sekunders Vite-bygging og 5-sekunders CDN-deploy. Forhåndsvisnings-URLer for hver PR. Tilbakeruling med ett klikk. Null nedetid.', 'Netlify auto-deploy з GitHub: push до main запускає 15-секундний Vite build та 5-секундний CDN deploy. Preview URL для кожного PR. Rollback одним кліком. Zero downtime.', 'Frontend development loop: changes, commit, push, manual deploy, 5-minute wait, production testing. Each iteration takes 7-10 minutes. With 20 deploys per day, that''s 3+ hours of "waiting." Users see the old version until you deploy.', 'Frontend-utviklingsløkke: endringer, commit, push, manuell deploy, 5 minutters venting. Hver iterasjon tar 7-10 minutter. Med 20 deployer per dag er det 3+ timer "venting."', 'Frontend development loop: зміни, commit, push, manual deploy, 5 хвилин очікування. Кожна ітерація — 7-10 хвилин. При 20 deploy на день — 3+ години "чекання."', 'Netlify project connected to GitHub repo. Configuration: branch main, build command npm run build, publish directory dist/. Auto-deploy on push. Preview deploys for pull requests with unique URLs. Vite production build: tree-shaking, minification, code splitting. Output: static bundle ~500KB gzipped.', 'Netlify-prosjekt koblet til GitHub-repo. Auto-deploy ved push. Forhåndsvisningsdeploy for pull requests. Vite produksjonsbygging: tree-shaking, minifisering. Output: ~500KB gzipped.', 'Netlify підключено до GitHub repo. Auto-deploy on push. Preview deploys для PR. Vite production build: tree-shaking, minification, code splitting. Output: ~500KB gzipped.', 'Git push — 15-second build — 5-second deploy — production updated. Preview URL for every PR for testing without merging. Rollback with one click. Zero downtime.', 'Git push — 15 sekunders bygging — 5 sekunders deploy — produksjon oppdatert. Forhåndsvisnings-URL for hver PR. Tilbakeruling med ett klikk. Null nedetid.', 'Git push — 15 секунд build — 5 секунд deploy — production оновлено. Preview URL для кожного PR. Rollback одним кліком. Zero downtime.', '{"Netlify","Vite","React","GitHub integration","CDN"}', '{"#Netlify","#AutoDeploy","#CICD","#ZeroDowntime","#StaticHosting","#Frontend"}', 'published');
INSERT INTO features (feature_id, project_id, category, title_en, title_no, title_ua, short_description_en, short_description_no, short_description_ua, problem_en, problem_no, problem_ua, solution_en, solution_no, solution_ua, result_en, result_no, result_ua, tech_stack, hashtags, status) VALUES ('j42', 'jobbot', 'other', 'Free AI — Gemini analyzes errors', 'Gratis AI — Gemini analyserer feil', 'Безкоштовний AI — Gemini аналізує помилки', 'Google Gemini 2.5 Flash with its generous free tier (1500 RPD, 1M TPM) handles 200+ monthly skill guide generations at zero cost. Azure OpenAI is reserved for critical tasks only, cutting auxiliary AI costs to $0.', 'Google Gemini 2.5 Flash med sitt generose gratistilbud (1500 RPD, 1M TPM) håndterer 200+ månedlige skill guide-genereringer uten kostnad. Azure OpenAI reserveres kun for kritiske oppgaver.', 'Google Gemini 2.5 Flash з щедрим безкоштовним tier (1500 RPD, 1M TPM) обробляє 200+ генерацій skill guides на місяць безкоштовно. Azure OpenAI лише для критичних задач — допоміжні AI-витрати $0.', 'Azure OpenAI GPT-4 costs $2.50/1M input tokens. Generating skill guides after each Skyvern attempt adds 200+ AI calls per month. Small cost, but why pay for a task that a free AI can handle?', 'Azure OpenAI GPT-4 koster $2,50/1M input-tokens. Skill guide-generering etter hvert Skyvern-forsøk legger til 200+ AI-kall per måned. Hvorfor betale for det en gratis AI kan gjøre?', 'Azure OpenAI GPT-4 коштує $2.50/1M input tokens. Генерація skill guides після кожної Skyvern спроби — 200+ додаткових AI-викликів на місяць. Навіщо платити, якщо є безкоштовний AI?', 'generate_skill_from_memory() in auto_apply.py uses Gemini 2.5 Flash via REST API. Prompt: "You are a web automation expert. Analyze the form-filling attempt and generate a SKILL GUIDE for future attempts." Input: site domain, outcome, form fields (filled/failed), navigation flow, upload methods. Output: concise text guide (200-400 words). Stored in site_form_memory.skill_guide. Injected into navigation goals via build_memory_section().', 'generate_skill_from_memory() i auto_apply.py bruker Gemini 2.5 Flash via REST API. Input: nettstedsdomene, resultat, skjemafelt, navigasjonsflyt. Output: kortfattet tekstguide. Lagret i site_form_memory.skill_guide.', 'generate_skill_from_memory() в auto_apply.py використовує Gemini 2.5 Flash через REST API. Input: домен, результат, form fields, navigation flow. Output: стислий текстовий guide. Зберігається в site_form_memory.skill_guide. Вставляється через build_memory_section().', '200+ AI calls per month — free. Skill guides improve success rate by 15-20%. Azure OpenAI is used only for critical tasks (job analysis, cover letter generation). Gemini handles auxiliary work.', '200+ AI-kall per måned — gratis. Skill guides forbedrer suksessraten med 15-20%. Azure OpenAI brukes kun for kritiske oppgaver. Gemini håndterer hjelpefunksjoner.', '200+ AI-викликів на місяць — безкоштовно. Skill guides покращують success rate на 15-20%. Azure OpenAI тільки для критичних задач. Gemini — для допоміжних.', '{"Google Gemini 2.5 Flash","REST API","Python","Free tier AI"}', '{"#Gemini","#FreeTier","#SkillGeneration","#CostOptimization","#AIAgent","#GoogleAI"}', 'published');
